B.UT=new A.aL(B.aI,["\u0423\u0447\u0435\u043d\u0438\u043a","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u041c\u0430\u0433","\u0412\u0434\u043e\u0445\u043d\u043e\u0432\u0435\u043d\u0438\u0435, \u0441\u0438\u043b\u0430 \u0432\u043e\u043b\u0438, \u043d\u043e\u0432\u044b\u0435 \u043d\u0430\u0447\u0438\u043d\u0430\u043d\u0438\u044f. \u0421\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0447\u0435\u0440\u0435\u0437 \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u0438\u0435.","\u041e\u0431 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0438 \u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0438, \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u044b, \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0435 \u043e\u043f\u044b\u0442\u0430. \u041b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u0430\u044f. \u0423\u043f\u0440\u044f\u043c\u0430\u044f \u0438 \u0432\u0441\u043f\u044b\u043b\u044c\u0447\u0438\u0432\u0430\u044f. \u0421\u0432\u043e\u0431\u043e\u0434\u043e\u043b\u044e\u0431\u0438\u0432\u0430\u044f \u0438 \u043e\u0434\u0438\u043d\u043e\u043a\u0430\u044f.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f (\u043a \u043e\u0431\u0449\u0435\u043d\u0438\u044e), \u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f (\u043a \u043f\u043e\u0437\u043d\u0430\u043d\u0438\u044e)","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u043d\u0430\u043a\u043e\u043f\u0438\u0442\u044c \u043e\u043f\u044b\u0442, \u0443\u0437\u043d\u0430\u0442\u044c, \u043f\u0440\u0438\u043c\u0435\u043d\u0438\u0442\u044c","\u0427\u0435\u043b\u043e\u0432\u0435\u043a \u0431\u043e\u043b\u044c\u0448\u0435 \u043e\u0442\u043a\u0440\u044b\u0442 \u043a \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043c \u0438 \u043f\u043e\u0437\u043d\u0430\u043d\u0438\u044f\u043c. \u0411\u043e\u043b\u0435\u0435 \u043b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u0435\u043d, \u0443\u043f\u0440\u044f\u043c \u0438 \u0432\u0441\u043f\u044b\u043b\u044c\u0447\u0438\u0432.","\u041f\u043e\u0437\u043d\u0430\u043d\u0438\u0435, \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u044b, \u0438\u043d\u0442\u0435\u0440\u0435\u0441 \u043a \u0436\u0438\u0437\u043d\u0438, \u043a \u043b\u044e\u0431\u043e\u043c\u0443 \u043d\u0430\u0431\u043e\u0440\u0443 \u043e\u043f\u044b\u0442\u0430. \u041b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u0430.","\u041d\u043e\u0443-\u0445\u0430\u0443, \u043d\u043e\u0432\u0430\u0442\u043e\u0440\u0441\u0442\u0432\u043e. \u041d\u043e\u0432\u044b\u0435 \u0437\u043d\u0430\u043d\u0438\u044f \u0442\u0443\u0442 \u0436\u0435 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f \u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435. \u0418\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u0430.","\u0421\u0446\u0435\u043d\u0430, \u043f\u0443\u0431\u043b\u0438\u043a\u0430, \u043e\u0440\u0430\u0442\u043e\u0440\u0441\u0442\u0432\u043e, \u0440\u0435\u043a\u043b\u0430\u043c\u0430. \u0412\u0434\u043e\u0445\u043d\u043e\u0432\u0435\u043d\u0438\u0435.","\u0421\u0442\u0440\u0430\u0445 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c, \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u044c. \u0421\u0442\u0440\u0430\u0445 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b \u043c\u0435\u0441\u0442\u0430 (\u043d\u043e \u044d\u0442\u043e \u0436\u0435 \u0432\u0441\u0435 \u0438 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0443\u0441\u043b\u043e\u0432\u0438\u0435\u043c \u0440\u0435\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u0438). \u0421\u0442\u0440\u0430\u0445 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u0441\u0432\u043e\u044e \u043b\u0438\u0447\u043d\u0443\u044e \u0441\u0438\u043b\u0443.","\u041e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u0441\u044f. \u0412\u044b\u043d\u0443\u0436\u0434\u0435\u043d \u043f\u0440\u0438\u0431\u0435\u0433\u043d\u0443\u0442\u044c \u043a \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044e.","\u0423\u0447\u0438\u0442\u044c\u0441\u044f \u043e\u0431\u0443\u0447\u0430\u044f.","\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043e\u0432\u0430\u043d\u0438\u0435","\u041e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435, \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u044b, \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0435 \u043e\u043f\u044b\u0442\u0430 (\u0437\u043d\u0430\u043d\u0438\u044f \u043d\u0435 \u0438\u043c\u0435\u044e\u0442 \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u044f, \u043e\u043f\u044b\u0442 -- \u044d\u0442\u043e \u0432\u0441\u0451). \u041f\u043e\u043b\u043d\u043e\u0435 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043e\u043f\u044b\u0442\u0430 (\u0441\u043b\u0435\u043f\u0435\u0446, \u043d\u0430\u0438\u0432\u043d\u044b\u0439, \u043d\u0435\u0430\u0434\u0435\u043a\u0432\u0430\u0442\u043d\u044b\u0439, \u043d\u0435\u0441\u0430\u043c\u043e\u0441\u0442\u043e\u044f\u0442\u0435\u043b\u044c\u043d\u044b\u0439), \u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u0435\u043c, \u0447\u0435\u043c\u0443 \u0441\u043c\u043e\u0433 \u043d\u0430\u0443\u0447\u0438\u0442\u0441\u044f. \u041b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0439, \u0445\u043e\u0440\u043e\u0448\u043e \u0440\u0430\u0437\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044f \u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435. \u0423\u043f\u0440\u044f\u043c\u044b\u0439 \u0438 \u0432\u0441\u043f\u044b\u043b\u044c\u0447\u0438\u0432\u044b\u0439, \u043d\u0435\u043f\u043e\u0441\u043b\u0443\u0448\u043d\u044b\u0439 (\u0438 \u043d\u0435 \u0434\u043e\u043b\u0436\u0435\u043d), \u0441\u0432\u043e\u0431\u043e\u0434\u043e\u043b\u044e\u0431\u0438\u0432\u044b\u0439 \u0438 \u043e\u0434\u0438\u043d\u043e\u043a\u0438\u0439 - \u0435\u0434\u0438\u043d\u043e\u043b\u0438\u0447\u043d\u0438\u043a (\u0430\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442), \u043e\u0447\u0435\u043d\u044c \u043f\u043b\u043e\u0445\u043e \u0440\u0430\u0441\u043a\u0440\u044b\u0432\u0430\u0435\u0442 (\u043d\u0430\u0445\u043e\u0434\u0438\u0442/\u0432\u044b\u0440\u0430\u0436\u0430\u0435\u0442) \u0441\u0435\u0431\u044f \u0442\u0430\u043c, \u0433\u0434\u0435 \u043c\u043d\u043e\u0433\u043e \u043b\u044e\u0434\u0435\u0439. \u0416\u0435\u043b\u0430\u043d\u0438\u0435 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c (\u0441\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0438\u0437 \u043f\u043e\u0434\u0440\u0430\u0436\u0430\u043d\u0438\u044f \u043a\u043e\u043c\u0443-\u043b\u0438\u0431\u043e), \u043d\u0430\u0441\u0442\u0430\u0432\u043b\u044f\u0442\u044c (\u0438\u0437 \u0441\u0435\u0440\u0438\u0438 -- \u0432\u043c\u0435\u0441\u0442\u0435 \u0438\u043d\u0442\u0435\u0440\u0435\u0441\u043d\u0435\u0435 \u0438 \u043d\u0435 \u0441\u043a\u0443\u0447\u043d\u043e), \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u043b\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u0443 \u0438 \u0432\u043d\u0435\u0448\u043d\u0435\u0439 \u0432\u043b\u0430\u0441\u0442\u0438, \u043d\u043e \u0438\u0437-\u0437\u0430 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044f \u043e\u043f\u044b\u0442\u0430 \u0447\u0430\u0441\u0442\u043e \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0432 \u043d\u0435\u043b\u043e\u0432\u043a\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438. \u041a\u043e\u0433\u0434\u0430 \u043c\u043d\u043e\u0433\u043e \u0435\u0434\u0438\u043d\u0438\u0446 - \u043c\u0430\u043b\u043e\u0434\u0435\u0442\u0435\u043d, \u0441\u0432\u043e\u0438\u0445 \u0434\u0435\u0442\u0435\u0439 \u043c\u043e\u0436\u0435\u0442 \u043d\u0435 \u0431\u044b\u0442\u044c. \u0413\u0440\u043e\u043c\u043a\u0438\u0439, \u044f\u0440\u043a\u0438\u0439, \u0448\u0443\u043c\u043d\u044b\u0439 (\u043d\u043e \u0432\u0441\u0451 \u0436\u0435)","\u0423\u0447\u0435\u043d\u0438\u043a","\u041b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0436\u0430\u0436\u0434\u0430 \u043d\u043e\u0432\u043e\u0433\u043e \u043e\u043f\u044b\u0442\u0430.","\u0411\u044b\u0441\u0442\u0440\u043e \u0443\u0447\u0438\u0442\u0441\u044f, \u043e\u0442\u043a\u0440\u044b\u0442 \u043a \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043c, \u0441\u0440\u0430\u0437\u0443 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0435\u0442 \u0437\u043d\u0430\u043d\u0438\u044f \u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435.","\u0418\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u044c, \u043d\u0435\u0443\u043c\u0435\u043d\u0438\u0435 \u043f\u0440\u0438\u0441\u043b\u0443\u0448\u0438\u0432\u0430\u0442\u044c\u0441\u044f \u043a \u0434\u0440\u0443\u0433\u0438\u043c, \u0441\u0442\u0440\u0430\u0445 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0441\u0438\u043b\u044b.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0423\u0447\u0435\u043d\u0438\u043a \u043f\u0440\u043e\u0441\u044b\u043f\u0430\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u043e\u0441\u0432\u043e\u0438\u0442\u044c \u0447\u0442\u043e-\u0442\u043e \u0441 \u043d\u0443\u043b\u044f \u0438\u043b\u0438 \u043d\u0430\u0439\u0442\u0438 \u043d\u0435\u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0439 \u0432\u044b\u0445\u043e\u0434.","\xab\u0413\u0434\u0435 \u0432 \u043c\u043e\u0435\u0439 \u0436\u0438\u0437\u043d\u0438 \u0441\u0435\u0439\u0447\u0430\u0441 \u043d\u0443\u0436\u043d\u0430 \u044d\u043d\u0435\u0440\u0433\u0438\u044f \u043d\u043e\u0432\u0438\u0447\u043a\u0430, \u0433\u043e\u0442\u043e\u0432\u043e\u0433\u043e \u043a \u043e\u0448\u0438\u0431\u043a\u0430\u043c?\xbb","\u041b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0432\u0441\u043f\u044b\u043b\u044c\u0447\u0438\u0432\u043e\u0441\u0442\u044c, \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 (\u043d\u0430 \u043f\u0440\u0435\u043f\u044f\u0442\u0441\u0442\u0432\u0438\u044f \u0432 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0438), \u0432\u043e\u0441\u0442\u043e\u0440\u0433 \u043e\u0442\u043a\u0440\u044b\u0442\u0438\u044f, \u0443\u043f\u0440\u044f\u043c\u0441\u0442\u0432\u043e, \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0430 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044f.","\u042f\u0440\u043a\u0430\u044f, \u0448\u0443\u043c\u043d\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043e\u0442 \u043d\u043e\u0432\u043e\u0433\u043e \u0437\u043d\u0430\u043d\u0438\u044f \u0438\u043b\u0438 \u0443\u043c\u0435\u043d\u0438\u044f. \u0412\u0441\u043f\u044b\u0448\u043a\u0430 \u0433\u043d\u0435\u0432\u0430, \u0435\u0441\u043b\u0438 \u0435\u0433\u043e \u043f\u0440\u0435\u0440\u044b\u0432\u0430\u044e\u0442 \u0438\u043b\u0438 \u0443\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043d\u0430 \u043e\u0448\u0438\u0431\u043a\u0438 \u0432 \u043d\u0435\u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043d\u043e\u0439 \u0444\u043e\u0440\u043c\u0435. \u0423\u043f\u0440\u044f\u043c\u043e\u0435 \u043e\u0442\u0441\u0442\u0430\u0438\u0432\u0430\u043d\u0438\u0435 \u0441\u0432\u043e\u0435\u0433\u043e, \u0447\u0430\u0441\u0442\u043e \u043d\u0435\u043e\u0431\u043e\u0441\u043d\u043e\u0432\u0430\u043d\u043d\u043e\u0433\u043e, \u043c\u043d\u0435\u043d\u0438\u044f \u043a\u0430\u043a \u0441\u043f\u043e\u0441\u043e\u0431 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044f \u0447\u0435\u0440\u0435\u0437 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442. \u042d\u043d\u0442\u0443\u0437\u0438\u0430\u0437\u043c, \u0441\u043c\u0435\u043d\u044f\u044e\u0449\u0438\u0439\u0441\u044f \u0440\u0430\u0437\u043e\u0447\u0430\u0440\u043e\u0432\u0430\u043d\u0438\u0435\u043c, \u0435\u0441\u043b\u0438 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442 \u043d\u0435 \u0443\u0434\u0430\u043b\u0441\u044f."],t.l)
B.V9=new A.aL(B.aI,["\u041f\u043e\u0440\u044f\u0434\u043e\u043a","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u0412\u0435\u0440\u0445\u043e\u0432\u043d\u0430\u044f \u0416\u0440\u0438\u0446\u0430","\u0422\u0430\u0439\u043d\u044b\u0435 \u0437\u043d\u0430\u043d\u0438\u044f, \u0438\u043d\u0442\u0443\u0438\u0446\u0438\u044f, \u0441\u0432\u044f\u0437\u044c \u0441 \u043f\u043e\u0434\u0441\u043e\u0437\u043d\u0430\u043d\u0438\u0435\u043c. \u0425\u0440\u0430\u043d\u0435\u043d\u0438\u0435 \u0441\u0430\u043a\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u0438.","\u0423\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0438\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430, \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c\u0438 \u0432\u043e\u043f\u0440\u043e\u0441\u0430\u043c\u0438. \u0422\u0440\u0443\u0434\u043e\u043b\u044e\u0431\u0438\u0435. \u0411\u0435\u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u043e \u0438 \u0442\u0440\u0435\u0432\u043e\u0436\u043d\u043e\u0441\u0442\u044c.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f, \u0417\u0430\u043c\u043a\u043d\u0443\u0442\u0430\u044f","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u043d\u0430\u043a\u043e\u043f\u0438\u0442\u044c, \u0441\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u043e\u0435, \u0443\u0440\u0435\u0433\u0443\u043b\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0442\u0440\u0430\u0442\u044b","\u0427\u0435\u043b\u043e\u0432\u0435\u043a \u0441\u043a\u043b\u043e\u043d\u0435\u043d \u043a \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0438\u0432\u0430\u043d\u0438\u044e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430 \u0438 \u043d\u0430\u0432\u0435\u0434\u0435\u043d\u0438\u044e \u0432 \u043d\u0451\u043c \u0441\u0432\u043e\u0435\u0433\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0430. \u0411\u043e\u043b\u044c\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0443\u044f\u0437\u0432\u0438\u043c \u043a \u0442\u0440\u0430\u0442\u0430\u043c, \u0440\u0430\u0441\u0442\u043e\u0447\u0438\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0443 \u0438 \u043d\u0435\u0446\u0435\u043b\u0435\u0441\u043e\u043e\u0431\u0440\u0430\u0437\u043d\u043e\u0441\u0442\u0438. \u0411\u043e\u043b\u0435\u0437\u043d\u0435\u043d\u043d\u043e\u0435 \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435 \u043a \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442\u0441\u044f \u0435\u0433\u043e \u0432\u0435\u0449\u0430\u043c\u0438.","\u041d\u0430\u043a\u043e\u043f\u0438\u0442\u044c \u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u043e\u0435.","\u0421\u043e\u0431\u0438\u0440\u0430\u0435\u0442 \u0432\u043e\u043a\u0440\u0443\u0433 \u0441\u0435\u0431\u044f \u0440\u0435\u0441\u0443\u0440\u0441\u044b, \u043c\u043e\u0436\u0435\u0442 \u0434\u0430\u0436\u0435 \u043d\u0435 \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u0438\u043c\u0438, \u043d\u043e \u043e\u043d\u0438 \u0434\u043e\u043b\u0436\u043d\u044b \u0431\u044b\u0442\u044c. \u041d\u0435\u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u0440\u0430\u0441\u0441\u0442\u0430\u0432\u0430\u0442\u044c\u0441\u044f \u0441 \u0442\u043e\u043c, \u0447\u0442\u043e \u0435\u0441\u0442\u044c. \u042d\u043a\u043e\u043d\u043e\u043c\u0438\u044f (\u0437\u0430\u0447\u0435\u043c \u0442\u0440\u0430\u0442\u0438\u0442\u044c \u0431\u043e\u043b\u044c\u0448\u0435, \u0435\u0441\u043b\u0438 \u0435\u0441\u0442\u044c \u0434\u0435\u0448\u0435\u0432\u043b\u0435).","\u0425\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u0438\u043a\u0438, \u0430\u0434\u043c\u0438\u043d\u0438\u0441\u0442\u0440\u0430\u0442\u043e\u0440\u044b. \u041d\u0430 \u0432\u044b\u0441\u0448\u0435\u043c \u0443\u0440\u043e\u0432\u043d\u0435 \u043d\u0430\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u0438, \u0432\u043b\u0430\u0434\u0435\u044e\u0449\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u044f\u043c\u0438 \u043e \u0431\u044b\u0442\u0435.","\u0421\u0442\u0440\u0430\u0445 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u043e\u043c. \u0421\u0442\u0440\u0430\u0445 \u043d\u0430\u043a\u0430\u043f\u043b\u0438\u0432\u0430\u0442\u044c \u0438 \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0430\u0442\u044c\u0441\u044f \u0438\u043c\u0443\u0449\u0435\u0441\u0442\u0432\u043e\u043c. \u0421\u0442\u0440\u0430\u0445 \u0434\u043e\u0441\u0442\u0430\u0442\u043a\u0430 \u0438 \u043d\u0438\u0449\u0435\u0442\u044b \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e. \u0421\u0442\u0440\u0430\u0445 \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0445 \u043a\u043e\u043d\u0442\u0430\u043a\u0442\u043e\u0432 (\u0430\u0434\u043c\u0438\u043d\u0438\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0435 \u043e\u0431\u0449\u0435\u043d\u0438\u0435).","\u0412\u044b\u043d\u0443\u0436\u0434\u0435\u043d\u043d\u0430\u044f \u044d\u043a\u043e\u043d\u043e\u043c\u0438\u044f \u0438 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0441\u043b\u043e\u0436\u0438\u0432\u0448\u0435\u0439\u0441\u044f \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0431\u044b\u0442\u0430.","\u0412\u0430\u0436\u043d\u043e \u043d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u0431\u044b\u0441\u0442\u0440\u043e \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0442\u044c \u0441\u043b\u043e\u0436\u0438\u0432\u0448\u0443\u044e\u0441\u044f \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044e \u0431\u044b\u0442\u0430 \u0438 \u043d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u0432 \u043d\u0435\u0439. \u0423\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u043e\u043c.","\u0412\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0433\u043e\u043b\u043e\u0441","\u0423\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0438\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430 \u0438 \u043d\u0430\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0432 \u043d\u0451\u043c \u0441\u0432\u043e\u0435\u0433\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0430 (\u0437\u043d\u0430\u0435\u0442 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u043e \u0438 \u0443\u043c\u0435\u0435\u0442 \u0432\u043b\u0438\u044f\u0442\u044c \u043d\u0430 \u043d\u0435\u0433\u043e). \u0423\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c\u0438 \u0432\u043e\u043f\u0440\u043e\u0441\u0430\u043c\u0438 \u0438 \u043f\u0435\u0440\u0441\u043f\u0435\u043a\u0442\u0438\u0432\u0430\u043c\u0438. \u0424\u0443\u043d\u043a\u0446\u0438\u044f \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u044f \u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u043e\u0433\u043e. \u041f\u043e\u0440\u044f\u0434\u043e\u043a \u0438 \u0440\u0430\u0432\u043d\u043e\u0432\u0435\u0441\u0438\u0435, \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0435 \u0441\u0442\u0440\u043e\u0433\u0438\u043c\u0438 \u0433\u0440\u0430\u043d\u0438\u0446\u0430\u043c\u0438, \u0446\u0435\u043b\u0435\u0441\u043e\u043e\u0431\u0440\u0430\u0437\u043d\u043e\u0441\u0442\u044c. \u041e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u044b (\u043d\u043e \u043d\u0435 \u0430\u0432\u0430\u043d\u0442\u044e\u0440\u044b), \u043a\u0430\u043a \u043f\u0440\u0438\u043d\u0446\u0438\u043f \u0440\u0430\u0432\u043d\u043e\u0432\u0435\u0441\u0438\u044f. \u0422\u0440\u0443\u0434\u043e\u043b\u044e\u0431\u0438\u0435. \u0411\u0435\u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u043e, \u0432\u044b\u0441\u043e\u043a\u0430\u044f \u0442\u0440\u0435\u0432\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u043f\u0435\u0440\u0435\u0434 \u0431\u0443\u0434\u0443\u0449\u043d\u043e\u0441\u0442\u044c\u044e. \u0411\u043e\u043b\u0435\u0437\u043d\u0435\u043d\u043d\u043e\u0435 \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435 \u043a \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442\u0441\u044f \u0435\u0433\u043e \u0432\u0435\u0449\u0430\u043c\u0438. \u041e\u0431\u0440\u0430\u0449\u0435\u043d \u043a \u0434\u0435\u0442\u044f\u043c, \u0441\u043b\u044b\u0448\u0438\u0442 \u0438\u0445, \u0432\u0438\u0434\u0438\u0442, \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442. \u041e\u0434\u043d\u043e\u043b\u044e\u0431, \u043a\u043e\u0433\u0434\u0430 \u043c\u043d\u043e\u0433\u043e \u0434\u0432\u043e\u0435\u043a -- \u043c\u043e\u043d\u043e\u0433\u0430\u043c\u0435\u043d.","\u0425\u0440\u0430\u043d\u0438\u0442\u0435\u043b\u044c","\u0421\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u0438 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u0438.","\u0423\u043c\u0435\u0435\u0442 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043c\u0438, \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u0442\u044c \u0438 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0443\u044e\u0442, \u043f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u043d.","\u0422\u0440\u0435\u0432\u043e\u0436\u043d\u043e\u0441\u0442\u044c, \u0447\u0440\u0435\u0437\u043c\u0435\u0440\u043d\u044b\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c, \u0441\u0442\u0440\u0430\u0445 \u043f\u0435\u0440\u0435\u0434 \u043b\u044e\u0431\u044b\u043c\u0438 \u0442\u0440\u0430\u0442\u0430\u043c\u0438 \u0438 \u043f\u043e\u0442\u0435\u0440\u044f\u043c\u0438.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0425\u0440\u0430\u043d\u0438\u0442\u0435\u043b\u044c \u0430\u043a\u0442\u0438\u0432\u0435\u043d, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u043d\u0430\u0432\u0435\u0441\u0442\u0438 \u043f\u043e\u0440\u044f\u0434\u043e\u043a \u0432 \u0434\u0435\u043b\u0430\u0445 \u0438\u043b\u0438 \u043f\u043e\u0437\u0430\u0431\u043e\u0442\u0438\u0442\u044c\u0441\u044f \u043e \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u0445.","\xab\u0427\u0442\u043e \u044f \u043f\u044b\u0442\u0430\u044e\u0441\u044c \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0436\u0451\u0441\u0442\u043a\u043e \u0438 \u0433\u0434\u0435 \u043c\u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u043e\u0441\u043b\u0430\u0431\u0438\u0442\u044c \u0445\u0432\u0430\u0442\u043a\u0443?\xbb","\u0422\u0440\u0435\u0432\u043e\u0436\u043d\u043e\u0441\u0442\u044c, \u0431\u0435\u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u043e \u043e \u0431\u0443\u0434\u0443\u0449\u0435\u043c, \u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435 (\u043a\u043e\u0433\u0434\u0430 \u043f\u043e\u0440\u044f\u0434\u043e\u043a \u0434\u043e\u0441\u0442\u0438\u0433\u043d\u0443\u0442), \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u043e\u0442 \u0445\u0430\u043e\u0441\u0430, \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0438\u043d\u044b \u0437\u0430 \u043d\u0435\u0440\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0435 \u0442\u0440\u0430\u0442\u044b.","\u041d\u0430\u043a\u043e\u043f\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0442\u0440\u0435\u0432\u043e\u0433\u0430, \u043f\u0440\u043e\u044f\u0432\u043b\u044f\u044e\u0449\u0430\u044f\u0441\u044f \u0432 \u0431\u0435\u0441\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u043c \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0438\u0432\u0430\u043d\u0438\u0438 \u0432\u0435\u0449\u0435\u0439. \u0413\u043b\u0443\u0431\u043e\u043a\u043e\u0435 \u0443\u043c\u0438\u0440\u043e\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u0435 \u0438 \u0442\u0438\u0445\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043e\u0442 \u043d\u0430\u0432\u0435\u0434\u0435\u043d\u043d\u043e\u0433\u043e \u0443\u044e\u0442\u0430 \u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u043d\u043e\u0441\u0442\u0438 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432. \u0420\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0438 \u0445\u043e\u043b\u043e\u0434\u043d\u043e\u0441\u0442\u044c \u043a \u0442\u0435\u043c, \u043a\u0442\u043e \u043d\u0430\u0440\u0443\u0448\u0430\u0435\u0442 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044b\u0435 \u0438\u043c \u0433\u0440\u0430\u043d\u0438\u0446\u044b \u0438 \u043f\u043e\u0440\u044f\u0434\u043e\u043a. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0438\u043d\u044b \u043f\u043e\u0441\u043b\u0435 \u0441\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u043e\u0439 \u043f\u043e\u043a\u0443\u043f\u043a\u0438."],t.l)
B.UU=new A.aL(B.aI,["\u041b\u044e\u0431\u043e\u0432\u044c","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0418\u043c\u043f\u0435\u0440\u0430\u0442\u0440\u0438\u0446\u0430","\u041f\u043b\u043e\u0434\u043e\u0440\u043e\u0434\u0438\u0435, \u0438\u0437\u043e\u0431\u0438\u043b\u0438\u0435, \u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c. \u0422\u0432\u043e\u0440\u0447\u0435\u0441\u043a\u0430\u044f \u044d\u043d\u0435\u0440\u0433\u0438\u044f \u0436\u0438\u0437\u043d\u0438.","\u041b\u0438\u0434\u0438\u0440\u0443\u044e\u0449\u0430\u044f \u0436\u0435\u043d\u0441\u043a\u0430\u044f \u043f\u043e\u0437\u0438\u0446\u0438\u044f. \u0421\u043e\u0437\u0434\u0430\u043d\u0438\u0435 \u0443\u0441\u043b\u043e\u0432\u0438\u0439 \u0434\u043b\u044f \u0440\u043e\u0441\u0442\u0430 \u0434\u0440\u0443\u0433\u0438\u0445. \u042f\u0440\u043a\u0430\u044f, \u044d\u0440\u043e\u0442\u0438\u0447\u043d\u0430\u044f, \u0432\u043b\u044e\u0431\u0447\u0438\u0432\u0430\u044f.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f","\u0432\u044b\u0441\u043e\u043a\u0438\u0439 (\u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043e\u0442 \u043d\u0430\u043f\u0440\u044f\u0436\u0435\u043d\u0438\u044f)","\u0441\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435\u043c","\u0427\u0435\u043b\u043e\u0432\u0435\u043a \u0441\u043e\u0437\u0434\u0430\u0435\u0442 \u0443\u0441\u043b\u043e\u0432\u0438\u044f \u0434\u043b\u044f \u0440\u043e\u0441\u0442\u0430 \u0434\u0440\u0443\u0433\u0438\u0445 \u043b\u044e\u0434\u0435\u0439. \u0411\u043e\u043b\u044c\u0448\u0435 \u043e\u0442\u043a\u0440\u044b\u0442 \u0434\u043b\u044f \u0441\u043e\u0437\u0434\u0430\u043d\u0438\u044f \u0441\u0435\u043c\u044c\u0438, \u0434\u043e\u043c\u0430\u0448\u043d\u0435\u0433\u043e \u043e\u0447\u0430\u0433\u0430, \u043d\u0430\u0438\u0431\u043e\u043b\u0435\u0435 \u0441\u0438\u043b\u044c\u043d\u043e \u043f\u0440\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043b\u0435\u0433\u043a\u043e\u0441\u0442\u044c \u0432 \u0431\u044b\u0442\u0443.","\u041c\u0438\u043b\u043e\u0441\u0435\u0440\u0434\u0438\u0435, \u043b\u044e\u0431\u043e\u0432\u044c, \u0434\u043e\u0431\u0440\u043e\u0442\u0430.","\u0412\u0437\u0440\u0430\u0449\u0438\u0432\u0430\u043d\u0438\u0435, \u043c\u044f\u0433\u043a\u043e\u0435 \u043d\u0430\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u0438\u0435. \u041d\u0430\u043a\u043e\u0440\u043c\u0438\u0442\u044c, \u043e\u0431\u043e\u0433\u0440\u0435\u0442\u044c, \u043f\u0440\u0438\u044e\u0442\u0438\u0442\u044c, \u0432\u043e\u0441\u043f\u0438\u0442\u0430\u0442\u044c. \u041b\u044e\u0431\u043e\u0432\u043d\u0430. \u0422\u0432\u043e\u0440\u0447\u0435\u0441\u043a\u0430\u044f \u043d\u0430\u0442\u0443\u0440\u0430.","\u0412\u043e\u0441\u043f\u0438\u0442\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0435, \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u044b.","\u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0434\u043e\u043b\u0436\u043d\u044b\u043c \u043f\u043e \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430\u043c, \u043d\u0435 \u0432\u044b\u043f\u043e\u043b\u043d\u0438\u0442\u044c \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430. \u0421\u0442\u0440\u0430\u0445 \u0441\u043a\u0443\u043f\u043e\u0441\u0442\u0438 \u0438 \u0431\u0435\u0437\u0434\u0435\u0442\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0430.","\u041e\u0431\u0440\u0430\u0449\u0435\u043d\u0438\u0435 \u043a \u043b\u044e\u0431\u043e\u0432\u043d\u043e\u0441\u0442\u0438, \u0431\u043b\u0438\u0437\u043e\u0441\u0442\u0438.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u043b\u044e\u0431\u0432\u0438 \u0438 \u0431\u043b\u0438\u0437\u043e\u0441\u0442\u0438.","\u0422\u0432\u043e\u0440\u0447\u0435\u0441\u0442\u0432\u043e",'\u041b\u0438\u0434\u0438\u0440\u0443\u044e\u0449\u0430\u044f \u0436\u0435\u043d\u0441\u043a\u0430\u044f \u043f\u043e\u0437\u0438\u0446\u0438\u044f, \u043f\u043b\u043e\u0434\u043e\u0440\u043e\u0434\u043d\u0430\u044f \u0437\u0435\u043c\u043d\u0430\u044f \u043b\u044e\u0431\u043e\u0432\u044c, \u0442\u043e\u0442\u0430\u043b\u044c\u043d\u043e\u0435 \u043c\u0430\u0442\u0435\u0440\u0438\u043d\u0441\u0442\u0432\u043e, "\u0431\u043e\u0433\u043e\u043c\u0430\u0442\u0435\u0440\u044c". \u0421\u043e\u0437\u0434\u0430\u043d\u0438\u0435 \u0443\u0441\u043b\u043e\u0432\u0438\u0439 \u0434\u043b\u044f \u0440\u043e\u0441\u0442\u0430 \u0434\u0440\u0443\u0433\u0438\u0445 \u043b\u044e\u0434\u0435\u0439 (\u043a\u0430\u043a \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u044c, \u0432\u044b\u0431\u0438\u0440\u0430\u0435\u0442 \u0441\u0444\u0435\u0440\u0443 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0434\u043b\u044f \u0441\u0432\u043e\u0435\u0439 \u043a\u043e\u043c\u0430\u043d\u0434\u044b \u0442\u0430\u043a\u0443\u044e, \u0433\u0434\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u0441\u043e\u0442\u0440\u0443\u0434\u043d\u0438\u043a -- \u043e\u0431\u044f\u0437\u0430\u043d \u0432\u044b\u0440\u0430\u0441\u0442\u0438). \u041d\u0435\u0433\u043b\u0430\u0441\u043d\u0430\u044f \u0432\u043b\u0430\u0441\u0442\u044c - \u0432\u043b\u0430\u0441\u0442\u044c \u0438 \u0441\u0438\u043b\u0430 \u043b\u044e\u0431\u0432\u0438. \u0421\u0438\u043b\u0430 \u043f\u0440\u043e\u0448\u0435\u043d\u0438\u044f, \u043f\u0440\u0438\u044f\u0442\u0438\u0435 (\xab\u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u044f\u044e\u0441\u044c\xbb), \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u0430\u044f \u0436\u0435\u0440\u0442\u0432\u0430 \u0434\u043b\u044f \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044f \u0442\u0435\u0445, \u043a\u043e\u0433\u043e \u0441\u0447\u0438\u0442\u0430\u0435\u0442 \u0441\u043b\u0430\u0431\u0435\u0435 \u0438\u043b\u0438 \u043c\u0435\u043d\u044c\u0448\u0435 (\u0447\u0430\u0441\u0442\u043e \u044d\u0442\u043e \u0434\u0435\u0442\u0438). \u0422\u0432\u043e\u0440\u0447\u0435\u0441\u0442\u0432\u043e, \u0438\u0434\u0435\u0438, \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u0430, \u0440\u0438\u0441\u043a\u0438. \u042f\u0440\u043a\u0438\u0439, \u0437\u0432\u043e\u043d\u043a\u0438\u0439, \u044d\u0440\u043e\u0442\u0438\u0447\u043d\u044b\u0439, \u0432\u043b\u044e\u0431\u0447\u0438\u0432\u044b\u0439. \u0421\u043e\u0437\u0434\u0430\u043d\u0438\u0435 \u0441\u0435\u043c\u044c\u0438 (\u0432\u044b\u0431\u0438\u0440\u0430\u0435\u0442 \u043f\u0430\u0440\u0442\u043d\u0451\u0440\u043e\u0432 \u0438\u0441\u043a\u043b\u044e\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0434\u043b\u044f \u044d\u0442\u043e\u0433\u043e), \u0434\u043e\u043c\u0430\u0448\u043d\u0435\u0433\u043e \u043e\u0447\u0430\u0433\u0430, \u043b\u0435\u0433\u043a\u043e\u0441\u0442\u044c \u0432 \u0431\u044b\u0442\u0443, \u0440\u043e\u0436\u0434\u0435\u043d\u0438\u0435 \u0438 \u0432\u044b\u0440\u0430\u0449\u0438\u0432\u0430\u043d\u0438\u0435 \u0434\u0435\u0442\u0435\u0439. \u041a\u043e\u0433\u0434\u0430 \u043c\u043d\u043e\u0433\u043e \u0442\u0440\u043e\u0435\u043a - \u043c\u043d\u043e\u0433\u043e\u0434\u0435\u0442\u0435\u043d.',"\u041c\u0430\u0442\u044c","\u0417\u0430\u0431\u043e\u0442\u0430, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u0442\u044c \u0443\u0441\u043b\u043e\u0432\u0438\u044f \u0434\u043b\u044f \u0440\u043e\u0441\u0442\u0430.","\u041f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442, \u0432\u0434\u043e\u0445\u043d\u043e\u0432\u043b\u044f\u0435\u0442, \u043f\u0438\u0442\u0430\u0435\u0442 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u0438 \u0438 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e, \u0442\u0432\u043e\u0440\u0447\u0435\u0441\u043a\u0438\u0439 \u043f\u043e\u0434\u0445\u043e\u0434.","\u041f\u0440\u0438\u043d\u044f\u0442\u0438\u0435 \u043d\u0430 \u0441\u0435\u0431\u044f \u0447\u0440\u0435\u0437\u043c\u0435\u0440\u043d\u043e\u0439 \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0437\u0430 \u0434\u0440\u0443\u0433\u0438\u0445, \u0441\u0442\u0440\u0430\u0445 \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0430.","\u0412\u0430\u0448\u0430 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u044f\u044f \u041c\u0430\u0442\u044c \u043f\u0440\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u043f\u043e\u0437\u0430\u0431\u043e\u0442\u0438\u0442\u044c\u0441\u044f \u043e \u043a\u043e\u043c-\u0442\u043e \u0438\u043b\u0438 \u0432\u0437\u0440\u0430\u0441\u0442\u0438\u0442\u044c \u043d\u043e\u0432\u0443\u044e \u0438\u0434\u0435\u044e.","\xab\u041e \u043a\u043e\u043c \u0438\u043b\u0438 \u043e \u0447\u0451\u043c \u044f \u0437\u0430\u0431\u043e\u0447\u0443\u0441\u044c \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u0431\u0435\u0441\u043a\u043e\u0440\u044b\u0441\u0442\u043d\u043e?\xbb","\u0417\u0430\u0431\u043e\u0442\u0430, \u043d\u0435\u0436\u043d\u043e\u0441\u0442\u044c, \u0442\u0435\u043f\u043b\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043e\u0442 \u0440\u043e\u0441\u0442\u0430 \u0434\u0440\u0443\u0433\u0438\u0445, \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0434\u043e\u043b\u0433\u0430, \u0441\u0442\u0440\u0430\u0445 \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0430, \u044d\u0440\u043e\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043f\u0440\u0438\u0442\u044f\u0433\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c.","\u0429\u0435\u043c\u044f\u0449\u0430\u044f \u043d\u0435\u0436\u043d\u043e\u0441\u0442\u044c \u0438 \u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u043e\u0431\u043e\u0433\u0440\u0435\u0442\u044c, \u043d\u0430\u043a\u043e\u0440\u043c\u0438\u0442\u044c, \u0437\u0430\u0449\u0438\u0442\u0438\u0442\u044c. \u0422\u0432\u043e\u0440\u0447\u0435\u0441\u043a\u0438\u0439 \u043f\u043e\u0434\u044a\u0435\u043c \u0438 \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043f\u0440\u0438 \u0441\u043e\u0437\u0434\u0430\u043d\u0438\u0438 \u0443\u0441\u043b\u043e\u0432\u0438\u0439 \u0434\u043b\u044f \u0431\u043b\u0438\u0437\u043a\u0438\u0445 (\u043e\u0431\u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u043e \u0434\u043e\u043c\u0430, \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u043a\u0430 \u043f\u0440\u043e\u0435\u043a\u0442\u043e\u0432). \u0422\u0440\u0435\u0432\u043e\u0433\u0430 \u0438 \u0441\u0442\u0440\u0430\u0445, \u0435\u0441\u043b\u0438 \u043f\u043e\u0434\u043e\u043f\u0435\u0447\u043d\u044b\u0435 \u043e\u0442\u0434\u0430\u043b\u044f\u044e\u0442\u0441\u044f \u0438\u043b\u0438 \u043d\u0435 \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0442 \u0437\u0430\u0431\u043e\u0442\u0443. \u042f\u0440\u043a\u0430\u044f, \u043c\u0430\u0433\u043d\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0432\u043b\u044e\u0431\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u043a\u0430\u043a \u0444\u043e\u0440\u043c\u0430 \u043f\u0440\u043e\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u0438\u043d\u0442\u0435\u0440\u0435\u0441\u0430 \u043a \u0436\u0438\u0437\u043d\u0438."],t.l)
B.V1=new A.aL(B.aI,["\u0418\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0418\u043c\u043f\u0435\u0440\u0430\u0442\u043e\u0440","\u0421\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0430, \u0432\u043b\u0430\u0441\u0442\u044c, \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c. \u0423\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0430 \u0447\u0435\u0440\u0435\u0437 \u043b\u043e\u0433\u0438\u043a\u0443.","\u0423\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u043e\u043d\u043d\u044b\u043c\u0438 \u043f\u043e\u0442\u043e\u043a\u0430\u043c\u0438. \u0425\u043e\u0440\u043e\u0448\u0438\u0439 \u0438\u0441\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c. \u041e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043b\u0438\u0447\u043d\u043e\u0439 \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u044b.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044e, \u043e\u0442\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u0432\u044b\u0433\u043e\u0434\u0435","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u043d\u0430\u0431\u043e\u0440 \u0438 \u043e\u043f\u0435\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439",'\u0421\u043a\u043b\u043e\u043d\u0435\u043d \u043a \u0440\u0430\u0431\u043e\u0442\u0435 \u0441 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439, \u0430\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0435. \u041f\u0440\u0438 \u044d\u0442\u043e\u043c \u043d\u0430\u0431\u043b\u044e\u0434\u0430\u0435\u0442\u0441\u044f \u0441\u043f\u0430\u0434 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u044b, \u043d\u0443\u0436\u0435\u043d \u0442\u043e\u0442, \u043a\u0442\u043e "\u043d\u0430\u043f\u0440\u0430\u0432\u0438\u0442" \u044d\u0442\u0443 \u0440\u0430\u0431\u043e\u0442\u0443.',"\u041f\u043e\u0438\u0441\u043a, \u043f\u043e\u0433\u043b\u043e\u0449\u0435\u043d\u0438\u0435 \u0438 \u043e\u043f\u0435\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439.","\u041e\u043f\u0435\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439: \u043f\u043e\u043a\u0443\u043f\u043a\u0430, \u043f\u0440\u043e\u0434\u0430\u0436\u0430, \u043e\u0431\u043c\u0435\u043d \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438. \u0410\u0432\u0430\u043d\u0442\u044e\u0440\u0430.","\u041f\u0440\u0435\u0434\u043e\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438 \u043a\u0430\u043a \u0443\u0441\u043b\u0443\u0433\u0438.","\u0421\u0442\u0440\u0430\u0445 \u043b\u0436\u0438 \u0438 \u043b\u0438\u0446\u0435\u043c\u0435\u0440\u0438\u044f. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435\u043a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0442\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0433\u043e\u043b\u043e\u0434\u0430.","\u041f\u0440\u0438 \u0434\u0435\u0444\u0438\u0446\u0438\u0442\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438 \u0432 \u044d\u043a\u0441\u0442\u0440\u0435\u043d\u043d\u043e\u043c \u0441\u043b\u0443\u0447\u0430\u0435 \u0432\u043e\u0437\u043d\u0438\u043a\u0430\u0435\u0442 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043e\u043f\u0435\u0440\u0430\u0442\u0438\u0432\u043d\u043e \u0435\u0435 \u043d\u0430\u0439\u0442\u0438.","\u0412\u0430\u0436\u043d\u043e \u0443\u0447\u0438\u0442\u044c\u0441\u044f \u0432\u043b\u0430\u0434\u0435\u0442\u044c \u0438 \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0430\u0442\u044c\u0441\u044f \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439.","\u0411\u0443\u043d\u0442\u0430\u0440\u044c",'\u0423\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u043e\u043d\u043d\u044b\u043c\u0438 \u043f\u043e\u0442\u043e\u043a\u0430\u043c\u0438. \u0424\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438 \u043a\u0430\u043a \u043f\u0440\u043e\u0434\u0443\u043a\u0442 \u043f\u0440\u043e\u0434\u0430\u0436\u0438, \u0430\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0430. \u0411\u044b\u0441\u0442\u0440\u044b\u0439 \u043d\u0430\u0431\u043e\u0440 \u0438 \u043e\u0431\u043c\u0435\u043d \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439 \u043f\u0440\u0438 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0438 \u0437\u0430\u0434\u0430\u0447 "\u043f\u043e\u0438\u0441\u043a\u0430". \u041e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043b\u0438\u0447\u043d\u043e\u0439 \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u044b (\u043d\u0443\u0436\u0435\u043d \u0442\u043e\u0442, \u043a\u0442\u043e \u043d\u0430\u043f\u0440\u0430\u0432\u0438\u0442 \u044d\u0442\u0443 \u0440\u0430\u0431\u043e\u0442\u044b), \u043d\u043e \u043f\u0440\u0438 \u044d\u0442\u043e\u043c \u0445\u043e\u0440\u043e\u0448\u0430\u044f \u043f\u0440\u0435\u0434\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u044c (\u043f\u0440\u0438 \u0443\u0441\u043b\u043e\u0432\u0438\u0438, \u0447\u0442\u043e \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u044b \u0438 \u043f\u043e\u043d\u044f\u0442\u043d\u044b \u0437\u0430\u0434\u0430\u0447\u0438). \u0412\u0435\u043b\u0438\u043a\u043e\u043b\u0435\u043f\u043d\u044b\u0435 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0438 \u0437\u0430\u0434\u0430\u0442\u043a\u0438 \u0445\u043e\u0440\u043e\u0448\u0435\u0433\u043e \u0438\u0441\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044f (\u0435\u0441\u043b\u0438 \u0438 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044e\u0442\u0441\u044f \u0441\u0440\u0435\u0434\u0438 \u043d\u0438\u0445 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0446\u044b, \u0442\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u0434 \u0447\u044c\u0438\u043c-\u0442\u043e \u0433\u0440\u0430\u043c\u043e\u0442\u043d\u044b\u043c \u043d\u0430\u0447\u0430\u043b\u043e\u043c - \u044d\u0442\u043e \u0437\u0430\u043b\u043e\u0433 \u0438\u0445 \u0443\u0441\u043f\u0435\u0445\u0430). \u0413\u043b\u0430\u0441\u043d\u0430\u044f \u0432\u043b\u0430\u0441\u0442\u044c, \u0432\u043d\u0435\u0448\u043d\u0435\u0435 \u043b\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u043e, \u0431\u043e\u0440\u044c\u0431\u0430 \u0437\u0430 \u0432\u043b\u0430\u0441\u0442\u044c, \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u0430\u0432\u0442\u043e\u0440\u0438\u0442\u0435\u0442\u0443, \u0430\u0432\u0442\u043e\u0440\u0438\u0442\u0430\u0440\u043d\u043e\u0441\u0442\u0438 (\u0434\u043b\u044f \u043c\u0443\u0436\u0447\u0438\u043d -- \u0445\u043e\u0440\u043e\u0448\u0438\u0439 \u0430\u0441\u043f\u0435\u043a\u0442, \u0434\u043b\u044f \u0436\u0435\u043d\u0449\u0438\u043d -- \u0442\u044f\u0436\u0435\u043b\u043e\u0432\u0430\u0442\u044b\u0439). \u041b\u0443\u0447\u0448\u0438\u0439 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0442\u043e\u0440. \u0412\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u044c \u0432\u0440\u0435\u043c\u0435\u043d\u0438!!! \u0417\u0430\u0449\u0438\u0449\u0430\u0435\u0442, \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442, \u0434\u043e\u0432\u043e\u0434\u0438\u0442 \u043b\u0438\u0434\u0435\u0440\u0430 \u0434\u043e \u0432\u043b\u0430\u0441\u0442\u0438, \u0438\u0434\u0451\u0442 \u0441 \u043d\u0438\u043c \u0442\u043e\u0442\u0430\u043b\u044c\u043d\u043e \u0434\u043e \u043a\u043e\u043d\u0446\u0430. \u0423 \xab4\xbb \u043d\u0435\u0442 \u043c\u0435\u0441\u0442\u0430 \u0437\u0430 \u0444\u0438\u043d\u0438\u0448\u043d\u043e\u0439 \u0447\u0435\u0440\u0442\u043e\u0439. \u0415\u0441\u0442\u044c \u0432\u043b\u0430\u0441\u0442\u044c \u043e\u0444\u0438\u0446\u0438\u0430\u043b\u044c\u043d\u0430\u044f, \u043d\u043e \u043d\u0435\u0442 \u043f\u043e\u0437\u0438\u0446\u0438\u0438 \u043b\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u0430. \u0411\u0435\u0437 \xab4\xbb \u0438\u0441\u0442\u0438\u043d\u043d\u043e\u043c\u0443 \u043b\u0438\u0434\u0435\u0440\u0443, \u0430 \u0438\u043c\u0435\u043d\u043d\u043e \xab3\xbb \u0438 \xab5\xbb - \u043d\u0438\u043a\u0443\u0434\u0430. \u0421\u043b\u0430\u0431\u043e\u0435 \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u0435, \u043c\u043d\u043e\u0433\u043e \u043d\u0430\u043f\u0440\u044f\u0433\u0430\u0435\u0442\u0441\u044f.',"\u0410\u043d\u0430\u043b\u0438\u0442\u0438\u043a","\u0421\u0431\u043e\u0440 \u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438.","\u0412\u0438\u0434\u0438\u0442 \u0441\u0445\u0435\u043c\u044b \u0438 \u0441\u0432\u044f\u0437\u0438, \u043f\u0440\u0435\u043a\u0440\u0430\u0441\u043d\u044b\u0439 \u0438\u0441\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c \u0447\u0451\u0442\u043a\u043e\u0433\u043e \u043f\u043b\u0430\u043d\u0430.","\u041d\u0435\u0445\u0432\u0430\u0442\u043a\u0430 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u044b, \u043f\u043e\u0442\u0440\u0435\u0431\u043d\u043e\u0441\u0442\u044c \u0432 \u043b\u0438\u0434\u0435\u0440\u0435, \u0441\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u043d\u0435\u043a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0442\u043d\u044b\u043c.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0410\u043d\u0430\u043b\u0438\u0442\u0438\u043a \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0434\u043b\u044f \u043e\u0446\u0435\u043d\u043a\u0438 \u0440\u0438\u0441\u043a\u043e\u0432 \u0438 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0442\u0430\u043a\u0442\u0438\u043a\u0438.","\xab\u0414\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u043b\u0438 \u044f \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044e, \u0438\u043b\u0438 \u043b\u0438\u0448\u044c \u0430\u043d\u0430\u043b\u0438\u0437\u0438\u0440\u0443\u044e \u0438 \u0436\u0434\u0443 \u0443\u043a\u0430\u0437\u0430\u043d\u0438\u0439?\xbb","\u0418\u043d\u0442\u0435\u0440\u0435\u0441 \u043a \u0441\u0445\u0435\u043c\u0430\u043c, \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u043d\u0430 \u043d\u0435\u0434\u043e\u0441\u0442\u043e\u0432\u0435\u0440\u043d\u0443\u044e \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044e, \u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435 \u043e\u0442 \u0447\u0435\u0442\u043a\u043e\u0433\u043e \u043f\u043b\u0430\u043d\u0430, \u0441\u0442\u0440\u0430\u0445 \u043d\u0435\u043a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0442\u043d\u043e\u0441\u0442\u0438.","\u0410\u0437\u0430\u0440\u0442 \u0438 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u0438 \u0441\u0431\u043e\u0440\u0435 \u0438 \u0430\u043d\u0430\u043b\u0438\u0437\u0435 \u0434\u0430\u043d\u043d\u044b\u0445. \u041f\u0440\u0435\u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u0433\u043d\u0435\u0432 \u0432 \u043e\u0442\u0432\u0435\u0442 \u043d\u0430 \u043b\u043e\u0436\u044c \u0438\u043b\u0438 \u043c\u0430\u043d\u0438\u043f\u0443\u043b\u044f\u0446\u0438\u0438 \u0444\u0430\u043a\u0442\u0430\u043c\u0438. \u0423\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0438 \u043d\u0430\u0434\u0435\u0436\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u0438 \u0440\u0430\u0431\u043e\u0442\u0435 \u043f\u043e \u0438\u043d\u0441\u0442\u0440\u0443\u043a\u0446\u0438\u0438. \u041d\u0435\u0440\u0432\u043d\u043e\u0435 \u0431\u0435\u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u043e \u0438 \u0441\u0442\u0443\u043f\u043e\u0440 \u0432 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u0438, \u0433\u0434\u0435 \u043d\u0435\u0442 \u044f\u0441\u043d\u043e\u0439 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438."],t.l)
B.UW=new A.aL(B.aI,["\u0421\u0430\u043c\u0435\u0446","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f. \u0412\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u044c\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0418\u0435\u0440\u043e\u0444\u0430\u043d\u0442","\u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u0440\u0435\u043b\u0438\u0433\u0438\u044f, \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u043d\u043e\u0440\u043c\u044b. \u0414\u0443\u0445\u043e\u0432\u043d\u044b\u0439 \u043d\u0430\u0441\u0442\u0430\u0432\u043d\u0438\u043a \u0438 \u043f\u0440\u043e\u0432\u043e\u0434\u043d\u0438\u043a.","\u041b\u0438\u0434\u0438\u0440\u0443\u044e\u0449\u0430\u044f \u043c\u0443\u0436\u0441\u043a\u0430\u044f \u043f\u043e\u0437\u0438\u0446\u0438\u044f. \u0420\u0430\u0441\u0448\u0438\u0440\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430. \u041c\u0443\u0436\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c, \u0432\u043b\u0430\u0441\u0442\u044c, \u0441\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u0435.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044e, \u0437\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043f\u0435\u0440\u0435\u0441\u043c\u043e\u0442\u0440\u0443 \u043f\u0440\u0430\u0432\u0438\u043b","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u0437\u0430\u0432\u043e\u0435\u0432\u0430\u043d\u0438\u0435 \u0438 \u0441\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435, \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043d\u0438\u0435","\u0421\u0442\u0440\u0435\u043c\u0438\u0442\u0441\u044f \u043f\u0440\u043e\u044f\u0432\u0438\u0442\u044c \u0441\u0432\u043e\u044e \u0432\u043b\u0430\u0441\u0442\u044c \u0438 \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c. \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044f \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u044b \u043d\u0430 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043d\u0438\u0435 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430 \u0438 \u0441\u043e\u0437\u0434\u0430\u043d\u0438\u044f \u043d\u043e\u0432\u043e\u0433\u043e.","\u0422\u043e\u0442\u0430\u043b\u044c\u043d\u044b\u0439 \u0437\u0430\u0445\u0432\u0430\u0442 \u0432\u043b\u0430\u0441\u0442\u0438 \u0447\u0435\u0440\u0435\u0437 \u043f\u0440\u043e\u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u0435\u0431\u044f (\u0434\u043e\u0441\u0442\u043e\u0439\u043d\u044b\u0435 \u043f\u043e\u0441\u0442\u0443\u043f\u043a\u0438).","\u041a\u043e\u043c\u043f\u0440\u043e\u043c\u0438\u0441\u0441\u043e\u0432 \u043d\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442.","\u0421\u0446\u0435\u043d\u0430, \u043f\u0443\u0431\u043b\u0438\u043a\u0430, \u0430\u0440\u043c\u0438\u044f, \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u0430.","\u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0441\u0438\u043b\u044c\u043d\u044b\u043c \u0438 \u0441\u043b\u0430\u0431\u044b\u043c \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435 \u0440\u0435\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u0438 \u0441\u0435\u0431\u044f \u0432 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0438, \u0438 \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0441\u0442\u0440\u0430\u0445 \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430. \u0421\u0442\u0440\u0430\u0445 \u0431\u0435\u0437\u0434\u0435\u0442\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u0441\u0432\u043e\u0435 \u043c\u0443\u0436\u0435\u0441\u0442\u0432\u043e.","\u041f\u0440\u0438\u0431\u0435\u0433\u0430\u043d\u0438\u0435 \u043a \u0433\u043b\u0430\u0441\u043d\u043e\u0439 \u0432\u043b\u0430\u0441\u0442\u0438. \u0414\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043b\u0443.","\u0423\u0441\u043b\u043e\u0432\u0438\u0435 \u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0438 \u0434\u043e\u0441\u0442\u043e\u0438\u043d\u0441\u0442\u0432\u0430.","\u041d\u0438-\u0447\u0442\u043e",'\u041b\u0438\u0434\u0438\u0440\u0443\u044e\u0449\u0430\u044f \u043c\u0443\u0436\u0441\u043a\u0430\u044f \u043f\u043e\u0437\u0438\u0446\u0438\u044f, \u0442\u043e\u0442\u0430\u043b\u044c\u043d\u0430\u044f \u0432\u043b\u0430\u0441\u0442\u044c, "\u043f\u0430\u0442\u0440\u0438\u0430\u0440\u0445". \u0420\u0430\u0441\u0448\u0438\u0440\u0435\u043d\u0438\u0435 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430 \u0438 \u0441\u043e\u0437\u0434\u0430\u043d\u0438\u0435 \u043d\u043e\u0432\u043e\u0433\u043e. \u042f\u0440\u043a\u043e \u0432\u044b\u0440\u0430\u0436\u0435\u043d\u043d\u044b\u0435 \u043c\u0443\u0436\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0438 \u0432\u043b\u0430\u0441\u0442\u044c (\u0433\u043b\u0430\u0441\u043d\u0430\u044f, \u0442\u0440\u0438\u0431\u0443\u043d\u043d\u0430\u044f). \u0421\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u0435, \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u0437\u0430\u0432\u043e\u0435\u0432\u044b\u0432\u0430\u0442\u044c, \u043d\u043e \u043d\u0435 \u043f\u0443\u0442\u0435\u043c \u0434\u0438\u043a\u0442\u0430\u0442\u0430, \u0430 \u043f\u0443\u0442\u0435\u043c \u0443\u0437\u0430\u043a\u043e\u043d\u0438\u0432\u0430\u043d\u0438\u044f \u0432\u043b\u0430\u0441\u0442\u0438, \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u041e\u0447\u0435\u043d\u044c \u0441\u0438\u043b\u044c\u043d\u044b\u0439, \u043d\u043e \u0431\u044b\u0432\u0430\u0435\u0442 \u0442\u044f\u0436\u0435\u043b\u043e - \u0432\u0441\u0435 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0434\u0435\u043b\u0430\u0442\u044c \u0441\u0430\u043c\u043e\u043c\u0443. \u0422\u0440\u0443\u0434\u043d\u043e\u0441\u0442\u044c \xab5\xbb \u0432 \u043f\u043e\u0437\u0451\u0440\u0441\u0442\u0432\u0435. \u041e\u0441\u043e\u0431\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0434\u043b\u044f \u0436\u0435\u043d\u0441\u043a\u043e\u0439 \u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0438: \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043d\u0430\u0437\u0438\u0434\u0430\u0442\u044c \u0438 \u043a\u0440\u0438\u0442\u0438\u043a\u043e\u0432\u0430\u0442\u044c \u043e\u0448\u0438\u0431\u043a\u0438.',"\u041b\u0438\u0434\u0435\u0440","\u041e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c, \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043d\u0438\u044e \u0432\u043b\u0438\u044f\u043d\u0438\u044f.","\u0411\u0435\u0440\u0435\u0442 \u043d\u0430 \u0441\u0435\u0431\u044f \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c, \u0441\u043e\u0437\u0434\u0430\u0435\u0442 \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e \u0432\u0435\u0434\u0451\u0442 \u0437\u0430 \u0441\u043e\u0431\u043e\u0439.","\u041f\u043e\u0437\u0451\u0440\u0441\u0442\u0432\u043e, \u043d\u0435\u0443\u043c\u0435\u043d\u0438\u0435 \u0434\u0435\u043b\u0435\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c, \u0441\u0442\u0440\u0430\u0445 \u043f\u0440\u043e\u044f\u0432\u0438\u0442\u044c \u0441\u043b\u0430\u0431\u043e\u0441\u0442\u044c.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u041b\u0438\u0434\u0435\u0440 \u0432\u0435\u0434\u0451\u0442 \u0432\u0430\u0441, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0432\u043e\u0437\u0433\u043b\u0430\u0432\u0438\u0442\u044c \u043f\u0440\u043e\u0446\u0435\u0441\u0441.","\xab\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e \u044f \u0441\u0432\u043e\u044e \u0432\u043b\u0430\u0441\u0442\u044c \u0434\u043b\u044f \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \u0434\u043b\u044f \u0441\u043e\u0437\u0434\u0430\u043d\u0438\u044f \u043f\u043e\u0440\u044f\u0434\u043a\u0430?\xbb","\u0423\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c, \u0433\u043d\u0435\u0432 (\u043d\u0430 \u0441\u043e\u043f\u0440\u043e\u0442\u0438\u0432\u043b\u0435\u043d\u0438\u0435), \u0433\u043e\u0440\u0434\u043e\u0441\u0442\u044c, \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u0430\u044f \u043d\u0435\u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c (\u0441\u0442\u0440\u0430\u0445 \u043f\u0440\u043e\u044f\u0432\u0438\u0442\u044c \u0441\u043b\u0430\u0431\u043e\u0441\u0442\u044c), \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438.","\u0413\u0440\u043e\u043c\u043a\u0438\u0439, \u0432\u043b\u0430\u0441\u0442\u043d\u044b\u0439 \u0433\u043d\u0435\u0432 \u043a\u0430\u043a \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u0441\u043e\u043f\u0440\u043e\u0442\u0438\u0432\u043b\u0435\u043d\u0438\u044f \u0438 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f \u0441\u0432\u043e\u0435\u0433\u043e \u0440\u0435\u0448\u0435\u043d\u0438\u044f. \u041c\u043e\u043b\u0447\u0430\u043b\u0438\u0432\u0430\u044f, \u0445\u043e\u043b\u043e\u0434\u043d\u0430\u044f \u0433\u043e\u0440\u0434\u043e\u0441\u0442\u044c \u0437\u0430 \u0434\u043e\u0441\u0442\u0438\u0433\u043d\u0443\u0442\u044b\u0435 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b. \u041f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u043e\u0435 \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0438 \u043e\u0442\u0441\u0442\u0440\u0430\u043d\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0432 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044f\u0445, \u0433\u0434\u0435 \u043d\u0435\u043b\u044c\u0437\u044f \u043f\u0440\u043e\u044f\u0432\u0438\u0442\u044c \u0441\u0438\u043b\u0443 \u043d\u0430\u043f\u0440\u044f\u043c\u0443\u044e. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u0433\u043e \u0443\u0434\u043e\u0432\u043b\u0435\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u044f, \u043a\u043e\u0433\u0434\u0430 \u0435\u0433\u043e \u043b\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u044e\u0442 \u0434\u043e\u0431\u0440\u043e\u0432\u043e\u043b\u044c\u043d\u043e."],t.l)
B.V_=new A.aL(B.aI,["\u0412\u044b\u0433\u043e\u0434\u0430","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f. \u0421\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u0432\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u0438","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u0412\u043b\u044e\u0431\u043b\u0451\u043d\u043d\u044b\u0435","\u0412\u044b\u0431\u043e\u0440, \u0433\u0430\u0440\u043c\u043e\u043d\u0438\u044f, \u043f\u0430\u0440\u0442\u043d\u0451\u0440\u0441\u0442\u0432\u043e. \u0421\u043e\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u043f\u043e\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u0435\u0439.","\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u043a\u0430\u043a \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u0430. \u0421\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u043c \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f\u043c.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f, \u0417\u0430\u043c\u043a\u043d\u0443\u0442\u0430\u044f","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u043f\u0440\u0435\u0434\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u044c, \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f, \u0441\u0432\u044f\u0437\u0438","\u041e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u0438 \u043f\u0440\u043e\u044f\u0432\u043b\u044f\u0435\u0442 \u0441\u0432\u043e\u044e \u043f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0435\u0439, \u043a\u0430\u043a \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u043e\u0431\u0449\u0435\u043d\u0438\u044f \u0441 \u043b\u044e\u0434\u044c\u043c\u0438. \u0422\u044f\u0433\u0430 \u043a \u043d\u043e\u0432\u044b\u043c \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u043c \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f\u043c.","\u0412\u043d\u0435\u0434\u0440\u0435\u043d\u0438\u0435, \u043f\u0440\u0438\u0441\u043f\u043e\u0441\u043e\u0431\u043b\u0435\u043d\u0438\u0435 \u0438 \u043e\u043f\u0435\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435.","\u041f\u043e\u043b\u0443\u0447\u0435\u043d\u0438\u0435 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0432\u044b\u0433\u043e\u0434\u044b \u0438\u0437 \u043b\u044e\u0431\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438. \u041f\u0440\u0438\u0441\u043f\u043e\u0441\u0430\u0431\u043b\u0438\u0432\u0430\u0435\u0442\u0441\u044f. \u0418\u0449\u0435\u0442 \u0431\u043e\u043b\u0435\u0435 \u0441\u0438\u043b\u044c\u043d\u043e\u0433\u043e, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0434\u0441\u0442\u0440\u043e\u0438\u0442\u0441\u044f \u043f\u043e\u0434 \u043d\u0435\u0433\u043e.","\u041f\u0440\u043e\u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u0435\u0431\u044f \u043a\u0430\u043a \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0430 \u043f\u0440\u043e\u0434\u0430\u0436\u0438.","\u0421\u0442\u0440\u0430\u0445 \u043f\u0440\u0435\u043b\u044c\u0449\u0435\u043d\u0438\u044f. \u0421\u0442\u0440\u0430\u0445 \u043f\u043e\u0442\u0435\u0440\u044f\u0442\u044c \u0432\u044b\u0433\u043e\u0434\u0443. \u0421\u0442\u0440\u0430\u0445 \u0441\u0435\u043a\u0441\u0443\u0430\u043b\u044c\u043d\u043e\u0439 \u043d\u0435\u043f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0431\u043e\u043b\u0438.","\u0412\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u0438\u0431\u0435\u0433\u0430\u0442\u044c \u043a \u043f\u0440\u0435\u0434\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u0438, \u043c\u0438\u043c\u0438\u043a\u0440\u0438\u0438 \u0438 \u043f\u0440\u0435\u0434\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u043e\u0439 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438.","\u0412\u0430\u0436\u043d\u043e \u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044e \u0434\u0432\u043e\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u043f\u0440\u0438\u0440\u043e\u0434\u044b.","\u041b\u044e\u0431\u043e\u0432\u043d\u0438\u043a\u0438","\u041e\u0442\u043a\u0440\u044b\u0442\u0438\u0435 \u0438 \u043f\u0440\u043e\u044f\u0432\u043b\u0435\u043d\u0438\u0435 \u0441\u0432\u043e\u0435\u0439 \u043f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438, \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u0435\u0451, \u043a\u0430\u043a \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u0430 \u043e\u0431\u0449\u0435\u043d\u0438\u044f \u0441 \u043b\u044e\u0434\u044c\u043c\u0438. \u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u0438\u0441\u043f\u043e\u0441\u043e\u0431\u0438\u0442\u044c\u0441\u044f \u043a \u0431\u043e\u043b\u0435\u0435 \u0441\u0438\u043b\u044c\u043d\u043e\u043c\u0443 \u0432 \u043b\u044e\u0431\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0437\u0430 \u0441\u0447\u0435\u0442 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u0414\u0432\u043e\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439, \u0441\u043a\u043b\u043e\u043d\u043d\u044b\u0439 \u043a \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0443 \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438. \u0425\u043e\u0440\u043e\u0448\u0430\u044f \u043f\u0440\u0435\u0434\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u044c. \u0421\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u043c \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f\u043c (\u043f\u0440\u0438 \u043d\u0438\u0437\u043a\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u0435 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u043e\u0441\u043d\u043e\u0432\u043d\u0430\u044f \u043f\u043e\u0442\u0440\u0435\u0431\u043d\u043e\u0441\u0442\u044c -- \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u0430\u044f \u0432\u044b\u0433\u043e\u0434\u0430, \u043b\u0435\u0433\u043a\u0438\u0435 \u0434\u0435\u043d\u044c\u0433\u0438).","\u0418\u0441\u043a\u0443\u0441\u0438\u0442\u0435\u043b\u044c","\u041f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0443\u043c\u0435\u043d\u0438\u0435 \u0432\u0438\u0434\u0435\u0442\u044c \u0438 \u0438\u0437\u0432\u043b\u0435\u043a\u0430\u0442\u044c \u0432\u044b\u0433\u043e\u0434\u0443.","\u041c\u0430\u0441\u0442\u0435\u0440 \u043e\u0431\u0430\u044f\u043d\u0438\u044f \u0438 \u0443\u0431\u0435\u0436\u0434\u0435\u043d\u0438\u044f, \u043b\u0435\u0433\u043a\u043e \u043d\u0430\u0445\u043e\u0434\u0438\u0442 \u0441\u043b\u0430\u0431\u044b\u0435 \u043c\u0435\u0441\u0442\u0430 \u0434\u0440\u0443\u0433\u0438\u0445 \u0438 \u043f\u0440\u0435\u0434\u043b\u0430\u0433\u0430\u0435\u0442 \u0432\u044b\u0433\u043e\u0434\u043d\u044b\u0435 \u0441\u0434\u0435\u043b\u043a\u0438.","\u0413\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u044c \u043f\u043e\u0441\u0442\u0443\u043f\u0438\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0430\u043c\u0438 \u0440\u0430\u0434\u0438 \u043d\u0430\u0436\u0438\u0432\u044b, \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u044c \u043e\u0442 \u0432\u043d\u0435\u0448\u043d\u0435\u0433\u043e \u043e\u0434\u043e\u0431\u0440\u0435\u043d\u0438\u044f.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0418\u0441\u043a\u0443\u0441\u0438\u0442\u0435\u043b\u044c \u0430\u043a\u0442\u0438\u0432\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0432 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044f\u0445 \u0442\u043e\u0440\u0433\u043e\u0432\u043b\u0438, \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u043e\u0432 \u0438 \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u0432\u044b\u0433\u043e\u0434\u043d\u043e\u0435 \u0432\u043f\u0435\u0447\u0430\u0442\u043b\u0435\u043d\u0438\u0435.","\xab\u042f \u0438\u0441\u043a\u0440\u0435\u043d\u043d\u0435 \u043f\u0440\u043e\u044f\u0432\u043b\u044f\u044e \u0438\u043d\u0442\u0435\u0440\u0435\u0441 \u043a \u043b\u044e\u0434\u044f\u043c \u0438\u043b\u0438 \u043f\u0440\u043e\u0441\u0442\u043e \u043f\u044b\u0442\u0430\u044e\u0441\u044c \u0438\u0437\u0432\u043b\u0435\u0447\u044c \u0438\u0437 \u043d\u0438\u0445 \u043f\u043e\u043b\u044c\u0437\u0443?\xbb","\u0412\u043b\u0435\u0447\u0435\u043d\u0438\u0435, \u0441\u043e\u0431\u043b\u0430\u0437\u043d, \u043b\u0435\u0433\u043a\u0430\u044f \u0437\u0430\u0432\u0438\u0441\u0442\u044c (\u043a\u0430\u043a \u0441\u0442\u0438\u043c\u0443\u043b), \u0441\u0442\u0440\u0430\u0445 \u043f\u043e\u0442\u0435\u0440\u044f\u0442\u044c \u0432\u044b\u0433\u043e\u0434\u0443, \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u043d\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043e\u0442 \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f.","\u041e\u0431\u0430\u044f\u0442\u0435\u043b\u044c\u043d\u0430\u044f, \u0438\u0433\u0440\u0438\u0432\u0430\u044f \u0443\u043b\u044b\u0431\u043a\u0430 \u0438 \u0444\u043b\u0438\u0440\u0442 \u043a\u0430\u043a \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u0434\u043b\u044f \u0437\u0430\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f \u0432\u044b\u0433\u043e\u0434\u043d\u043e\u0439 \u0441\u0434\u0435\u043b\u043a\u0438. \u041e\u0441\u0442\u0440\u0430\u044f, \u043d\u043e \u0431\u044b\u0441\u0442\u0440\u043e \u043f\u0440\u043e\u0445\u043e\u0434\u044f\u0449\u0430\u044f \u0434\u043e\u0441\u0430\u0434\u0430, \u0435\u0441\u043b\u0438 \u043a\u0442\u043e-\u0442\u043e \u043f\u043e\u043b\u0443\u0447\u0438\u043b \u043b\u0443\u0447\u0448\u0443\u044e \u0434\u043e\u043b\u044e. \u0421\u0442\u0440\u0430\u0445 \u0438 \u043d\u0435\u0440\u0432\u043e\u0437\u043d\u043e\u0441\u0442\u044c, \u043a\u043e\u0433\u0434\u0430 \u0441\u0434\u0435\u043b\u043a\u0430 \u043f\u043e\u0434 \u0443\u0433\u0440\u043e\u0437\u043e\u0439 \u0441\u0440\u044b\u0432\u0430. \u0421\u0438\u044f\u043d\u0438\u0435 \u0438 \u0434\u0435\u043c\u043e\u043d\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0435 \u0443\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0438\u0435 \u043e\u0442 \u043d\u043e\u0432\u043e\u0433\u043e \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f."],t.l)
B.V7=new A.aL(B.aI,["\u0412\u0440\u0435\u043c\u044f","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f. \u0412\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u044c\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u041a\u043e\u043b\u0435\u0441\u043d\u0438\u0446\u0430","\u0414\u0432\u0438\u0436\u0435\u043d\u0438\u0435 \u0432\u043f\u0435\u0440\u0451\u0434, \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c, \u043f\u043e\u0431\u0435\u0434\u0430. \u041f\u0440\u0435\u043e\u0434\u043e\u043b\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u043f\u044f\u0442\u0441\u0442\u0432\u0438\u0439 \u0441\u0438\u043b\u043e\u0439 \u0432\u043e\u043b\u0438.","\u041e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u0441\u0432\u043e\u0435\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u041f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u0438 \u043e\u043f\u043e\u0437\u0434\u0430\u043d\u0438\u0438. \u0420\u0435\u0437\u043a\u043e\u0441\u0442\u044c, \u0446\u0435\u043b\u0435\u0443\u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f (\u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0443\u0435\u0442\u0441\u044f \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u043c\u0438 \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u044f\u043c\u0438)","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u0438\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0438",'\u041e\u0441\u0442\u0440\u043e \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u0432\u043e\u0435\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0441\u0432\u043e\u0438\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u041e\u0442\u0441\u044e\u0434\u0430 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0430\u0435\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u044f \u043f\u043e \u0436\u0438\u0437\u043d\u0438 -- \u0432\u0441\u0435\u043c\u0443 \u0441\u0432\u043e\u0435 \u0432\u0440\u0435\u043c\u044f. \u0427\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u0435\u0431\u044f "\u043f\u043e\u0442\u0435\u0440\u044f\u043d\u043d\u044b\u043c", \u043a\u043e\u0433\u0434\u0430 \u0432\u044b\u043f\u0430\u0434\u0430\u0435\u0442 \u0438\u0437 \u044d\u0442\u043e\u0433\u043e \u043f\u043e\u0442\u043e\u043a\u0430.',"\u0423\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c, \u0441\u0442\u0440\u043e\u0433\u0430\u044f \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438.","\u041a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0435 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435 \u0438\u0437 \u0410 \u0432 \u0411. \u0422\u043e\u0447\u043d\u043e\u0435 \u043e\u043f\u0435\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0444\u0430\u043a\u0442\u0430\u043c\u0438, \u0441\u0443\u0445\u0430\u044f \u0440\u0435\u0447\u044c.","\u0412\u0441\u0435 \u0442\u043e\u0447\u043d\u044b\u0435 \u043d\u0430\u0443\u043a\u0438.","\u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u043d\u0435\u0443\u043c\u0435\u0441\u0442\u043d\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0441\u0442\u0440\u043e \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0442\u044c \u0440\u0435\u0448\u0435\u043d\u0438\u044f. \u0421\u0442\u0440\u0430\u0445 \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0438 (\u043a\u0430\u043a \u043d\u0435\u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438 \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0430\u0442\u044c\u0441\u044f \u0441\u0432\u043e\u0438\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c).","\u0420\u0435\u0437\u043a\u043e\u0435 \u0443\u0441\u043a\u043e\u0440\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u0437\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435 \u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0435 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u043c \xab\u0432\u0440\u0435\u043c\u044f\xbb.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0441\u0442\u044c",'\u041e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u0441\u0432\u043e\u0435\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0441\u0432\u043e\u0438\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 (\u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0430\u0435\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u044f \u043f\u043e \u0436\u0438\u0437\u043d\u0438 -- \u043d\u0430 \u0432\u0441\u0435 \u0441\u0442\u0440\u043e\u0433\u043e \u043e\u0442\u0432\u0435\u0434\u0435\u043d\u043e \u0432\u0440\u0435\u043c\u044f, \u0436\u0435\u0441\u0442\u043a\u0430\u044f \u043f\u043e\u0437\u0438\u0446\u0438\u044f \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0433\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 - \u0435\u0441\u043b\u0438 \u0447\u0442\u043e-\u0442\u043e \u043d\u0435 \u0441\u0434\u0435\u043b\u0430\u043d\u043e \u0441\u0440\u0430\u0437\u0443, \u0442\u043e \u0432\u0442\u043e\u0440\u043e\u0433\u043e \u0448\u0430\u043d\u0441\u0430 \u0443\u0436\u0435 \u043d\u0435 \u0431\u0443\u0434\u0435\u0442). \u0414\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f, \u043e\u0431\u0443\u0441\u043b\u043e\u0432\u043b\u0435\u043d\u043d\u044b\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u043c\u0438 \u0440\u0430\u043c\u043a\u0430\u043c\u0438. \u0412\u043e\u0437\u043c\u043e\u0436\u043d\u0430 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0438 \u0430\u043f\u0430\u0442\u0438\u044f \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u0430\u044f \u0441 \u043e\u043f\u043e\u0437\u0434\u0430\u043d\u0438\u0435\u043c \u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 (\u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u0435\u0431\u044f "\u043f\u043e\u0442\u0435\u0440\u044f\u043d\u043d\u044b\u043c", \u043a\u043e\u0433\u0434\u0430 \u0432\u044b\u043f\u0430\u0434\u0430\u0435\u0442 \u0438\u0437 \u044d\u0442\u043e\u0433\u043e \u043f\u043e\u0442\u043e\u043a\u0430). \u0427\u0435\u043c \u0431\u043e\u043b\u0435\u0435 \u0438\u0441\u043a\u0440\u0438\u0432\u043b\u0435\u043d\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u043e, \u0447\u0435\u043c \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0435\u0434\u043e\u0434\u0435\u043b\u043e\u043a -- \u0432\u0441\u0435 \u043f\u0440\u043e\u0435\u0434\u0430\u0435\u0442 \u0438 \u0435\u0433\u043e \u0432\u0440\u0435\u043c\u044f \u0441\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f. \u0418\u0437\u043e\u043b\u044f\u0446\u0438\u044f, \u043a\u043e\u043c\u0444\u043e\u0440\u0442, \u0432\u044b\u0440\u0430\u0436\u0435\u043d\u043d\u0430\u044f \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u043d\u0430 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0445 \u043f\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043d\u0438\u044f\u0445 \u0438 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u0430\u0445, \u0440\u0435\u0437\u043a\u043e\u0441\u0442\u044c, \u0446\u0435\u043b\u0435\u0443\u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c. \u0421\u043b\u043e\u0436\u043d\u044b\u0435 \u043b\u044e\u0434\u0438, \xab\u0437\u0430\u0447\u0435\u043c \u043d\u0430\u043b\u0430\u0436\u0438\u0432\u0430\u0442\u044c \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044f \u0435\u0441\u043b\u0438 \u043e\u043d\u0438 \u0443\u0436\u0435 \u0438\u0441\u043f\u043e\u0440\u0447\u0435\u043d\u044b...\xbb, \u043f\u0440\u043e\u0449\u0430\u044e\u0442\u0441\u044f \u043d\u0435 \u0437\u0434\u043e\u0440\u043e\u0432\u0430\u044f\u0441\u044c (\xab\u0438 \u044d\u0442\u043e \u0442\u043e\u0436\u0435 \u0437\u0430\u043a\u043e\u043d\u0447\u0438\u0442\u0441\u044f...\xbb), \u0437\u043b\u044b\u0435, \u043e\u0434\u0438\u043d\u043e\u043a\u0438\u0435, \u0445\u043e\u043b\u043e\u0434\u043d\u044b\u0435, \u043f\u0440\u0438\u0447\u0438\u043d\u0430 -- \u0441\u0442\u0440\u0430\u0445. \u041a\u043e\u0433\u0434\u0430 \u043c\u043d\u043e\u0433\u043e \u0441\u0435\u043c\u0435\u0440\u043e\u043a -- \u043c\u0430\u043b\u043e\u0434\u0435\u0442\u043d\u044b\u0439.',"\u0425\u0440\u043e\u043d\u043e\u0441","\u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438, \u043f\u0443\u043d\u043a\u0442\u0443\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c.","\u0423\u043c\u0435\u0435\u0442 \u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u044f\u0442\u044c \u0432\u0440\u0435\u043c\u044f, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u0432\u043e\u0435\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e, \u0441\u043e\u0431\u0440\u0430\u043d.","\u0420\u0438\u0433\u0438\u0434\u043d\u043e\u0441\u0442\u044c, \u043f\u0430\u043d\u0438\u043a\u0430 \u043f\u0440\u0438 \u0441\u0440\u044b\u0432\u0435 \u043f\u043b\u0430\u043d\u043e\u0432, \u0441\u0442\u0440\u0430\u0445 \u043e\u043f\u043e\u0437\u0434\u0430\u0442\u044c.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0425\u0440\u043e\u043d\u043e\u0441 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442, \u043a\u043e\u0433\u0434\u0430 \u0432\u0430\u0436\u043d\u043e \u0443\u043b\u043e\u0436\u0438\u0442\u044c\u0441\u044f \u0432 \u0441\u0440\u043e\u043a\u0438.","\xab\u0427\u0442\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442, \u043a\u043e\u0433\u0434\u0430 \u044f \u0432\u044b\u043f\u0430\u0434\u0430\u044e \u0438\u0437 \u0433\u0440\u0430\u0444\u0438\u043a\u0430?\xbb","\u0421\u043f\u043e\u043a\u043e\u0439\u043d\u0430\u044f \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c (\u043a\u043e\u0433\u0434\u0430 \u0432\u0441\u0435 \u043f\u043e \u0433\u0440\u0430\u0444\u0438\u043a\u0443), \u043f\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0442\u0440\u0435\u0432\u043e\u0433\u0430 (\u043f\u0440\u0438 \u043e\u043f\u043e\u0437\u0434\u0430\u043d\u0438\u0438), \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u043d\u0430 \u043c\u0435\u0434\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445, \u0444\u0430\u0442\u0430\u043b\u0438\u0437\u043c.","\u041f\u0430\u043d\u0438\u043a\u0430 \u0438 \u0441\u0430\u043c\u043e\u0431\u0438\u0447\u0435\u0432\u0430\u043d\u0438\u0435, \u0435\u0441\u043b\u0438 \u043e\u043f\u043e\u0437\u0434\u0430\u043b \u043d\u0430 \u0432\u0430\u0436\u043d\u0443\u044e \u0432\u0441\u0442\u0440\u0435\u0447\u0443 \u043d\u0430 2 \u043c\u0438\u043d\u0443\u0442\u044b. \u0425\u043e\u043b\u043e\u0434\u043d\u043e\u0435, \u043c\u043e\u043b\u0447\u0430\u043b\u0438\u0432\u043e\u0435 \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u043d\u0430 \u043b\u044e\u0434\u0435\u0439, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 '\u0442\u0440\u0430\u0442\u044f\u0442 \u0435\u0433\u043e \u0432\u0440\u0435\u043c\u044f'. \u0413\u043b\u0443\u0431\u043e\u043a\u043e\u0435, \u043f\u043e\u0447\u0442\u0438 \u043c\u0435\u0434\u0438\u0442\u0430\u0442\u0438\u0432\u043d\u043e\u0435 \u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435, \u043a\u043e\u0433\u0434\u0430 \u0432\u0441\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0432\u044b\u043f\u043e\u043b\u043d\u0435\u043d\u044b \u0432\u043e\u0432\u0440\u0435\u043c\u044f. \u0424\u0430\u0442\u0430\u043b\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435 ('\u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435\u043b\u044c\u0437\u044f \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c'), \u043a\u043e\u0433\u0434\u0430 \u0441\u0440\u043e\u043a\u0438 \u0431\u0435\u0437\u0432\u043e\u0437\u0432\u0440\u0430\u0442\u043d\u043e \u0443\u043f\u0443\u0449\u0435\u043d\u044b."],t.l)
B.V0=new A.aL(B.aI,["\u0417\u0430\u0449\u0438\u0442\u0430","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u041f\u0440\u0430\u0432\u043e\u0441\u0443\u0434\u0438\u0435","\u0411\u0430\u043b\u0430\u043d\u0441, \u043a\u0430\u0440\u043c\u0430, \u0437\u0430\u043a\u043e\u043d. \u041e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u0432\u044b\u0431\u043e\u0440.","\u041e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u0437\u0430 \u0431\u044b\u0442\u043e\u0432\u043e\u0439 \u0437\u0430\u043a\u043e\u043d. \u0425\u0440\u0430\u0431\u0440\u043e\u0441\u0442\u044c, \u043d\u0430\u0434\u0435\u0436\u043d\u043e\u0441\u0442\u044c. \u0423\u043f\u0440\u044f\u043c\u0441\u0442\u0432\u043e \u043d\u0430 \u043d\u0438\u0437\u043a\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u0435.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f, \u0417\u0430\u043c\u043a\u043d\u0443\u0442\u0430\u044f","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0437\u0430 \u0438\u0441\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u0435\u043c \u0437\u0430\u043a\u043e\u043d\u0430","\u0411\u043e\u043b\u0435\u0435 \u0437\u0430\u043c\u043a\u043d\u0443\u0442 \u0432 \u0441\u0435\u0431\u0435, \u043e\u0441\u043c\u044b\u0441\u043b\u0438\u0432\u0430\u044f \u0441\u0432\u043e\u0438 \u0441\u0442\u0440\u0430\u0445\u0438. \u0412 \u0432\u0438\u0434\u0443 \u0437\u0430\u043c\u043a\u043d\u0443\u0442\u043e\u0441\u0442\u0438 \u043d\u0435 \u0441\u043b\u044b\u0448\u0438\u0442 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0438\u0445. \u041f\u0440\u043e\u0449\u0435 \u043a\u043e\u0433\u0434\u0430 \u044d\u0442\u043e \u0432\u0442\u043e\u0440\u043e\u0439 \u0438\u043b\u0438 \u0442\u0440\u0435\u0442\u0438\u0439 \u043f\u0435\u0440\u0438\u043e\u0434 -- \u043a\u043e\u0433\u0434\u0430 \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442 \u0432 \u044d\u0442\u043e \u0441 \u0443\u0436\u0435 \u0441\u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u043c\u0438 \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u0438\u044f\u043c\u0438 \u043e \u0436\u0438\u0437\u043d\u0438.","\u0425\u0440\u0430\u0431\u0440\u043e\u0441\u0442\u044c, \u0441\u0438\u043b\u044c\u043d\u043e\u0435 \u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0430\u0442\u044c\u0441\u044f.","\u0421\u0440\u0430\u0432\u043d\u0438\u0442\u044c, \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u044c, \u043f\u043e\u0431\u0435\u0434\u0438\u0442\u044c. \u0412\u043e\u0439\u043d\u0430. \u041d\u0430 \u0432\u044b\u0441\u0448\u0435\u043c \u0443\u0440\u043e\u0432\u043d\u0435 -- \u0441\u043b\u0443\u0436\u0435\u043d\u0438\u0435.","\u0417\u0430\u043a\u043e\u043d, \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0430. \u0413\u043e\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u043e, \u0430\u0440\u043c\u0438\u044f.","\u0421\u0442\u0440\u0430\u0445 \u043e\u043a\u0430\u0437\u0430\u0442\u044c\u0441\u044f \u043d\u0435\u0437\u043d\u0430\u0447\u0438\u043c\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u0438.","\u0421\u043c\u0435\u043b\u043e\u0441\u0442\u044c, \u0445\u0440\u0430\u0431\u0440\u043e\u0441\u0442\u044c, \u0440\u0435\u0448\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0438 \u0430\u043f\u0435\u043b\u043b\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u043a \u0437\u0430\u043a\u043e\u043d\u0443.","\u0412\u0430\u0436\u043d\u043e \u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u044e \u0437\u0430\u043a\u043e\u043d\u043e\u0432 \u043d\u0430 \u0432\u0441\u0435\u0445 \u0443\u0440\u043e\u0432\u043d\u044f\u0445 \u0436\u0438\u0437\u043d\u0438.","\u0425\u0440\u0430\u0431\u0440\u043e\u0441\u0442\u044c",'\u0421\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c \u0438 \u0445\u0440\u0430\u0431\u0440\u043e\u0441\u0442\u044c, \u0447\u0435\u0441\u0442\u043d\u043e\u0441\u0442\u044c, \u043d\u0430\u0434\u0435\u0436\u043d\u043e\u0441\u0442\u044c, \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0441\u0442\u044c, "\u0431\u043e\u0440\u0435\u0446, \u0432\u043e\u0438\u043d" (\u043d\u0430 \u043d\u0438\u0437\u043a\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u044f: \u0443\u043f\u0440\u044f\u043c\u0441\u0442\u0432\u043e, \u0442\u0443\u043f\u043e\u0443\u043c\u0438\u0435, \u0447\u0432\u0430\u043d\u043b\u0438\u0432\u043e\u0441\u0442\u044c). \u041e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0437\u0430 "\u0431\u044b\u0442\u043e\u0432\u043e\u0439" \u0437\u0430\u043a\u043e\u043d, \u0443\u043a\u043b\u0430\u0434 \u0438 \u043f\u043e\u0440\u044f\u0434\u043e\u043a \u0432 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u043c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435, "\u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0439 \u0447\u0438\u043d\u043e\u0432\u043d\u0438\u043a". \u0421\u0430\u043c\u043e\u0435 \u0441\u0438\u043b\u044c\u043d\u043e\u0435 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435 - \xab\u0441\u0435\u043c\u044c\u044f\xbb, \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u0441\u0435\u043c\u044c\u044e. \u041e\u0434\u0438\u043d\u043e\u043a\u0438\u0439 \u043d\u0435\u043c\u043d\u043e\u0433\u043e, \u043d\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u0432 \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0438 - \u0441\u043b\u044b\u0448\u0438\u0442 \u0441\u0435\u0431\u044f \u0432 \u0442\u0438\u0448\u0438\u043d\u0435, \xab\u0437\u0432\u0443\u043a\u043e\u0432\u0438\u0447\u043e\u043a\xbb. \u0423\u043c\u0435\u0435\u0442 \u043d\u0430\u043b\u0430\u0436\u0438\u0432\u0430\u0442\u044c \u0441\u0432\u044f\u0437\u0438, \u043d\u043e \u043d\u0435 \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442 - \u0440\u0435\u0448\u0430\u0435\u0442 \u0432\u043e\u043f\u0440\u043e\u0441\u044b \u0441\u0438\u043b\u043e\u0439.',"\u0417\u0430\u0449\u0438\u0442\u043d\u0438\u043a","\u0421\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c, \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u0441\u0432\u043e\u0438\u0445.","\u0413\u043e\u0442\u043e\u0432 \u0432\u0441\u0442\u0443\u043f\u0438\u0442\u044c\u0441\u044f \u0437\u0430 \u0441\u043b\u0430\u0431\u043e\u0433\u043e, \u043e\u0442\u0441\u0442\u043e\u044f\u0442\u044c \u0433\u0440\u0430\u043d\u0438\u0446\u044b.","\u0423\u043f\u0440\u044f\u043c\u0441\u0442\u0432\u043e, \u0433\u0440\u0443\u0431\u043e\u0441\u0442\u044c, \u043d\u0435\u0443\u043c\u0435\u043d\u0438\u0435 \u0438\u0434\u0442\u0438 \u043d\u0430 \u043a\u043e\u043c\u043f\u0440\u043e\u043c\u0438\u0441\u0441\u044b.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0417\u0430\u0449\u0438\u0442\u043d\u0438\u043a \u0430\u043a\u0442\u0438\u0432\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043f\u0440\u0438 \u0443\u0433\u0440\u043e\u0437\u0435 \u0432\u0430\u0448\u0438\u043c \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u044f\u043c.","\xab\u0427\u0442\u043e \u044f \u0437\u0430\u0449\u0438\u0449\u0430\u044e --- \u0441\u0432\u043e\u0438 \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0438\u043b\u0438 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443 \u0431\u044b\u0442\u044c \u043f\u0440\u0430\u0432\u044b\u043c?\xbb","\u0413\u043d\u0435\u0432 (\u043d\u0430 \u0443\u0433\u0440\u043e\u0437\u0443), \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u0438, \u0443\u043f\u0440\u044f\u043c\u0441\u0442\u0432\u043e, \u0432\u0438\u043d\u0430 (\u0435\u0441\u043b\u0438 \u043d\u0435 \u0437\u0430\u0449\u0438\u0442\u0438\u043b), \u043d\u0430\u0434\u0435\u0436\u043d\u043e\u0441\u0442\u044c.","\u041c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u0430\u044f, \u044f\u0440\u043e\u0441\u0442\u043d\u0430\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u0433\u043d\u0435\u0432\u0430 \u043d\u0430 \u043d\u0435\u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c \u043f\u043e \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044e \u043a \u043d\u0435\u043c\u0443 \u0438\u043b\u0438 \u0435\u0433\u043e \u0431\u043b\u0438\u0437\u043a\u0438\u043c. \u0423\u043f\u0440\u044f\u043c\u043e\u0435, '\u0433\u043b\u0443\u0445\u043e\u0435' \u043e\u0442\u0441\u0442\u0430\u0438\u0432\u0430\u043d\u0438\u0435 \u0441\u0432\u043e\u0435\u0439 \u043f\u0440\u0430\u0432\u0434\u044b, \u0434\u0430\u0436\u0435 \u0435\u0441\u043b\u0438 \u0444\u0430\u043a\u0442\u044b \u043f\u0440\u043e\u0442\u0438\u0432. \u0413\u043b\u0443\u0431\u043e\u043a\u043e\u0435, \u0442\u044f\u0436\u0435\u043b\u043e\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0438\u043d\u044b \u0438 \u0441\u0442\u044b\u0434\u0430, \u0435\u0441\u043b\u0438 \u043d\u0435 \u0441\u043c\u043e\u0433 \u0432\u044b\u043f\u043e\u043b\u043d\u0438\u0442\u044c \u0441\u0432\u043e\u0439 \u0434\u043e\u043b\u0433 \u0437\u0430\u0449\u0438\u0442\u044b. \u0422\u0438\u0445\u043e\u0435, \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u043e\u0435 \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u0438, \u043a\u043e\u0433\u0434\u0430 \u0435\u0433\u043e \u0441\u0435\u043c\u044c\u044f/\u0446\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0432 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u0438."],t.l)
B.V5=new A.aL(B.aI,["\u0417\u043d\u0430\u043d\u0438\u0435","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f. \u0412\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u044c\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u041d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0443\u0441\u0438\u043b\u0438\u0442\u0435\u043b\u044c","\u041e\u0442\u0448\u0435\u043b\u044c\u043d\u0438\u043a","\u0421\u0430\u043c\u043e\u0430\u043d\u0430\u043b\u0438\u0437, \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u044c, \u043f\u043e\u0438\u0441\u043a \u0438\u0441\u0442\u0438\u043d\u044b. \u0421\u0432\u0435\u0442 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0435\u0433\u043e \u0437\u043d\u0430\u043d\u0438\u044f.","\u041a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0437\u043d\u0430\u043d\u0438\u0439. \u041a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0447\u043d\u043e\u0441\u0442\u044c, \u043a\u0440\u0438\u0442\u0438\u043a\u0430, \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438, \u0437\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0431\u0449\u0435\u043d\u0438\u044e","\u043d\u0438\u0437\u043a\u0438\u0439","\u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u0439","\u0421\u0444\u043e\u043a\u0443\u0441\u0438\u0440\u043e\u0432\u0430\u043d \u043d\u0430 \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0438 \u043d\u043e\u0432\u044b\u0445 \u0437\u043d\u0430\u043d\u0438\u0439. \u0417\u043d\u0430\u043d\u0438\u044f \u0441\u0430\u043c\u0438 \u043f\u043e \u0441\u0435\u0431\u0435 \u0441\u0442\u0430\u043d\u043e\u0432\u044f\u0442\u0441\u044f \u043a\u0440\u0430\u0435\u0443\u0433\u043e\u043b\u044c\u043d\u044b\u043c \u043a\u0430\u043c\u043d\u0435\u043c, \u043f\u0440\u0430\u0432\u0434\u0430 \u0435\u0441\u0442\u044c \u043f\u0440\u0430\u0432\u0434\u0430 -- \u044d\u0442\u043e \u043d\u0435\u0437\u044b\u0431\u043b\u0435\u043c\u043e. \u0417\u043d\u0430\u043d\u0438\u044f \u043d\u0435 \u043c\u043e\u0433\u0443\u0442 \u0438\u0441\u043a\u0430\u0436\u0430\u0442\u044c\u0441\u044f.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0438\u0441\u0442\u0438\u043d\u044b. \u0418\u0441\u0442\u0438\u043d\u043d\u043e\u0441\u0442\u044c \u0438 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u0437\u043d\u0430\u043d\u0438\u0439.","\u041c\u0435\u0442\u043e\u0434\u043e\u043b\u043e\u0433\u0438\u044f. \u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0430, \u0432\u043d\u0435\u0434\u0440\u0435\u043d\u0438\u0435 \u0438 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u0439.","\u0410\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0430, \u0443\u0447\u0435\u0442, \u043f\u0440\u043e\u0433\u043d\u043e\u0437.","\u0421\u0442\u0440\u0430\u0445 \u043e\u0441\u0442\u0430\u0442\u044c\u0441\u044f \u043d\u0435 \u0443 \u0434\u0435\u043b. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0441\u043c\u0435\u0448\u043d\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u0433\u043e\u043b\u043e\u0434\u0430.","\u041f\u0440\u0438\u0431\u0435\u0433\u0430\u0435\u0442 \u043a \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u044b\u043c \u0437\u043d\u0430\u043d\u0438\u044f\u043c, \u043d\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043f\u043e\u043d\u0438\u043c\u0430\u044f \u0438\u0445 \u043f\u0440\u0438\u0440\u043e\u0434\u0443.","\u0412\u0437\u0440\u0430\u0449\u0438\u0432\u0430\u0442\u044c \u0438\u043d\u0442\u0435\u0440\u0435\u0441 \u043a \u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044e \u0437\u043d\u0430\u043d\u0438\u0439, \u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u0430\u043f\u0435\u043b\u043b\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0438\u043c\u0438.","\u041e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u043e","\u041d\u0430\u0431\u043e\u0440 \u0437\u043d\u0430\u043d\u0438\u0439: \u0437\u043d\u0430\u0442\u044c, \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c, \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u044c. \u0421\u0442\u0440\u0430\u0441\u0442\u044c \u043a \u043f\u043e\u0437\u043d\u0430\u043d\u0438\u044e, \u0441\u043f\u043e\u0441\u043e\u0431\u0435\u043d \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0442\u044c, \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0442\u044c \u0438 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u044c \u0437\u043d\u0430\u043d\u0438\u044f. \u041a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0437\u043d\u0430\u043d\u0438\u0439: \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0437\u0430 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e, \u0438\u0441\u0442\u0438\u043d\u043d\u043e\u0441\u0442\u044c \u0437\u043d\u0430\u043d\u0438\u044f, \u0438\u0441\u043a\u0430\u0436\u0435\u043d\u0438\u0435 \u0438\u0441\u0442\u0438\u043d\u043d\u043e\u0441\u0442\u0438 \u0437\u043d\u0430\u043d\u0438\u044f -- \u043d\u0435\u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e, \u0432 \u043f\u0440\u0430\u0432\u0434\u0435 -- \u0440\u0438\u0433\u0438\u0434\u043d\u044b\u0439 (\u0442\u0432\u0435\u0440\u0434\u044b\u0439, \u043d\u0435\u043f\u043e\u0434\u0434\u0430\u0442\u043b\u0438\u0432\u044b\u0439). \u041a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0447\u043d\u043e\u0441\u0442\u044c, \u043a\u0440\u0438\u0442\u0438\u043a\u0430, \u0441\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u0418\u043d\u0442\u0443\u0438\u0442. \u041e\u0431\u044b\u0447\u043d\u043e \u0433\u043e\u0432\u043e\u0440\u044f\u0442 \u0431\u044b\u0441\u0442\u0440\u043e, \u0437\u0430\u0436\u0438\u0433\u0430\u0442\u0435\u043b\u044c\u043d\u043e, \u043b\u0435\u0433\u043a\u043e \u0443\u0437\u043d\u0430\u0442\u044c \u043f\u043e \u0438\u043d\u0442\u0435\u0440\u0435\u0441\u0443: \u043f\u043e\u0447\u0435\u043c\u0443\u0447\u043a\u0438. \u0421\u0438\u043b\u0430 \u0432\u044b\u0445\u043e\u0434\u0430 \u0432 \u043e\u0431\u0449\u0435\u0441\u0442\u0432\u043e, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u043d\u0438\u043a\u0430\u0442\u044c \u0438 \u0431\u044b\u0442\u044c \u0432 \u043e\u0431\u0449\u0435\u0441\u0442\u0432\u0435 (\u0435\u0441\u043b\u0438 \u043d\u0435 \u043d\u0430\u043f\u0443\u0433\u0430\u043d - \u043b\u0435\u0433\u043a\u043e \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u0432 \u0441\u043e\u0446\u0438\u0443\u043c \u0438 \u043c\u043e\u0436\u0435\u0442 \u0437\u0430\u0439\u0442\u0438 \u043d\u0430 \u043f\u043e\u0441\u0442, \u0435\u0441\u043b\u0438 \u0441\u0442\u0440\u0430\u0445 -- \u0441\u043e\u043b\u044c\u0435\u0442\u0441\u044f \u0441 \u0438\u043d\u0442\u0435\u0440\u044c\u0435\u0440\u043e\u043c \u0438 \u0441\u0442\u0430\u043d\u0435\u0442 \u043d\u0435\u0437\u0430\u043c\u0435\u0442\u0435\u043d), \u043f\u043e\u043b\u0435\u0437\u043d\u043e \u0432\u044b\u0445\u043e\u0434\u0438\u0442\u044c \u0432 \u043e\u0431\u0449\u0435\u0441\u0442\u0432\u043e, \u0447\u0442\u043e\u0431\u044b \u043d\u0435 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0442\u044c\u0441\u044f \u0432 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 (\u0435\u0441\u043b\u0438 \u0437\u0430\u043c\u044b\u043a\u0430\u0435\u0442\u0441\u044f \u0432 \u0441\u0435\u0431\u0435 -- \u0441\u0436\u0438\u0433\u0430\u0435\u0442 \u0441\u0435\u0431\u044f). \u0415\u0441\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0434\u0438\u043d \u0448\u0430\u043d\u0441, \u043a\u0430\u043a \u043f\u043e\u0434\u0430\u0440\u043e\u043a, \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0435 \u0431\u0443\u0434\u0435\u0442 \u0434\u043e\u0431\u0438\u0440\u0430\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u0441\u0432\u043e\u0438\u043c \u0443\u043c\u043e\u043c, \u043e\u043f\u044b\u0442\u043e\u043c \u0438 \u0432\u044b\u0432\u043e\u0434\u0430\u043c\u0438.","\u042d\u0440\u0443\u0434\u0438\u0442","\u0413\u043b\u0443\u0431\u043e\u043a\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u044f, \u043f\u043e\u0438\u0441\u043a \u0438\u0441\u0442\u0438\u043d\u044b.","\u0412\u0438\u0434\u0438\u0442 \u0441\u0443\u0442\u044c, \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442 \u043f\u0440\u0430\u0432\u0434\u0443 \u043e\u0442 \u0432\u044b\u043c\u044b\u0441\u043b\u0430, \u0443\u043c\u0435\u0435\u0442 \u0443\u0447\u0438\u0442\u044c.","\u041a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0447\u043d\u043e\u0441\u0442\u044c, \u043a\u0440\u0438\u0442\u0438\u043a\u0430 \u0432\u0441\u0435\u0433\u043e \u043d\u043e\u0432\u043e\u0433\u043e, \u043d\u0435\u0434\u043e\u0432\u0435\u0440\u0438\u0435.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u042d\u0440\u0443\u0434\u0438\u0442 \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0434\u043b\u044f \u0430\u043d\u0430\u043b\u0438\u0437\u0430 \u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0438 \u0444\u0430\u043a\u0442\u043e\u0432.","\xab\u041c\u0435\u0448\u0430\u0435\u0442 \u043b\u0438 \u043c\u043d\u0435 \u043c\u043e\u044f \u043b\u044e\u0431\u043e\u0432\u044c \u043a \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438 \u0432\u0438\u0434\u0435\u0442\u044c \u0446\u0435\u043b\u043e\u0441\u0442\u043d\u0443\u044e \u043a\u0430\u0440\u0442\u0438\u043d\u0443?\xbb","\u041b\u044e\u0431\u043e\u043f\u044b\u0442\u0441\u0442\u0432\u043e, \u043a\u0440\u0438\u0442\u0438\u0446\u0438\u0437\u043c, \u043f\u0440\u0435\u0437\u0440\u0435\u043d\u0438\u0435 \u043a \u043d\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0443, \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043e\u0442 \u043d\u0430\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u0438\u0441\u0442\u0438\u043d\u044b, \u0441\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u043d\u0435\u043f\u0440\u0430\u0432\u044b\u043c.","\u0414\u0435\u0442\u0441\u043a\u0438\u0439 \u0432\u043e\u0441\u0442\u043e\u0440\u0433 \u0438 \u0430\u0437\u0430\u0440\u0442 \u043f\u0440\u0438 \u043e\u0431\u043d\u0430\u0440\u0443\u0436\u0435\u043d\u0438\u0438 \u043d\u043e\u0432\u043e\u0433\u043e \u0444\u0430\u043a\u0442\u0430 \u0438\u043b\u0438 \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0441\u0442\u0438. \u0420\u0435\u0437\u043a\u043e\u0435, \u0441\u0430\u0440\u043a\u0430\u0441\u0442\u0438\u0447\u043d\u043e\u0435 \u043d\u0435\u043f\u0440\u0438\u044f\u0442\u0438\u0435 \u0438 \u043a\u0440\u0438\u0442\u0438\u043a\u0430 \u0447\u0443\u0436\u0438\u0445 '\u0433\u043b\u0443\u043f\u044b\u0445' \u0438\u0434\u0435\u0439. \u041d\u0435\u0434\u043e\u0432\u0435\u0440\u0438\u0435 \u0438 \u043f\u043e\u0434\u043e\u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043a \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u043d\u0435\u043b\u044c\u0437\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c. \u0421\u0442\u0440\u0430\u0445 \u043f\u0443\u0431\u043b\u0438\u0447\u043d\u043e \u043e\u0448\u0438\u0431\u0438\u0442\u044c\u0441\u044f, \u043f\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u043d\u0435\u0432\u0435\u0440\u043d\u044b\u0439 \u0444\u0430\u043a\u0442."],t.l)
B.UZ=new A.aL(B.aI,["\u041f\u0435\u0440\u0435\u043c\u0435\u043d\u044b","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f. \u0413\u043e\u0440\u0438\u0437\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f","\u0414\u0435\u0442\u0441\u043a\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u041a\u043e\u043b\u0435\u0441\u043e \u0424\u043e\u0440\u0442\u0443\u043d\u044b","\u0426\u0438\u043a\u043b\u044b \u0441\u0443\u0434\u044c\u0431\u044b, \u043d\u0435\u043e\u0436\u0438\u0434\u0430\u043d\u043d\u044b\u0435 \u043f\u043e\u0432\u043e\u0440\u043e\u0442\u044b. \u041f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0439.","\u0413\u0430\u0440\u043c\u043e\u043d\u0438\u044f, \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u043e\u0441\u0442\u044c, \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u043e\u0441\u0442\u044c. \u0418\u043d\u0434\u0438\u043a\u0430\u0442\u043e\u0440 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u043f\u0440\u0430\u0432\u043e \u043d\u0430 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b","\u0411\u043e\u043b\u0435\u0435 \u0441\u043a\u043b\u043e\u043d\u0435\u043d \u043a \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u0430\u043c, \u0438 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b \u043f\u0440\u043e\u0445\u043e\u0434\u044f\u0442 \u043b\u0435\u0433\u043a\u043e.","\u0413\u0430\u0440\u043c\u043e\u043d\u0438\u044f. \u0421\u043e\u0437\u0432\u0443\u0447\u043d\u043e\u0441\u0442\u044c.","\u041f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u044b, \u0443\u0431\u0435\u0436\u0434\u0435\u043d\u0438\u044f. \u041f\u0435\u0440\u0435\u0435\u0437\u0434\u044b. \u0423\u0432\u043b\u0435\u0447\u0435\u043d\u0438\u044f.","\u041a\u0443\u043b\u044c\u0442\u0443\u0440\u0430.","\u0421\u0442\u0440\u0430\u0445 \u043f\u0435\u0440\u0435\u043c\u0435\u043d, \u043d\u043e\u0432\u0438\u0437\u043d\u044b. \u0421\u0442\u0440\u0430\u0445 \u0442\u043e\u043b\u043f\u044b. \u0421\u0442\u0440\u0430\u0445 \u0438\u0437\u043c\u0435\u043d.","\u0421\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043c\u0435\u043d\u044f\u0442\u044c \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044e \u0438 \u0441\u043e\u0431\u044b\u0442\u0438\u044f.","\u0423\u0447\u0438\u0442\u044c\u0441\u044f \u0431\u044b\u0442\u044c \u0431\u043e\u043b\u0435\u0435 \u0433\u0438\u0431\u043a\u0438\u043c, \u043f\u043e\u0434\u0430\u0442\u043b\u0438\u0432\u044b\u043c. \u0421\u043c\u0435\u043b\u043e\u0441\u0442\u044c \u043a \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u0430\u043c.","\u0418\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435","\u0412\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u0438, \u043b\u0435\u0433\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b. \u0415\u0441\u0442\u044c \u043f\u0440\u0430\u0432\u043e \u0438\u0437\u043c\u0435\u043d\u044f\u0442\u044c, \u0441\u043f\u043e\u0441\u043e\u0431 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f \u0447\u0435\u0440\u0435\u0437 \u043f\u0440\u043e\u043d\u0438\u043a\u043d\u043e\u0432\u0435\u043d\u0438\u0435 - \u043f\u0440\u043e\u043d\u0438\u043a\u0430\u0435\u0442, \u043d\u0435\u0437\u0430\u043c\u0435\u0442\u043d\u043e \u0440\u0430\u0441\u0442\u0432\u043e\u0440\u044f\u044f \u0432\u0441\u0435 \u0437\u0430\u0441\u043e\u0432\u044b \u0438 \u0437\u0430\u043c\u043a\u0438 (\u0433\u0430\u0440\u043c\u043e\u043d\u0438\u044f, \u0441\u043e\u0437\u0432\u0443\u0447\u043d\u043e\u0441\u0442\u044c). \u0421\u043b\u0443\u0447\u0430\u0439\u043d\u043e\u0441\u0442\u044c. \u041f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439, \u0433\u0438\u0431\u043a\u0438\u0439, \u043a\u043e\u043c\u043c\u0443\u043d\u0438\u043a\u0430\u0431\u0435\u043b\u044c\u043d\u044b\u0439, \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0435 \u0438 \u043f\u043e\u0437\u043d\u0430\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u044b \u0431\u044b\u0441\u0442\u0440\u044b\u0435.","\u0418\u043c\u043f\u0440\u043e\u0432\u0438\u0437\u0430\u0442\u043e\u0440","\u041b\u0451\u0433\u043a\u043e\u0441\u0442\u044c, \u0441\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u043e\u0441\u0442\u044c, \u0443\u043c\u0435\u043d\u0438\u0435 \u043c\u0435\u043d\u044f\u0442\u044c\u0441\u044f.","\u041b\u0435\u0433\u043a\u043e \u043f\u0435\u0440\u0435\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0441\u044f, \u0432\u0438\u0434\u0438\u0442 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u0438 \u0432 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u0430\u0445.","\u041d\u0435\u043f\u043e\u0441\u0442\u043e\u044f\u043d\u0441\u0442\u0432\u043e, \u0438\u0437\u0431\u0435\u0433\u0430\u043d\u0438\u0435 \u0433\u043b\u0443\u0431\u0438\u043d\u044b \u0438 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0418\u043c\u043f\u0440\u043e\u0432\u0438\u0437\u0430\u0442\u043e\u0440 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u0430\u0434\u0430\u043f\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u043a \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f\u043c.","\xab\u041d\u0435 \u0443\u0431\u0435\u0433\u0430\u044e \u043b\u0438 \u044f \u043e\u0442 \u0432\u0430\u0436\u043d\u044b\u0445 \u0432\u0435\u0449\u0435\u0439 \u043f\u043e\u0434 \u043c\u0430\u0441\u043a\u043e\u0439 \u0441\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u043e\u0441\u0442\u0438?\xbb","\u041b\u0435\u0433\u043a\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c, \u043f\u0440\u0435\u0434\u0432\u043a\u0443\u0448\u0435\u043d\u0438\u0435 \u043d\u043e\u0432\u043e\u0433\u043e, \u0441\u043a\u0443\u043a\u0430 (\u043e\u0442 \u0440\u0443\u0442\u0438\u043d\u044b), \u0441\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u043d\u044b\u043c, \u043e\u0431\u043b\u0435\u0433\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0438 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0438 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438.","\u0418\u0441\u043a\u0440\u0435\u043d\u043d\u0438\u0439, \u0437\u0430\u0440\u0430\u0437\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0441\u043c\u0435\u0445 \u0438 \u043b\u0435\u0433\u043a\u043e\u0441\u0442\u044c \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 \u043d\u043e\u0432\u043e\u0433\u043e \u043f\u0443\u0442\u0435\u0448\u0435\u0441\u0442\u0432\u0438\u044f \u0438\u043b\u0438 \u043f\u0440\u043e\u0435\u043a\u0442\u0430. \u041d\u0435\u0440\u0432\u043d\u043e\u0435, \u0431\u0435\u0441\u043f\u043e\u043a\u043e\u0439\u043d\u043e\u0435 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u0438 \u043f\u043e\u0438\u0441\u043a \u043f\u0435\u0440\u0435\u043c\u0435\u043d, \u043a\u043e\u0433\u0434\u0430 \u0436\u0438\u0437\u043d\u044c \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u043f\u0440\u0435\u0434\u0441\u043a\u0430\u0437\u0443\u0435\u043c\u043e\u0439. \u041f\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0441\u0442\u0440\u0430\u0445 \u043f\u0435\u0440\u0435\u0434 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 '\u043f\u0440\u0438\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442' \u043d\u0430\u0434\u043e\u043b\u0433\u043e. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u0433\u043e \u043e\u0431\u043b\u0435\u0433\u0447\u0435\u043d\u0438\u044f, \u043a\u043e\u0433\u0434\u0430 '\u043b\u0435\u0434 \u0442\u0440\u043e\u043d\u0443\u043b\u0441\u044f' \u0438 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044f \u0438\u0437\u043c\u0435\u043d\u0438\u043b\u0430\u0441\u044c."],t.l)
B.V6=new A.aL(B.aI,["\u0421\u0438\u043b\u0430","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e-\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u041d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0443\u0441\u0438\u043b\u0438\u0442\u0435\u043b\u044c","\u0421\u0438\u043b\u0430","\u0412\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u044f\u044f \u043c\u043e\u0449\u044c, \u043c\u044f\u0433\u043a\u043e\u0435 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435. \u041a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0447\u0435\u0440\u0435\u0437 \u0441\u043e\u0441\u0442\u0440\u0430\u0434\u0430\u043d\u0438\u0435.","\u0412\u043e\u0441\u043f\u0440\u0438\u044f\u0442\u0438\u0435 \u0438 \u0433\u0435\u043d\u0435\u0440\u0430\u0446\u0438\u044f \u044d\u043d\u0435\u0440\u0433\u0438\u0438. \u0425\u0430\u043e\u0441. \u0424\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u0438\u043b\u044b","\u0417\u0430\u0434\u0430\u0435\u0442\u0441\u044f \u0432\u043e\u043f\u0440\u043e\u0441\u043e\u043c \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043c\u043e\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0441\u0438\u043b\u044b \u0438 \u0437\u043d\u0430\u0447\u0438\u043c\u043e\u0441\u0442\u0438.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0441\u0438\u043b\u043e\u0439.","\u041f\u0440\u043e\u0442\u0438\u0432\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435, \u043f\u0440\u043e\u0442\u0435\u0441\u0442, \u0432\u044b\u0437\u043e\u0432. \u041b\u0438\u0431\u043e \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0438 \u0443\u0433\u043d\u0435\u0442\u0435\u043d\u0438\u0435.","(\u0423\u0441\u0438\u043b\u0438\u0442\u0435\u043b\u044c \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445 \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445)","\u0421\u0442\u0440\u0430\u0445 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0440\u0430\u0441\u043f\u0440\u0430\u0432\u044b. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u043e\u0439 \u0441\u0438\u043b\u044b. \u0421\u0442\u0440\u0430\u0445 \u044f\u0440\u043e\u0441\u0442\u0438 \u0438 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u043d\u044b\u0445 \u044d\u043c\u043e\u0446\u0438\u0439, \u043a\u0430\u043a \u043e\u0442 \u0441\u0435\u0431\u044f \u0442\u0430\u043a \u0438 \u043a \u0441\u0435\u0431\u0435.","\u041c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0441\u0438\u043b\u044b \u043a\u0430\u043a \u0440\u0435\u0441\u0443\u0440\u0441.","\u0423\u0447\u0438\u0442\u044c\u0441\u044f \u0432\u043b\u0430\u0434\u0435\u0442\u044c \u0438 \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0430\u0442\u044c\u0441\u044f \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0441\u0438\u043b\u043e\u0439, \u0432 \u043f\u0440\u043e\u0442\u0438\u0432\u043d\u043e\u043c \u0441\u043b\u0443\u0447\u0430\u0435 \u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u043f\u0440\u0438\u0440\u043e\u0434\u044b \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0431\u0435\u0441\u0441\u0438\u043b\u0438\u044f.","\u041f\u0440\u043e\u0440\u044b\u0432","\u0412\u043e\u0441\u043f\u0440\u0438\u044f\u0442\u0438\u0435 \u0438 \u0433\u0435\u043d\u0435\u0440\u0430\u0446\u0438\u044f \u044d\u043d\u0435\u0440\u0433\u0438\u0438. \u0421\u0438\u043b\u0430 \u043a\u0430\u043a \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435. \u0412\u043e\u043f\u0440\u043e\u0441\u044b \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043c\u043e\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0441\u0438\u043b\u044b \u0438 \u0437\u043d\u0430\u0447\u0438\u043c\u043e\u0441\u0442\u0438. \u0425\u0430\u043e\u0441.","\u0411\u0443\u0440\u044f","\u0421\u0438\u043b\u0430, \u043f\u0440\u043e\u0442\u0435\u0441\u0442, \u0432\u044b\u0437\u043e\u0432.","\u0421\u043f\u043e\u0441\u043e\u0431\u0435\u043d \u043d\u0430 \u043f\u0440\u043e\u0440\u044b\u0432, \u043e\u0442\u0441\u0442\u0430\u0438\u0432\u0430\u0435\u0442 \u043b\u0438\u0447\u043d\u044b\u0435 \u0433\u0440\u0430\u043d\u0438\u0446\u044b \u0441 \u044d\u043d\u0435\u0440\u0433\u0438\u0435\u0439.","\u041d\u0435\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u0430\u044f \u0430\u0433\u0440\u0435\u0441\u0441\u0438\u044f, \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0433\u043d\u0435\u0432, \u043e\u0442\u0440\u0438\u0446\u0430\u043d\u0438\u0435 \u043b\u044e\u0431\u043e\u0439 \u0432\u043b\u0430\u0441\u0442\u0438.","\u0412\u0430\u0448\u0430 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u044f\u044f \u0411\u0443\u0440\u044f \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0441\u043a\u0430\u0437\u0430\u0442\u044c \xab\u043d\u0435\u0442\xbb \u0438\u043b\u0438 \u0441\u043b\u043e\u043c\u0430\u0442\u044c \u0441\u0442\u0430\u0440\u044b\u0435 \u0440\u0430\u043c\u043a\u0438.","\xab\u0412\u043e \u0447\u0442\u043e \u044f \u0432\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u044e \u0441\u0432\u043e\u044e \u0441\u0438\u043b\u0443 --- \u0432 \u0441\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0438\u043b\u0438 \u0432 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u0435?\xbb","\u0413\u043d\u0435\u0432, \u044f\u0440\u043e\u0441\u0442\u044c, \u043f\u0440\u043e\u0442\u0435\u0441\u0442, \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u043c\u043e\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c (\u043e\u0442 \u0431\u0435\u0441\u0441\u0438\u043b\u0438\u044f), \u044d\u043a\u0437\u0438\u0441\u0442\u0435\u043d\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0442\u0440\u0430\u0445 \u043f\u0435\u0440\u0435\u0434 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0441\u0438\u043b\u043e\u0439.","\u0421\u043b\u0435\u043f\u0430\u044f, \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u044f\u0440\u043e\u0441\u0442\u044c \u0432 \u043e\u0442\u0432\u0435\u0442 \u043d\u0430 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0438 \u043d\u0435\u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c. \u042d\u0439\u0444\u043e\u0440\u0438\u044f \u0438 \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043c\u043e\u0449\u0438 \u043f\u0440\u0438 \u043f\u0440\u0435\u043e\u0434\u043e\u043b\u0435\u043d\u0438\u0438 \u0441\u0435\u0440\u044c\u0435\u0437\u043d\u043e\u0433\u043e \u043f\u0440\u0435\u043f\u044f\u0442\u0441\u0442\u0432\u0438\u044f. \u0413\u043b\u0443\u0431\u043e\u043a\u0430\u044f \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u044f \u0438 \u0430\u043f\u0430\u0442\u0438\u044f, \u043a\u043e\u0433\u0434\u0430 \u0441\u0438\u043b\u0430 \u043d\u0435\u0434\u043e\u0441\u0442\u0443\u043f\u043d\u0430 \u0438\u043b\u0438 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0430. \u0421\u0442\u0440\u0430\u0445 '\u0441\u043e\u0440\u0432\u0430\u0442\u044c\u0441\u044f \u0441 \u0446\u0435\u043f\u0438' \u0438 \u043f\u0440\u0438\u0447\u0438\u043d\u0438\u0442\u044c \u0432\u0440\u0435\u0434 \u0432 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0438 \u0433\u043d\u0435\u0432\u0430."],t.l)
B.Vb=new A.aL(B.aI,["\u041f\u043e\u043c\u043e\u0449\u044c","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f. \u0413\u043e\u0440\u0438\u0437\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u041f\u043e\u0432\u0435\u0448\u0435\u043d\u043d\u044b\u0439","\u0416\u0435\u0440\u0442\u0432\u0430, \u043d\u043e\u0432\u044b\u0439 \u0432\u0437\u0433\u043b\u044f\u0434, \u043f\u0435\u0440\u0435\u0445\u043e\u0434. \u041c\u0443\u0434\u0440\u043e\u0441\u0442\u044c \u0447\u0435\u0440\u0435\u0437 \u0441\u0434\u0430\u0447\u0443.","\u041f\u043e\u043c\u043e\u0449\u044c \u0434\u0440\u0443\u0433\u0438\u043c. \u041c\u0438\u043b\u043e\u0441\u0435\u0440\u0434\u0438\u0435, \u0431\u043b\u0430\u0433\u043e\u0440\u043e\u0434\u0441\u0442\u0432\u043e. \u0418\u043d\u0434\u0438\u043a\u0430\u0442\u043e\u0440 \u0438\u0441\u043a\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u0438.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044f\u043c","\u043d\u0438\u0437\u043a\u0438\u0439","\u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u0438\u0435 \u043f\u043e\u043c\u043e\u0449\u0438","\u0411\u043e\u043b\u0435\u0435 \u043e\u0442\u043a\u0440\u044b\u0442 \u0438 \u0443\u0447\u0430\u0441\u0442\u043b\u0438\u0432 \u043a \u0434\u0440\u0443\u0433\u0438\u043c \u043b\u044e\u0434\u044f\u043c. \u041f\u0440\u043e\u044f\u0432\u043b\u044f\u0435\u0442 \u0441\u0435\u0431\u044f \u0447\u0435\u0440\u0435\u0437 \u043f\u043e\u043c\u043e\u0449\u044c \u0434\u0440\u0443\u0433\u0438\u043c.","\u041f\u043e\u043c\u043e\u0449\u044c \u0438 \u043f\u043e\u0433\u043b\u043e\u0449\u0435\u043d\u0438\u0435 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u043d\u043e\u0439 \u0447\u0430\u0441\u0442\u0438.","\u041f\u043e\u043c\u043e\u0449\u044c \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u0430, \u043d\u043e \u0442\u043e\u0442\u0430\u043b\u044c\u043d\u0430. \u041e\u0431\u043b\u0435\u0433\u0447\u0438\u0442\u044c \u0436\u0438\u0437\u043d\u044c \u0434\u0440\u0443\u0433\u043e\u043c\u0443, \u0432\u0437\u044f\u0442\u044c \u043d\u0430 \u0441\u0435\u0431\u044f \u0435\u0433\u043e \u043d\u043e\u0448\u0443.","\u041f\u043e\u043c\u043e\u0433\u0430\u044e\u0449\u0438\u0435 \u043f\u0440\u043e\u0444\u0435\u0441\u0441\u0438\u0438. \u041f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u044f, \u043c\u0435\u0434\u0438\u0446\u0438\u043d\u0430.","\u0421\u0442\u0440\u0430\u0445 \u0440\u0430\u0432\u043d\u043e\u0434\u0443\u0448\u0438\u044f, \u0431\u0435\u0441\u043f\u043e\u043c\u043e\u0449\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u043d\u044b\u043c \u0438\u043b\u0438 \u043d\u0435\u043d\u0443\u0436\u043d\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0432\u0438\u043d\u043e\u0432\u0430\u0442\u044b\u043c.","\u0418\u043d\u043e\u0433\u0434\u0430 \u0432\u043e\u0437\u043d\u0438\u043a\u0430\u044e\u0449\u0435\u0435 \u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u043f\u043e\u043c\u043e\u0447\u044c, \u043f\u043e\u043d\u044f\u0442\u044c \u0438 \u0440\u0430\u0437\u0433\u0440\u0443\u0437\u0438\u0442\u044c.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0435 \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u043e\u043c\u043e\u0433\u0430\u0442\u044c \u0443\u043c\u0435\u0441\u0442\u043d\u043e.","\u041d\u043e\u0432\u043e\u0435 \u0432\u0438\u0434\u0435\u043d\u0438\u0435",'\u041e\u0442\u043a\u0440\u044b\u0442\u043e\u0441\u0442\u044c, \u043e\u0442\u0437\u044b\u0432\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u0438 \u0443\u0447\u0430\u0441\u0442\u043b\u0438\u0432\u043e\u0441\u0442\u044c \u043a \u0434\u0440\u0443\u0433\u0438\u043c \u043b\u044e\u0434\u044f\u043c. \u041f\u0440\u043e\u044f\u0432\u043b\u044f\u0435\u0442 \u0441\u0435\u0431\u044f \u0447\u0435\u0440\u0435\u0437 \u043f\u043e\u043c\u043e\u0449\u044c \u0434\u0440\u0443\u0433\u0438\u043c. \u041c\u0438\u043b\u043e\u0441\u0435\u0440\u0434\u0438\u0435, \u0431\u043b\u0430\u0433\u043e\u0440\u043e\u0434\u0441\u0442\u0432\u043e, \u043f\u0440\u043e\u0449\u0435\u043d\u0438\u0435. \u0418\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u0435\u043d \u0432 \u043f\u043e\u043c\u043e\u0449\u0438. \u0427\u0435\u0440\u043d\u0430\u044f \u0434\u044b\u0440\u0430. \u0418\u043d\u0434\u0438\u043a\u0430\u0442\u043e\u0440 \u0438\u0441\u043a\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0438 "\u0447\u0438\u0441\u0442\u043e\u0442\u044b" \u043b\u0438\u0447\u043d\u043e\u0441\u0442\u0438.',"\u0426\u0435\u043b\u0438\u0442\u0435\u043b\u044c","\u042d\u043c\u043f\u0430\u0442\u0438\u044f, \u043c\u0438\u043b\u043e\u0441\u0435\u0440\u0434\u0438\u0435, \u0441\u043b\u0443\u0436\u0435\u043d\u0438\u0435.","\u0427\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0431\u043e\u043b\u044c \u0434\u0440\u0443\u0433\u0438\u0445, \u0443\u043c\u0435\u0435\u0442 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0430\u0442\u044c, \u0438\u0441\u0446\u0435\u043b\u0438\u0442\u044c \u0441\u043b\u043e\u0432\u043e\u043c \u0438\u043b\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043c.","\u0421\u043b\u0438\u044f\u043d\u0438\u0435 \u0441 \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u0430\u043c\u0438 \u0434\u0440\u0443\u0433\u0438\u0445, \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0435 \u0432\u044b\u0433\u043e\u0440\u0430\u043d\u0438\u0435, \u0436\u0430\u043b\u043e\u0441\u0442\u044c \u043a \u0441\u0435\u0431\u0435.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0426\u0435\u043b\u0438\u0442\u0435\u043b\u044c \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u0440\u044f\u0434\u043e\u043c \u043a\u0442\u043e-\u0442\u043e \u0441\u0442\u0440\u0430\u0434\u0430\u0435\u0442.","\xab\u042f \u043f\u043e\u043c\u043e\u0433\u0430\u044e \u0438\u0437 \u043b\u044e\u0431\u0432\u0438 \u0438\u043b\u0438 \u0438\u0437 \u0441\u0442\u0440\u0430\u0445\u0430 \u0431\u044b\u0442\u044c \u043d\u0435\u043d\u0443\u0436\u043d\u044b\u043c?\xbb","\u0421\u043e\u0441\u0442\u0440\u0430\u0434\u0430\u043d\u0438\u0435, \u0436\u0430\u043b\u043e\u0441\u0442\u044c, \u043c\u0438\u043b\u043e\u0441\u0435\u0440\u0434\u0438\u0435, \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0438\u043d\u044b (\u0435\u0441\u043b\u0438 \u043d\u0435 \u043f\u043e\u043c\u043e\u0433), \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0435 \u0438\u0441\u0442\u043e\u0449\u0435\u043d\u0438\u0435, \u0443\u043c\u0438\u0440\u043e\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u0435 \u043e\u0442 \u043f\u043e\u043c\u043e\u0449\u0438.","\u0429\u0435\u043c\u044f\u0449\u0435\u0435 \u0441\u0435\u0440\u0434\u0446\u0435 \u0441\u043e\u0441\u0442\u0440\u0430\u0434\u0430\u043d\u0438\u0435 \u0438 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e\u0435 \u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u043f\u043e\u043c\u043e\u0447\u044c \u043f\u0440\u0438 \u0432\u0438\u0434\u0435 \u0447\u0443\u0436\u043e\u0439 \u0431\u043e\u043b\u0438. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0438\u043d\u044b \u0438 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 '\u043f\u043b\u043e\u0445\u043e\u0441\u0442\u0438', \u0435\u0441\u043b\u0438 \u043f\u0440\u0438\u0448\u043b\u043e\u0441\u044c \u043e\u0442\u043a\u0430\u0437\u0430\u0442\u044c \u0432 \u043f\u043e\u043c\u043e\u0449\u0438. \u0422\u0438\u0445\u0430\u044f, \u0441\u0432\u0435\u0442\u043b\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c, \u043a\u043e\u0433\u0434\u0430 \u0435\u0433\u043e \u043f\u043e\u043c\u043e\u0449\u044c \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u043e\u0431\u043b\u0435\u0433\u0447\u0438\u043b\u0430 \u0441\u0442\u0440\u0430\u0434\u0430\u043d\u0438\u044f. \u041f\u043e\u043b\u043d\u043e\u0435 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0435 \u0432\u044b\u0433\u043e\u0440\u0430\u043d\u0438\u0435 \u0438 \u043e\u043f\u0443\u0441\u0442\u043e\u0448\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u043f\u043e\u0441\u043b\u0435 '\u0432\u043f\u0438\u0442\u044b\u0432\u0430\u043d\u0438\u044f' \u0447\u0443\u0436\u0438\u0445 \u043f\u0440\u043e\u0431\u043b\u0435\u043c."],t.l)
B.V2=new A.aL(B.aI,["\u0422\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0421\u043c\u0435\u0440\u0442\u044c","\u041a\u043e\u043d\u0435\u0446 \u0446\u0438\u043a\u043b\u0430, \u043f\u0435\u0440\u0435\u0440\u043e\u0436\u0434\u0435\u043d\u0438\u0435, \u043e\u0442\u043f\u0443\u0441\u043a\u0430\u043d\u0438\u0435. \u0422\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u0435.","\u0422\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f \u0447\u0435\u0440\u0435\u0437 \u0436\u0435\u0441\u0442\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b. \u0424\u0430\u0442\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043e\u0441\u0442\u0440\u044b\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f","\u0411\u043e\u043b\u0435\u0435 \u0436\u0435\u0441\u0442\u043a\u0438\u0439 \u0438 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0447\u043d\u044b\u0439 \u0432 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0438 \u0440\u0435\u0448\u0435\u043d\u0438\u044f. \u0412\u043e\u0437\u043c\u043e\u0436\u043d\u044b \u0440\u0430\u0437\u043b\u0438\u0447\u043d\u044b\u0435 \u043e\u0441\u0442\u0440\u044b\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0431\u0443\u0434\u0443 \u0432\u0435\u0441\u0442\u0438 \u043a \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044e \u0441\u0443\u0442\u0438 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 (\u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438).","\u0422\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f.","\u0427\u0442\u043e\u0431\u044b \u043d\u0430\u0447\u0430\u0442\u044c \u0436\u0438\u0442\u044c, \u043d\u0443\u0436\u043d\u043e \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0443\u043c\u0435\u0440\u0435\u0442\u044c.","\u041f\u043e\u043c\u043e\u0433\u0430\u044e\u0449\u0438\u0435 \u043f\u0440\u043e\u0444\u0435\u0441\u0441\u0438\u0438. \u042d\u043a\u0441\u0442\u0440\u0435\u043d\u043d\u0430\u044f \u043f\u043e\u043c\u043e\u0449\u044c. \u041f\u043e\u043b\u0438\u0442\u0438\u043a\u0430.","\u0421\u0442\u0440\u0430\u0445 \u043d\u0435 \u0443\u0441\u043f\u0435\u0442\u044c. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u0431\u0435\u0437\u0434\u0443\u0445\u043e\u0432\u043d\u043e\u0441\u0442\u0438, \u0431\u0435\u0441\u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438.","\u0420\u0435\u0437\u043a\u043e\u0435 \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u043d\u0430 \u0432\u0435\u0441\u044c \u0445\u043e\u0434 \u0441\u043e\u0431\u044b\u0442\u0438\u044f, \u0435\u0433\u043e \u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f.","\u0423\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u0437\u043d\u0430\u0432\u0430\u0442\u044c \u0441\u0432\u043e\u044e \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0438 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043a \u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438.","\u0422\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f",'\u0422\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044f (\u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0441\u0443\u0442\u0438) \u0447\u0435\u0440\u0435\u0437 \u0432\u043b\u0438\u044f\u043d\u0438\u0435, \u0436\u0435\u0441\u0442\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b. \u0420\u0435\u0437\u043a\u043e\u0441\u0442\u044c, \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0447\u043d\u043e\u0441\u0442\u044c \u0432 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0438 \u0440\u0435\u0448\u0435\u043d\u0438\u044f, \u0432\u044b\u0431\u043e\u0440 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0439 "\u043c\u0435\u0436\u0434\u0443\xbb (\u0436\u0438\u0437\u043d\u044c \u0438\u043b\u0438 \u0441\u043c\u0435\u0440\u0442\u044c). \u0424\u0430\u0442\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043e\u0441\u0442\u0440\u044b\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 (\u0432\u0435\u0434\u0443\u0449\u0438\u0435 \u043a \u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438). \u0423\u0441\u043f\u0435\u0442\u044c.',"\u0424\u0435\u043d\u0438\u043a\u0441","\u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043a \u0440\u0430\u0434\u0438\u043a\u0430\u043b\u044c\u043d\u044b\u043c \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f\u043c.","\u0423\u043c\u0435\u0435\u0442 \u043e\u0442\u043f\u0443\u0441\u043a\u0430\u0442\u044c \u043e\u0442\u0436\u0438\u0432\u0448\u0435\u0435, \u0432\u043e\u0437\u0440\u043e\u0436\u0434\u0430\u0442\u044c\u0441\u044f \u0438\u0437 \u043a\u0440\u0438\u0437\u0438\u0441\u0430 \u0441 \u043d\u043e\u0432\u044b\u043c\u0438 \u0441\u0438\u043b\u0430\u043c\u0438.","\u0421\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u0442\u044c \u043a\u0440\u0438\u0437\u0438\u0441\u044b \xab\u043d\u0430 \u043f\u0443\u0441\u0442\u043e\u043c \u043c\u0435\u0441\u0442\u0435\xbb, \u043d\u0435\u0442\u0435\u0440\u043f\u0438\u043c\u043e\u0441\u0442\u044c \u043a \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u0438.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0424\u0435\u043d\u0438\u043a\u0441 \u0432\u0435\u0434\u0451\u0442 \u0432\u0430\u0441 \u0447\u0435\u0440\u0435\u0437 \u043f\u0435\u0440\u0438\u043e\u0434\u044b \u0442\u044f\u0436\u0451\u043b\u044b\u0445, \u043d\u043e \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u044b\u0445 \u043f\u0435\u0440\u0435\u043c\u0435\u043d.","\xab\u0427\u0442\u043e \u043f\u0440\u044f\u043c\u043e \u0441\u0435\u0439\u0447\u0430\u0441 \u0434\u043e\u043b\u0436\u043d\u043e \xab\u0443\u043c\u0435\u0440\u0435\u0442\u044c\xbb \u0432\u043e \u043c\u043d\u0435, \u0447\u0442\u043e\u0431\u044b \u044f \u043c\u043e\u0433 \xab\u0440\u043e\u0434\u0438\u0442\u044c\u0441\u044f\xbb \u0437\u0430\u043d\u043e\u0432\u043e?\xbb","\u0428\u043e\u043a, \u043e\u0442\u0447\u0430\u044f\u043d\u0438\u0435 (\u043f\u0435\u0440\u0435\u0434 \u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439), \u0440\u0435\u0448\u0438\u043c\u043e\u0441\u0442\u044c, \u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0435\u043d\u0438\u0435 (\u043f\u043e\u0441\u043b\u0435), \u0444\u0430\u0442\u0430\u043b\u0438\u0437\u043c, \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u0441\u0438\u043b\u044b \u043e\u0442 \u043f\u0435\u0440\u0435\u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f.","\u0428\u043e\u043a \u0438 \u043e\u0442\u0440\u0438\u0446\u0430\u043d\u0438\u0435 \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 \u043a\u0440\u0438\u0437\u0438\u0441\u0430, \u043b\u043e\u043c\u0430\u044e\u0449\u0435\u0433\u043e \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u0443\u044e \u0436\u0438\u0437\u043d\u044c. \u0416\u0435\u0441\u0442\u043a\u0430\u044f, \u0431\u0435\u0437\u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u0430\u044f \u0440\u0435\u0448\u0438\u043c\u043e\u0441\u0442\u044c '\u0441\u0436\u0435\u0447\u044c \u043c\u043e\u0441\u0442\u044b' \u0438 \u043f\u0440\u0438\u043d\u044f\u0442\u044c \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u043e\u0441\u0442\u044c \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0439. \u041e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u043d\u0435\u0432\u0435\u0440\u043e\u044f\u0442\u043d\u043e\u0439 \u043b\u0435\u0433\u043a\u043e\u0441\u0442\u0438 \u0438 \u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u043f\u043e\u0441\u043b\u0435 \u043f\u0440\u043e\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f '\u0434\u043d\u0430'. \u0424\u0430\u0442\u0430\u043b\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435 ('\u0442\u0430\u043a \u0431\u044b\u043b\u043e \u043d\u0430\u0434\u043e') \u043f\u0440\u0438 \u0432\u0437\u0433\u043b\u044f\u0434\u0435 \u043d\u0430 \u043f\u0440\u043e\u0439\u0434\u0435\u043d\u043d\u044b\u0439 \u043a\u0440\u0438\u0437\u0438\u0441."],t.l)
B.US=new A.aL(B.aI,["\u0418\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044f","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f. \u0413\u043e\u0440\u0438\u0437\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u0423\u043c\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c","\u0411\u0430\u043b\u0430\u043d\u0441, \u0430\u043b\u0445\u0438\u043c\u0438\u044f, \u0433\u0430\u0440\u043c\u043e\u043d\u0438\u044f \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u043f\u043e\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u0435\u0439. \u0418\u0441\u0446\u0435\u043b\u044f\u044e\u0449\u0438\u0439 \u0441\u0438\u043d\u0442\u0435\u0437.","\u0414\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u044f, \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u0430. \u041e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u043e\u0432 \u0438\u043b\u0438 \u043f\u043e\u043f\u0443\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0431\u0449\u0435\u043d\u0438\u044e","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u0438\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044f","\u0411\u043e\u043b\u0435\u0435 \u043b\u043e\u044f\u043b\u0435\u043d \u0438 \u043b\u0438\u0431\u0435\u0440\u0430\u043b\u0435\u043d, \u043c\u043e\u0436\u0435\u0442 \u0438\u0434\u0442\u0438 \u043d\u0430 \u0443\u0441\u0442\u0443\u043f\u043a\u0438, \u043c\u043e\u0436\u0435\u0442 \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c\u0441\u044f.","\u0418\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044f.","\u041f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u044b, \u043f\u0440\u0438\u043c\u0438\u0440\u0435\u043d\u0438\u0435, \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c\u0441\u044f.","\u041f\u043e\u043b\u0438\u0442\u0438\u043a\u0430. \u041c\u0435\u0436\u0434\u0443\u043d\u0430\u0440\u043e\u0434\u043d\u044b\u0435 \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044f.","\u0421\u0442\u0440\u0430\u0445 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0443\u043d\u0438\u0436\u0435\u043d\u043d\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u0443\u0449\u0435\u0440\u0431\u043d\u043e\u0441\u0442\u0438.","\u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043a \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u0430\u043c, \u0432\u044b\u0439\u0442\u0438 \u043d\u0430 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u043a\u043e\u043c\u043f\u0440\u043e\u043c\u0438\u0441\u0441\u0430. \u0416\u0435\u0441\u0442\u0430\u043d\u0438\u0435 \u0441\u0442\u0430\u0442\u044c \u043f\u043e\u0441\u0440\u0435\u0434\u043d\u0438\u043a\u043e\u043c.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0435 \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u043e\u0441\u0442\u0438, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438 \u043a \u0438\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438.","\u0418\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044f",'\u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c\u0441\u044f \u0438 \u043f\u043e\u0439\u0442\u0438 \u043d\u0430 \u0443\u0441\u0442\u0443\u043f\u043a\u0438, \u043b\u043e\u044f\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043b\u0438\u0431\u0435\u0440\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c, "\u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442". \u041f\u0440\u0438 \u0432\u044b\u0441\u043e\u043a\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u0435 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 -- \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0442\u043e\u0440 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u043e\u0432, \u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0438\u0435. \u041f\u0440\u0438 \u043d\u0438\u0437\u043a\u043e\u043c -- \u0438\u0437\u0431\u0435\u0433\u0430\u043d\u0438\u0435, \u043f\u043e\u043f\u0443\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e, \u0431\u0430\u0440\u0434\u0430\u043a, \u0443\u0449\u0435\u0440\u0431\u043d\u043e\u0441\u0442\u044c, \u0443\u0442\u0440\u0430\u0442\u044b, \u0431\u043e\u043b\u0435\u0437\u043d\u0438. \u041f\u043e\u043b\u0438\u0442\u0438\u043a\u0430. \u0421\u0432\u043e\u0431\u043e\u0434\u043d\u043e \u043e\u043f\u0435\u0440\u0438\u0440\u0443\u0435\u0442 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0439.',"\u0414\u0438\u043f\u043b\u043e\u043c\u0430\u0442","\u0421\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u0433\u0430\u0440\u043c\u043e\u043d\u0438\u0438, \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u044f.","\u0412\u0438\u0434\u0438\u0442 \u043e\u0431\u0449\u0435\u0435 \u0432 \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u043f\u043e\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044f\u0445, \u0443\u043c\u0435\u0435\u0442 \u0434\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0442\u044c\u0441\u044f, \u0441\u043d\u0438\u043c\u0430\u0442\u044c \u043d\u0430\u043f\u0440\u044f\u0436\u0435\u043d\u0438\u0435.","\u041f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043e\u0432, \u043d\u0435\u0438\u0441\u043a\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0438\u0437-\u0437\u0430 \u0436\u0435\u043b\u0430\u043d\u0438\u044f \u0443\u0433\u043e\u0434\u0438\u0442\u044c \u0432\u0441\u0435\u043c.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0414\u0438\u043f\u043b\u043e\u043c\u0430\u0442 \u0430\u043a\u0442\u0438\u0432\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0432 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430\u0445 \u0434\u043b\u044f \u043f\u043e\u0438\u0441\u043a\u0430 \u043a\u043e\u043d\u0441\u0435\u043d\u0441\u0443\u0441\u0430.","\xab\u042f \u0438\u0441\u043a\u0440\u0435\u043d\u043d\u0435 \u0441\u0442\u0440\u0435\u043c\u043b\u044e\u0441\u044c \u043a \u043c\u0438\u0440\u0443 \u0438\u043b\u0438 \u043f\u0440\u043e\u0441\u0442\u043e \u0431\u043e\u044e\u0441\u044c \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430?\xbb","\u0421\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435, \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0435 \u043a \u0433\u0430\u0440\u043c\u043e\u043d\u0438\u0438, \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0435\u0435 \u043d\u0430\u043f\u0440\u044f\u0436\u0435\u043d\u0438\u0435 (\u043e\u0442 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430), \u043e\u0431\u043b\u0435\u0433\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0438 \u043d\u0430\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u0438 \u043a\u043e\u043c\u043f\u0440\u043e\u043c\u0438\u0441\u0441\u0430.","\u0418\u0441\u043a\u0443\u0441\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f, \u043d\u0430\u0442\u044f\u043d\u0443\u0442\u0430\u044f \u0443\u043b\u044b\u0431\u043a\u0430 \u0438 \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u044b\u0439 \u0442\u043e\u043d \u0432 \u0440\u0430\u0437\u0433\u0430\u0440 \u043e\u0436\u0435\u0441\u0442\u043e\u0447\u0435\u043d\u043d\u043e\u0433\u043e \u0441\u043f\u043e\u0440\u0430. \u0418\u0441\u043a\u0440\u0435\u043d\u043d\u044f\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u0438 \u0440\u0430\u0441\u0441\u043b\u0430\u0431\u043b\u0435\u043d\u0438\u0435, \u043a\u043e\u0433\u0434\u0430 \u0432\u0440\u0430\u0436\u0434\u0443\u044e\u0449\u0438\u0435 \u0441\u0442\u043e\u0440\u043e\u043d\u044b \u043f\u0440\u0438\u0445\u043e\u0434\u044f\u0442 \u043a \u0441\u043e\u0433\u043b\u0430\u0441\u0438\u044e. \u0412\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0435\u0435 \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0438 \u043d\u0435\u0432\u044b\u0441\u043a\u0430\u0437\u0430\u043d\u043d\u043e\u0435 \u043d\u0435\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u043e, \u0435\u0441\u043b\u0438 \u043f\u0440\u0438\u0448\u043b\u043e\u0441\u044c \u0443\u0441\u0442\u0443\u043f\u0438\u0442\u044c \u0440\u0430\u0434\u0438 \u043c\u0438\u0440\u0430. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u043f\u0440\u043e\u0444\u0435\u0441\u0441\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0439 \u0433\u043e\u0440\u0434\u043e\u0441\u0442\u0438 \u0437\u0430 \u0443\u0441\u043f\u0435\u0448\u043d\u043e \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u043d\u044b\u0435 \u0441\u043b\u043e\u0436\u043d\u044b\u0435 \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u044b."],t.l)
B.UV=new A.aL(B.aI,["\u041f\u0440\u043e\u0432\u043e\u043a\u0430\u0446\u0438\u044f","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f. \u0412\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u044c\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0414\u044c\u044f\u0432\u043e\u043b","\u0418\u043b\u043b\u044e\u0437\u0438\u0438, \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0438, \u0442\u0435\u043d\u0438. \u041e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0435\u043d\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u0438\u0435.","\u0412\u044b\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0438\u0437 \u0438\u043b\u043b\u044e\u0437\u0438\u0439. \u0416\u0435\u0441\u0442\u043a\u0430\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u043d\u0430 \u0444\u0430\u043b\u044c\u0448\u044c. \u0418\u043d\u0442\u0440\u0438\u0433\u0438.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u0432 \u043e\u0431\u0449\u0435\u043d\u0438\u0438","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u0432\u044b\u044f\u0432\u043b\u0435\u043d\u0438\u0435 \u0444\u0430\u043b\u044c\u0448\u0438","\u0411\u043e\u043b\u0435\u0435 \u043e\u0441\u0442\u0440\u043e \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442 \u043d\u0430 \u0444\u0430\u043b\u044c\u0448 \u0438 \u043d\u0430\u0438\u0433\u0440\u0430\u043d\u043d\u043e\u0441\u0442\u044c \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438. \u0412\u0438\u0434\u0438\u0442 \u0438\u043b\u043b\u044e\u0437\u0438\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u043b\u044e\u0434\u0438 \u0441\u043e\u0437\u0434\u0430\u044e\u0442 \u043e \u0441\u0435\u0431\u0435.","\u0414\u043e\u0441\u0442\u043e\u0432\u0435\u0440\u043d\u043e\u0441\u0442\u044c, \u0438\u0441\u0442\u0438\u043d\u043d\u043e\u0441\u0442\u044c.","\u0418\u0441\u043a\u0443\u0448\u0435\u043d\u0438\u0435, \u043f\u0440\u043e\u0432\u043e\u043a\u0430\u0446\u0438\u044f. \u0414\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0430 \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u0438\u0439.","\u041f\u043e\u043b\u0438\u0442\u0438\u043a\u0430. \u0410\u0434\u0432\u043e\u043a\u0430\u0442\u0443\u0440\u0430.","\u0421\u0442\u0440\u0430\u0445 \u0441\u0435\u043a\u0441\u0443\u0430\u043b\u044c\u043d\u044b\u0445 \u043a\u043e\u043d\u0442\u0430\u043a\u0442\u043e\u0432. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u043e\u0439 \u0441\u0435\u043a\u0441\u0443\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u043e\u0442\u0432\u0435\u0440\u0433\u043d\u0443\u0442\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u0440\u0430\u0441\u043a\u0440\u0435\u043f\u043e\u0449\u0435\u043d\u043d\u044b\u043c \u0438 \u0437\u0430\u043a\u0440\u044b\u0442\u044b\u043c \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e. \u0421\u0442\u0440\u0430\u0445 \u043a\u043e\u043c\u043f\u0440\u043e\u043c\u0430\u0442\u0430.","\u0418\u043d\u043e\u0433\u0434\u0430 \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u043f\u0440\u0438\u0440\u043e\u0434\u0430 \u0438\u0441\u043a\u0443\u0448\u0435\u043d\u0438\u044f, \u0441\u043e\u0431\u043b\u0430\u0437\u043d\u0430, \u043f\u0440\u043e\u0432\u043e\u043a\u0430\u0446\u0438\u0438.","\u0423\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u0437\u043d\u0430\u0432\u0430\u0442\u044c \u0441\u0432\u043e\u044e \u043f\u0440\u043e\u0432\u043e\u043a\u0430\u0446\u0438\u043e\u043d\u043d\u0443\u044e \u043f\u0440\u0438\u0440\u043e\u0434\u0443 \u0438 \u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u0435\u044e \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e.","\u041e\u0431\u0443\u0441\u043b\u043e\u0432\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c",'\u0412\u044b\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0438\u0437 \u0438\u043b\u043b\u044e\u0437\u0438\u0439. \u0412\u0438\u0434\u0438\u0442 \u0438\u043b\u043b\u044e\u0437\u0438\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u043b\u044e\u0434\u0438 \u0441\u043e\u0437\u0434\u0430\u044e\u0442 \u043e \u0441\u0435\u0431\u0435. \u0416\u0435\u0441\u0442\u043a\u0430\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u043d\u0430 \u0444\u0430\u043b\u044c\u0448 \u0438 \u043d\u0430\u0438\u0433\u0440\u0430\u043d\u043d\u043e\u0441\u0442\u044c \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438: \u0438\u0441\u043a\u0443\u0448\u0435\u043d\u0438\u0435, \u043f\u0440\u043e\u0432\u043e\u043a\u0430\u0446\u0438\u044f, \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u0435 "\u043e\u0431\u0440\u0430\u0437\u0430" (\u0447\u0435\u043c \u0432\u044b\u0448\u0435 \u0441\u0442\u0430\u0442\u0443\u0441, \u0442\u0435\u043c \u0438\u0437\u043e\u0449\u0440\u0435\u043d\u043d\u0435\u0435 \u0438\u043d\u0442\u0440\u0438\u0433\u0438). \u041a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u043f\u0440\u0438\u043d\u044f\u0442\u043e\u0433\u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u043e\u043c \u0440\u0435\u0448\u0435\u043d\u0438\u044f. \u0418\u043d\u0434\u0438\u043a\u0430\u0442\u043e\u0440 \u0438\u0441\u0442\u0438\u043d\u043d\u043e\u0441\u0442\u0438 \u0438 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0441\u043e\u0431\u044b\u0442\u0438\u0439. \u0421\u0432\u043e\u0431\u043e\u0434\u0430, \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u043e, \u043f\u0438\u043b\u0438\u0433\u0440\u0438\u043c. \u0413\u0438\u0431\u043a\u043e\u0441\u0442\u044c. \u0412\u043e\u0441\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u043c\u0438\u0440\u0430.',"\u041f\u0440\u043e\u0432\u043e\u043a\u0430\u0442\u043e\u0440","\u041f\u0440\u043e\u043d\u0438\u0446\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0443\u043c\u0435\u043d\u0438\u0435 \u0432\u0438\u0434\u0435\u0442\u044c \u0441\u0443\u0442\u044c.","\u0420\u0430\u0441\u043f\u043e\u0437\u043d\u0430\u0451\u0442 \u043b\u043e\u0436\u044c \u0438 \u043c\u0430\u043d\u0438\u043f\u0443\u043b\u044f\u0446\u0438\u0438, \u0432\u0441\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u043f\u0440\u0430\u0432\u0434\u0443, \u043a\u0430\u043a\u043e\u0439 \u0431\u044b \u0433\u043e\u0440\u044c\u043a\u043e\u0439 \u043e\u043d\u0430 \u043d\u0438 \u0431\u044b\u043b\u0430.","\u0426\u0438\u043d\u0438\u0437\u043c, \u0436\u0435\u0441\u0442\u043e\u043a\u043e\u0441\u0442\u044c \u0432 \u043e\u0431\u043b\u0438\u0447\u0435\u043d\u0438\u0438 \u0447\u0443\u0436\u0438\u0445 \u0441\u043b\u0430\u0431\u043e\u0441\u0442\u0435\u0439, \u043c\u0430\u043d\u0438\u043f\u0443\u043b\u044f\u0446\u0438\u044f \u043f\u0440\u0430\u0432\u0434\u043e\u0439.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u041f\u0440\u043e\u0432\u043e\u043a\u0430\u0442\u043e\u0440 \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u043e\u0442\u043b\u0438\u0447\u0438\u0442\u044c \u0438\u0441\u043a\u0440\u0435\u043d\u043d\u0435\u0435 \u043e\u0442 \u0444\u0430\u043b\u044c\u0448\u0438\u0432\u043e\u0433\u043e.","\xab\u042f \u0438\u0449\u0443 \u043f\u0440\u0430\u0432\u0434\u0443 \u0434\u043b\u044f \u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \u0434\u043b\u044f \u0442\u043e\u0433\u043e, \u0447\u0442\u043e\u0431\u044b \u043e\u0441\u0443\u0434\u0438\u0442\u044c?\xbb","\u041f\u0440\u0435\u0437\u0440\u0435\u043d\u0438\u0435, \u0446\u0438\u043d\u0438\u0437\u043c, \u0445\u043e\u043b\u043e\u0434\u043d\u0430\u044f \u044f\u0440\u043e\u0441\u0442\u044c \u043d\u0430 \u0444\u0430\u043b\u044c\u0448\u044c, \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0443\u0430\u043b\u044c\u043d\u043e\u0435 \u0443\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0438\u0435 \u043e\u0442 \u0440\u0430\u0437\u043e\u0431\u043b\u0430\u0447\u0435\u043d\u0438\u044f, \u0438\u0437\u043e\u043b\u044f\u0446\u0438\u044f.","\u042f\u0437\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f, \u0442\u043e\u0447\u043d\u0430\u044f \u0440\u0435\u043c\u0430\u0440\u043a\u0430, \u0432\u0441\u043a\u0440\u044b\u0432\u0430\u044e\u0449\u0430\u044f \u0447\u0443\u0436\u043e\u0435 \u043b\u0438\u0446\u0435\u043c\u0435\u0440\u0438\u0435, \u0441 \u0447\u0443\u0432\u0441\u0442\u0432\u043e\u043c \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u0433\u043e \u0443\u0434\u043e\u0432\u043b\u0435\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u044f. \u041b\u0435\u0434\u0435\u043d\u044f\u0449\u0435\u0435 \u043f\u0440\u0435\u0437\u0440\u0435\u043d\u0438\u0435 \u0438 \u043e\u0442\u0441\u0442\u0440\u0430\u043d\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u0442\u0435\u043c, \u043a\u043e\u0433\u043e \u043e\u043d \u0443\u043b\u0438\u0447\u0438\u043b \u0432\u043e \u043b\u0436\u0438. \u0421\u043a\u0440\u044b\u0442\u043e\u0435 \u0443\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0438\u0435 \u043e\u0442 \u0445\u0430\u043e\u0441\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u043e\u0437\u043d\u0438\u043a\u0430\u0435\u0442 \u043f\u043e\u0441\u043b\u0435 \u0435\u0433\u043e '\u0440\u0430\u0437\u043e\u0431\u043b\u0430\u0447\u0435\u043d\u0438\u0439'. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0430 \u0438 \u0442\u043e\u0441\u043a\u0438, \u043f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e '\u043d\u0435\u0442 \u0440\u0430\u0432\u043d\u044b\u0445, \u043a\u0442\u043e \u0432\u0438\u0434\u0438\u0442 \u0442\u0443 \u0436\u0435 \u043f\u0440\u0430\u0432\u0434\u0443'."],t.l)
B.Vc=new A.aL(B.aI,["\u0420\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u0435","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f. \u0412\u0435\u0440\u0442\u0438\u043a\u0430\u043b\u044c\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0411\u0430\u0448\u043d\u044f","\u041a\u0440\u0430\u0445 \u0438\u043b\u043b\u044e\u0437\u0438\u0439, \u0432\u043d\u0435\u0437\u0430\u043f\u043d\u044b\u0435 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b. \u041f\u0440\u043e\u0431\u0443\u0436\u0434\u0435\u043d\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0445\u0430\u043e\u0441.","\u0423\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u044f \u043e\u0442\u0436\u0438\u0442\u043e\u0433\u043e. \xab\u0427\u0438\u0441\u0442\u0438\u043b\u044c\u0449\u0438\u043a\xbb. \u0420\u0438\u0433\u0438\u0434\u043d\u043e\u0441\u0442\u044c, \u043c\u043e\u043b\u0447\u0430\u043b\u0438\u0432\u043e\u0441\u0442\u044c.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u0432\u043e\u0441\u043f\u0440\u0438\u044f\u0442\u0438\u044e","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u044f","\u041b\u0435\u0433\u0447\u0435 \u0440\u0430\u0441\u0441\u0442\u0430\u0435\u0442\u0441\u044f \u0441 \u043d\u0435\u043d\u0443\u0436\u043d\u044b\u043c \u043c\u0443\u0441\u043e\u0440\u043e\u043c (\u043a\u0430\u043a \u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435, \u0442\u0430\u043a \u0438 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435). \u0421 \u043b\u0435\u0433\u043a\u043e\u0441\u0442\u044c\u044e \u0431\u0443\u0434\u0435\u0442 \u0443\u0431\u0438\u0440\u0430\u0442\u044c \u044d\u0442\u043e\u0442 \u043c\u0443\u0441\u043e\u0440 \u0438 \u0432 \u0434\u0440\u0443\u0433\u0438\u0445 \u043b\u044e\u0434\u044f\u0445.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u044f.","\u0423\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u044f \u0432\u0441\u0435\u0433\u043e \u0447\u0442\u043e \u043e\u0442\u0436\u0438\u043b\u043e \u0438 \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043d\u043e.","\u0421\u0438\u043b\u043e\u0432\u044b\u0435 \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u044b.","\u0421\u0442\u0440\u0430\u0445 \u0431\u0435\u0437\u044b\u0441\u0445\u043e\u0434\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0432\u043e\u0439\u043d\u044b. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u0436\u0435\u043b\u0430\u043d\u0438\u0439.","\u0418\u043d\u043e\u0433\u0434\u0430 \u043f\u0440\u043e\u0441\u044b\u043f\u0430\u0435\u0442\u0441\u044f \u0441\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u044e, \u0432\u043c\u0435\u0441\u0442\u043e \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u044f \u0440\u0435\u0448\u0435\u043d\u0438\u044f.","\u041d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0442\u044c \u0441\u0432\u043e\u044e \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043a \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u044f\u043c.","\u041c\u043e\u043b\u043d\u0438\u044f",'\u0423\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u044f, \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u0435 \u043e\u0442\u0436\u0438\u0432\u0448\u0435\u0433\u043e (\u043b\u0435\u0433\u043a\u043e \u0440\u0430\u0441\u0441\u0442\u0430\u0435\u0442\u0441\u044f \u0441 \u043d\u0435\u043d\u0443\u0436\u043d\u044b\u043c \u043c\u0443\u0441\u043e\u0440\u043e\u043c \u0432 \u0441\u0432\u043e\u0435\u043c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435 \u0438 \u0433\u043e\u043b\u043e\u0432\u0435, \u0443\u0431\u0438\u0440\u0430\u0435\u0442 \u044d\u0442\u043e\u0442 \u043c\u0443\u0441\u043e\u0440 \u0432 \u0434\u0440\u0443\u0433\u0438\u0445 \u043b\u044e\u0434\u044f\u0445), "\u0447\u0438\u0441\u0442\u0438\u043b\u044c\u0449\u0438\u043a". \u0420\u0438\u0433\u0438\u0434\u043d\u043e\u0441\u0442\u044c. \u041c\u043e\u043b\u0447\u0430\u043b\u0438\u0432\u043e\u0441\u0442\u044c. \u0421 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435\u043c \u0432\u0441\u0435 \u0432 \u043f\u043e\u0440\u044f\u0434\u043a\u0435. \u0420\u043e\u0441\u0442 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043e\u0442 \u0443\u0440\u043e\u0432\u043d\u044f \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0441\u0442\u0438.',"\u0427\u0438\u0441\u0442\u0438\u043b\u044c\u0449\u0438\u043a","\u0420\u0430\u0434\u0438\u043a\u0430\u043b\u044c\u043d\u043e\u0435 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435, \u043e\u0447\u0438\u0449\u0435\u043d\u0438\u0435.","\u0423\u043c\u0435\u0435\u0442 \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0442\u044c \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044f, \u043f\u0440\u043e\u0435\u043a\u0442\u044b, \u044d\u0442\u0430\u043f\u044b \u0436\u0438\u0437\u043d\u0438, \u043d\u0435 \u043e\u0433\u043b\u044f\u0434\u044b\u0432\u0430\u044f\u0441\u044c \u043d\u0430\u0437\u0430\u0434.","\u0425\u043e\u043b\u043e\u0434\u043d\u043e\u0441\u0442\u044c, \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u0435 \u0431\u0435\u0437 \u0440\u0430\u0437\u0431\u043e\u0440\u0430, \u043d\u0435\u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0446\u0435\u043d\u0438\u0442\u044c \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0435.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0427\u0438\u0441\u0442\u0438\u043b\u044c\u0449\u0438\u043a \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \xab\u0432\u044b\u0447\u0435\u0440\u043a\u043d\u0443\u0442\u044c\xbb \u0442\u043e\u043a\u0441\u0438\u0447\u043d\u043e\u0435 \u0438\u0437 \u0436\u0438\u0437\u043d\u0438.","\xab\u0427\u0442\u043e \u043c\u043d\u0435 \u043f\u043e\u0440\u0430 \u0431\u0435\u0437\u0436\u0430\u043b\u043e\u0441\u0442\u043d\u043e \u043e\u0442\u043f\u0443\u0441\u0442\u0438\u0442\u044c, \u0447\u0442\u043e\u0431\u044b \u0434\u0432\u0438\u0433\u0430\u0442\u044c\u0441\u044f \u0432\u043f\u0435\u0440\u0451\u0434?\xbb","\u0411\u0435\u0437\u0440\u0430\u0437\u043b\u0438\u0447\u0438\u0435, \u0445\u043e\u043b\u043e\u0434\u043d\u043e\u0441\u0442\u044c, \u0440\u0435\u0448\u0438\u043c\u043e\u0441\u0442\u044c, \u043e\u0431\u043b\u0435\u0433\u0447\u0435\u043d\u0438\u0435 (\u043f\u043e\u0441\u043b\u0435 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043d\u0438\u044f), \u0441\u043a\u0443\u043a\u0430 (\u043a\u043e\u0433\u0434\u0430 \u043d\u0435\u0447\u0435\u0433\u043e \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u0442\u044c).","\u0425\u043e\u043b\u043e\u0434\u043d\u043e\u0435, \u0431\u0435\u0437\u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0435 '\u043d\u0435\u0442' \u0438 \u0440\u0430\u0437\u0440\u044b\u0432 \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0439, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0438\u0441\u0447\u0435\u0440\u043f\u0430\u043b\u0438 \u0441\u0435\u0431\u044f. \u041f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435, \u0434\u0435\u043b\u043e\u0432\u043e\u0435 \u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435 \u043f\u0440\u0438 \u043b\u0438\u043a\u0432\u0438\u0434\u0430\u0446\u0438\u0438 \u043f\u0440\u043e\u0432\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0435\u043a\u0442\u0430. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u0433\u043e \u043e\u0431\u043b\u0435\u0433\u0447\u0435\u043d\u0438\u044f \u0438 '\u0447\u0438\u0441\u0442\u043e\u0442\u044b' \u043f\u043e\u0441\u043b\u0435 \u0438\u0437\u0431\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u043e\u0442 \u0445\u043b\u0430\u043c\u0430 \u2014 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0438\u043b\u0438 \u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0433\u043e. \u0410\u043f\u0430\u0442\u0438\u044f \u0438 \u0441\u043a\u0443\u043a\u0430 \u0432 \u043f\u0435\u0440\u0438\u043e\u0434\u044b \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u0438, \u043a\u043e\u0433\u0434\u0430 '\u043d\u0435\u0447\u0435\u0433\u043e \u0440\u0443\u0448\u0438\u0442\u044c'."],t.l)
B.V4=new A.aL(B.aI,["\u0418\u0441\u0446\u0435\u043b\u0435\u043d\u0438\u0435","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u041f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u0430\u044f","\u041d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0443\u0441\u0438\u043b\u0438\u0442\u0435\u043b\u044c","\u0417\u0432\u0435\u0437\u0434\u0430","\u041d\u0430\u0434\u0435\u0436\u0434\u0430, \u0434\u0443\u0445\u043e\u0432\u043d\u044b\u0439 \u0441\u0432\u0435\u0442, \u0432\u0435\u0440\u0430. \u0418\u0441\u0446\u0435\u043b\u0435\u043d\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0441\u0432\u044f\u0437\u044c \u0441 \u0432\u044b\u0441\u0448\u0438\u043c.","\u0418\u0441\u0446\u0435\u043b\u0435\u043d\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0435. \u041c\u0435\u0434\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c. \u0427\u0443\u0432\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f","\u043d\u0438\u0437\u043a\u0438\u0439","\u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0430 \u0438 \u0438\u0441\u0446\u0435\u043b\u0435\u043d\u0438\u0435","\u0421\u043a\u043b\u043e\u043d\u0435\u043d \u043a \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u044e, \u043f\u043e\u0433\u0440\u0443\u0436\u0435\u043d\u0438\u044e \u0432 \u0441\u0435\u0431\u044f. \u0412\u043e\u0437\u043c\u043e\u0436\u0435\u043d \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u043f\u043e\u0438\u0441\u043a. \u0412\u0440\u0435\u043c\u044f \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442\u0441\u044f, \u0434\u043b\u044f \u043d\u0435\u0433\u043e \u0432\u0430\u0436\u043d\u0430 \u0442\u043e\u043b\u044c\u043a\u043e \u0435\u0433\u043e \u0441\u0443\u0442\u044c.","\u0421\u0430\u043c\u043e\u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0435.","\u041f\u043e\u0433\u0440\u0443\u0436\u0435\u043d\u0438\u0435 \u0432 \u0441\u0435\u0431\u044f, \u043c\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044f \u0438 \u043b\u044e\u0431\u043e\u0439 \u0434\u0440\u0443\u0433\u043e\u0439 \u0441\u043f\u043e\u0441\u043e\u0431, \u0434\u0430\u044e\u0449\u0438\u0439 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0443\u0441\u043b\u044b\u0448\u0430\u0442\u044c \u0441\u0435\u0431\u044f. \u0411\u0435\u0433\u0441\u0442\u0432\u043e \u0432 \u0442\u0438\u0448\u0438\u043d\u0443.","\u041d\u0435\u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u043d\u0430\u044f \u043c\u0435\u0434\u0438\u0446\u0438\u043d\u0430.","\u0421\u0442\u0440\u0430\u0445 \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0440\u0430\u0432\u043d\u043e\u0434\u0443\u0448\u0438\u044f \u0434\u0440\u0443\u0433\u0438\u0445 \u043b\u044e\u0434\u0435\u0439. \u0421\u0442\u0440\u0430\u0445 \u0431\u043e\u043b\u0435\u0437\u043d\u0438.","\u0418\u043d\u043e\u0433\u0434\u0430 \u043f\u0440\u043e\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0437\u0430\u043c\u044b\u043a\u0430\u043d\u0438\u044f \u0438 \u0443\u0445\u043e\u0434 \u0432 \u0441\u0435\u0431\u044f \u043d\u0430 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u043d\u043e\u0435 \u0432\u0440\u0435\u043c\u044f.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u0430\u044f \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c \u0441\u0430\u043c\u043e\u0440\u0435\u0433\u0443\u043b\u044f\u0446\u0438\u0435\u0439.","\u041c\u043e\u043b\u0447\u0430\u043d\u0438\u0435","\u0418\u0441\u0446\u0435\u043b\u0435\u043d\u0438\u0435, \u0441\u0430\u043c\u043e\u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f \u0438 \u0441\u0430\u043c\u043e\u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0435, \u043f\u043e\u0433\u0440\u0443\u0436\u0435\u043d\u0438\u0435 \u0432 \u0441\u0435\u0431\u044f. \u0417\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u043e\u0432, \u0443\u0441\u043a\u043e\u0440\u0435\u043d\u0438\u0435 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u043f\u0440\u0438\u0432\u043e\u0434\u0438\u0442 \u043a \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0435\u043c\u0443 \u0441\u0433\u043e\u0440\u0430\u043d\u0438\u044e \u0438 \u0438\u0441\u0442\u043e\u0449\u0435\u043d\u0438\u044e, \u043c\u0435\u0434\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0432 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0438 \u0440\u0435\u0448\u0435\u043d\u0438\u044f. \u0422\u0438\u0448\u0438\u043d\u0430. \u0420\u0430\u0432\u043d\u043e\u0432\u0435\u0441\u0438\u0435. \u0412\u043e\u0441\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u044c. \u041a\u0430\u043f\u0440\u0438\u0437\u043d\u043e\u0441\u0442\u044c, \u043e\u0431\u0438\u0434\u0447\u0438\u0432\u043e\u0441\u0442\u044c.","\u041e\u0442\u0448\u0435\u043b\u044c\u043d\u0438\u043a","\u0413\u043b\u0443\u0431\u0438\u043d\u0430, \u0441\u0432\u044f\u0437\u044c \u0441 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u043c \u043c\u0438\u0440\u043e\u043c.","\u0421\u0430\u043c\u043e\u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u0443\u043c\u0435\u043d\u0438\u0435 \u0441\u043b\u044b\u0448\u0430\u0442\u044c \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0433\u043e\u043b\u043e\u0441, \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0442\u044c\u0441\u044f \u0432 \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0438.","\u0418\u0437\u043e\u043b\u044f\u0446\u0438\u044f, \u043e\u0442\u0440\u044b\u0432 \u043e\u0442 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438, \u043f\u043e\u0433\u0440\u0443\u0436\u0435\u043d\u0438\u0435 \u0432 \u0441\u0435\u0431\u044f \u043a\u0430\u043a \u043f\u043e\u0431\u0435\u0433 \u043e\u0442 \u043f\u0440\u043e\u0431\u043b\u0435\u043c.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u041e\u0442\u0448\u0435\u043b\u044c\u043d\u0438\u043a \u0437\u043e\u0432\u0451\u0442 \u0432\u0430\u0441, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u0441\u0438\u043b\u044b \u0438 \u043d\u0430\u0439\u0442\u0438 \u043e\u0442\u0432\u0435\u0442 \u0432\u043d\u0443\u0442\u0440\u0438.","\xab\u042f \u0443\u0445\u043e\u0436\u0443 \u0432 \u0441\u0435\u0431\u044f \u0434\u043b\u044f \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \u0447\u0442\u043e\u0431\u044b \u0438\u0437\u0431\u0435\u0436\u0430\u0442\u044c \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0439?\xbb","\u0423\u043c\u0438\u0440\u043e\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u0435 (\u0432 \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0438), \u043a\u0430\u043f\u0440\u0438\u0437\u043d\u043e\u0441\u0442\u044c, \u043e\u0431\u0438\u0434\u0447\u0438\u0432\u043e\u0441\u0442\u044c, \u0442\u0438\u0445\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u0441\u0430\u043c\u043e\u043f\u043e\u0437\u043d\u0430\u043d\u0438\u044f, \u0442\u043e\u0441\u043a\u0430 \u043f\u043e \u0442\u0438\u0448\u0438\u043d\u0435.","\u0413\u043b\u0443\u0431\u043e\u043a\u0430\u044f \u043f\u043e\u0442\u0440\u0435\u0431\u043d\u043e\u0441\u0442\u044c \u0443\u0435\u0434\u0438\u043d\u0438\u0442\u044c\u0441\u044f \u0438 '\u043d\u0435 \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c \u043d\u0438 \u0441 \u043a\u0435\u043c' \u043f\u043e\u0441\u043b\u0435 \u0438\u043d\u0442\u0435\u043d\u0441\u0438\u0432\u043d\u043e\u0433\u043e \u043e\u0431\u0449\u0435\u043d\u0438\u044f. \u041e\u0431\u0438\u0434\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u0438 \u0443\u0445\u043e\u0434 \u0432 \u0441\u0435\u0431\u044f \u043f\u0440\u0438 \u043c\u0430\u043b\u0435\u0439\u0448\u0435\u043c \u0448\u0443\u043c\u0435 \u0438\u043b\u0438 \u043d\u0430\u0440\u0443\u0448\u0435\u043d\u0438\u0438 \u0435\u0433\u043e \u043b\u0438\u0447\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430. \u0421\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u043f\u043e\u0442\u043e\u043a\u0430 \u0438 \u0442\u0438\u0445\u043e\u0433\u043e \u0441\u0447\u0430\u0441\u0442\u044c\u044f \u0432\u043e \u0432\u0440\u0435\u043c\u044f \u043c\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 \u0438\u043b\u0438 \u043f\u0440\u043e\u0433\u0443\u043b\u043a\u0438 \u043d\u0430 \u043f\u0440\u0438\u0440\u043e\u0434\u0435 \u0432 \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0435. \u0420\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0438 \u043d\u0435\u0442\u0435\u0440\u043f\u0438\u043c\u043e\u0441\u0442\u044c, \u0435\u0441\u043b\u0438 \u0435\u0433\u043e \u0443\u0435\u0434\u0438\u043d\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u0440\u044b\u0432\u0430\u044e\u0442 \u0431\u0435\u0437 \u0432\u0435\u0441\u043a\u043e\u0439 \u043f\u0440\u0438\u0447\u0438\u043d\u044b."],t.l)
B.Va=new A.aL(B.aI,["\u041f\u0440\u043e\u0448\u043b\u043e\u0435","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e-\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u0421\u0442\u0430\u0440\u0448\u0430\u044f","\u041d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0443\u0441\u0438\u043b\u0438\u0442\u0435\u043b\u044c","\u041b\u0443\u043d\u0430","\u0422\u0435\u043d\u0438 \u043f\u0440\u043e\u0448\u043b\u043e\u0433\u043e, \u0438\u043b\u043b\u044e\u0437\u0438\u0438, \u043f\u043e\u0434\u0441\u043e\u0437\u043d\u0430\u043d\u0438\u0435. \u041f\u0443\u0442\u044c \u0447\u0435\u0440\u0435\u0437 \u0442\u044c\u043c\u0443 \u043a \u0441\u0432\u0435\u0442\u0443.","\u041f\u043e\u0437\u043d\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u0448\u043b\u043e\u0433\u043e \u043e\u043f\u044b\u0442\u0430. \u0422\u0440\u0435\u0432\u043e\u0436\u043d\u043e\u0441\u0442\u044c, \u0441\u0442\u0440\u0430\u0445. \u042d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f","\u043d\u0438\u0437\u043a\u0438\u0439","\u0430\u043d\u0430\u043b\u0438\u0437 \u043f\u0440\u043e\u0448\u043b\u043e\u0433\u043e","\u041e\u0431\u0440\u0430\u0449\u0430\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043d\u0430 \u0441\u0432\u043e\u0439 \u043f\u0440\u043e\u0448\u043b\u044b\u0439 \u043e\u043f\u044b\u0442. \u0412\u043e\u0437\u043d\u0438\u043a\u0430\u0435\u0442 \u0444\u043e\u043a\u0443\u0441 \u043d\u0430 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u0435 -- \u043f\u0440\u0438 \u043d\u043e\u0432\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0443\u0435\u0442\u0441\u044f \u0441\u0442\u0430\u0440\u044b\u043c \u043e\u043f\u044b\u0442\u043e\u043c.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u0448\u043b\u043e\u0433\u043e \u043e\u043f\u044b\u0442\u0430.","\u0418\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u0438\u0447\u0438\u043d\u043d\u043e-\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0441\u0432\u044f\u0437\u0435\u0439.","\u041f\u0441\u0438\u0445\u043e\u0442\u0435\u0440\u0430\u043f\u0438\u044f. \u0420\u0430\u0431\u043e\u0442\u0430 \u0441 \u0440\u043e\u0434\u043e\u0432\u044b\u043c\u0438 \u0441\u0438\u0441\u0442\u0435\u043c\u0430\u043c\u0438.","\u0421\u0442\u0440\u0430\u0445 \u043f\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0443\u0440\u0430\u0432\u043d\u043e\u0432\u0435\u0448\u0435\u043d\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f. \u0421\u0442\u0440\u0430\u0445 \u043d\u0435\u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u0438 \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u0441\u0442\u043e\u044f\u0442\u044c.","\u0418\u043d\u043e\u0433\u0434\u0430 \u043f\u0440\u043e\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0440\u043e\u0434\u043e\u0432\u043e\u0435 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0432 \u0432\u0438\u0434\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0438 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430: \u0442\u0430\u043a \u043a\u0430\u043a \u043f\u043e\u0441\u0442\u0443\u043f\u0430\u044e\u0442 \xab\u0443 \u043d\u0430\u0441\xbb (\u0432 \u0441\u0435\u043c\u044c\u0435).","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0442\u044c \u0432\u0441\u0435 \u0440\u043e\u0434\u043e\u0432\u043e\u0435 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435, \u0432\u0435\u0441\u044c \u0440\u043e\u0434\u043e\u0432\u043e\u0439 \u043e\u043f\u044b\u0442 \u0438 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c \u0441 \u043f\u0440\u043e\u0448\u043b\u044b\u043c \u043a\u0430\u043a \u0441 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u043c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430.","\u041f\u0440\u043e\u0448\u043b\u044b\u0435 \u0436\u0438\u0437\u043d\u0438","\u041f\u043e\u0437\u043d\u0430\u043d\u0438\u0435 \u043e\u0431\u0443\u0441\u043b\u043e\u0432\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u0438: \u043f\u0440\u043e\u0448\u043b\u044b\u0439 \u043e\u043f\u044b\u0442, \u043f\u0440\u0438\u0447\u0438\u043d\u043d\u043e-\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0441\u0432\u044f\u0437\u0435\u0439. \u0414\u0438\u0444\u0444\u0435\u0440\u0435\u043d\u0446\u0438\u0430\u0446\u0438\u044f (\u0440\u0430\u0437\u0434\u0435\u043b\u0435\u043d\u0438\u0435) \u043a\u0430\u043a \u0432\u044b\u0432\u043e\u0434 \u0438 \u0443\u0440\u043e\u043a. \u041f\u0430\u043c\u044f\u0442\u044c, \u0430\u0434\u0430\u043f\u0442\u0430\u0446\u0438\u044f \u043a \u043f\u0440\u043e\u0448\u043b\u043e\u043c\u0443. \u041d\u0435\u0434\u043e\u0432\u0435\u0440\u0438\u0435, \u0442\u0440\u0435\u0432\u043e\u0436\u043d\u043e\u0441\u0442\u044c, \u0441\u0442\u0440\u0430\u0445, \u0447\u0430\u0441\u0442\u044b\u0439 \u0444\u043e\u043a\u0443\u0441 \u043d\u0430 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u0435 (\u0432 \u043d\u043e\u0432\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0443\u0435\u0442\u0441\u044f \u0441\u0442\u0430\u0440\u044b\u043c \u043e\u043f\u044b\u0442\u043e\u043c). \u0412\u043e\u0441\u043f\u0440\u0438\u0438\u043c\u0447\u0438\u0432\u043e\u0441\u0442\u044c, \u0432\u044b\u0441\u043e\u043a\u0438\u0439 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u044d\u043c\u043e\u0446\u0438\u0439, \u044f\u0440\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043d\u0438\u044f.","\u0410\u0440\u0445\u0438\u0432\u0430\u0440\u0438\u0443\u0441","\u0421\u0432\u044f\u0437\u044c \u0441 \u043f\u0440\u043e\u0448\u043b\u044b\u043c, \u0430\u043d\u0430\u043b\u0438\u0437 \u043f\u0440\u0438\u0447\u0438\u043d \u0438 \u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0439.","\u0418\u0437\u0432\u043b\u0435\u043a\u0430\u0435\u0442 \u0443\u0440\u043e\u043a\u0438 \u0438\u0437 \u043e\u0448\u0438\u0431\u043e\u043a, \u043f\u043e\u043d\u0438\u043c\u0430\u0435\u0442 \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u043f\u0440\u043e\u0448\u043b\u043e\u0433\u043e \u043d\u0430 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0435.","\u0416\u0438\u0437\u043d\u044c \u0432 \u043f\u0440\u043e\u0448\u043b\u043e\u043c, \u043d\u0435\u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043e\u0442\u043f\u0443\u0441\u0442\u0438\u0442\u044c \u043e\u0431\u0438\u0434\u044b, \u043f\u0435\u0441\u0441\u0438\u043c\u0438\u0437\u043c.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0410\u0440\u0445\u0438\u0432\u0430\u0440\u0438\u0443\u0441 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u043f\u043e\u043d\u044f\u0442\u044c, \u043a\u0430\u043a \u043f\u0440\u043e\u0448\u043b\u044b\u0439 \u043e\u043f\u044b\u0442 \u0432\u043b\u0438\u044f\u0435\u0442 \u043d\u0430 \u0432\u0430\u0448\u0438 \u0441\u0435\u0433\u043e\u0434\u043d\u044f\u0448\u043d\u0438\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f.","\xab\u041a\u0430\u043a\u0430\u044f \u0438\u0441\u0442\u043e\u0440\u0438\u044f \u0438\u0437 \u043c\u043e\u0435\u0433\u043e \u043f\u0440\u043e\u0448\u043b\u043e\u0433\u043e \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u0435\u0442 \u043c\u043d\u043e\u0439 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c?\xbb","\u0422\u0440\u0435\u0432\u043e\u0433\u0430 (\u043e\u0441\u043d\u043e\u0432\u0430\u043d\u043d\u0430\u044f \u043d\u0430 \u043f\u0440\u043e\u0448\u043b\u043e\u043c \u043e\u043f\u044b\u0442\u0435), \u043d\u043e\u0441\u0442\u0430\u043b\u044c\u0433\u0438\u044f, \u043f\u0435\u0447\u0430\u043b\u044c, \u0432\u0438\u043d\u0430, \u043d\u0435\u0434\u043e\u0432\u0435\u0440\u0438\u0435.","\u041f\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u043d\u0430 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044e, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0447\u0435\u043c-\u0442\u043e \u043d\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0435\u0442 \u0441\u0442\u0430\u0440\u0443\u044e \u0442\u0440\u0430\u0432\u043c\u0443. \u0421\u043b\u0430\u0434\u043a\u0430\u044f, \u043d\u043e \u0433\u0440\u0443\u0441\u0442\u043d\u0430\u044f \u043d\u043e\u0441\u0442\u0430\u043b\u044c\u0433\u0438\u044f \u043f\u043e '\u0441\u0442\u0430\u0440\u044b\u043c \u0434\u043e\u0431\u0440\u044b\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0430\u043c'. \u041d\u0435\u0434\u043e\u0432\u0435\u0440\u0438\u0435 \u043a \u043d\u043e\u0432\u043e\u043c\u0443 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0443, \u043f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e '\u0442\u0430\u043a\u043e\u0439 \u0442\u0438\u043f \u043b\u044e\u0434\u0435\u0439 \u0443\u0436\u0435 \u043f\u043e\u0434\u0432\u043e\u0434\u0438\u043b'. \u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u0438\u043d\u044b \u0437\u0430 \u043e\u0448\u0438\u0431\u043a\u0438, \u0441\u043e\u0432\u0435\u0440\u0448\u0435\u043d\u043d\u044b\u0435 \u043c\u043d\u043e\u0433\u043e \u043b\u0435\u0442 \u043d\u0430\u0437\u0430\u0434, \u043a\u0430\u043a \u0431\u0443\u0434\u0442\u043e \u044d\u0442\u043e \u0431\u044b\u043b\u043e \u0432\u0447\u0435\u0440\u0430."],t.l)
B.V3=new A.aL(B.aI,["\u0411\u043e\u0433\u0430\u0442\u0441\u0442\u0432\u043e","\u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u0421\u0442\u0430\u0440\u0448\u0430\u044f","\u041d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0443\u0441\u0438\u043b\u0438\u0442\u0435\u043b\u044c","\u0421\u043e\u043b\u043d\u0446\u0435","\u0423\u0441\u043f\u0435\u0445, \u0440\u0430\u0434\u043e\u0441\u0442\u044c, \u0438\u0437\u043e\u0431\u0438\u043b\u0438\u0435. \u042f\u0441\u043d\u043e\u0441\u0442\u044c \u0438 \u0434\u0435\u0442\u0441\u043a\u0430\u044f \u0447\u0438\u0441\u0442\u043e\u0442\u0430.","\u041c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f. \u0414\u0443\u0445\u043e\u0432\u043d\u0430\u044f \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u0430 vs \u043d\u0438\u0449\u0435\u0442\u0430.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044e","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u0430\u044f \u0430\u0434\u0430\u043f\u0442\u0430\u0446\u0438\u044f","\u0421\u043a\u043b\u043e\u043d\u0435\u043d \u043a \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043a\u043e\u043c\u0444\u043e\u0440\u0442\u0443, \u043f\u043e\u0432\u044b\u0448\u0435\u043d\u0438\u044e \u0441\u0432\u043e\u0435\u0433\u043e \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f \u0438 \u043e\u043a\u0440\u0443\u0436\u0435\u043d\u0438\u044e \u0441\u0435\u0431\u044f \u0434\u043e\u0441\u0442\u0430\u0442\u043a\u043e\u043c.","\u0414\u043e\u0441\u0442\u0430\u0442\u043e\u043a, \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0435 \u0431\u043b\u0430\u0433\u043e\u043f\u043e\u043b\u0443\u0447\u0438\u0435.","\u0421\u0442\u0438\u043c\u0443\u043b \u043a \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f\u043c \u0447\u0435\u0440\u0435\u0437 \u043d\u0438\u0449\u0435\u0442\u0443.","\u042d\u043a\u043e\u043d\u043e\u043c\u0438\u043a\u0430, \u0444\u0438\u043d\u0430\u043d\u0441\u044b. \u0411\u0438\u0437\u043d\u0435\u0441.","\u0421\u0442\u0440\u0430\u0445 \u043d\u0438\u0449\u0435\u0442\u044b. \u0421\u0442\u0440\u0430\u0445 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u043e\u0439 \u0431\u0435\u0437\u0433\u0440\u0430\u043c\u043e\u0442\u043d\u043e\u0441\u0442\u0438. \u0421\u0442\u0440\u0430\u0445 \u0432\u044b\u0437\u0432\u0430\u0442\u044c \u0437\u0430\u0432\u0438\u0441\u0442\u044c \u0438 \u0441\u0442\u0440\u0430\u0445 \u043d\u0435 \u043e\u043f\u0440\u0430\u0432\u0434\u0430\u0442\u044c \u043d\u0430\u0434\u0435\u0436\u0434\u044b.","\u0418\u043d\u043e\u0433\u0434\u0430 \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u043b\u0438\u0431\u043e \u043e\u0442\u0440\u0435\u043a\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0431\u043b\u0430\u0433\u043e\u043f\u043e\u043b\u0443\u0447\u0438\u044f \u043b\u0438\u0431\u043e \u0434\u0435\u043b\u0430\u0435\u0442 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439 \u0432\u044b\u0431\u043e\u0440 \u0432 \u0441\u0442\u043e\u0440\u043e\u043d\u0443 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u0440\u0438\u0434\u0442\u0438 \u0447\u0435\u0440\u0435\u0437 \u0443\u0432\u0430\u0436\u0435\u043d\u0438\u0435 \u0441\u0435\u0431\u044f \u043a \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0439 \u043e\u0431\u0435\u0441\u043f\u0435\u0447\u0435\u043d\u043d\u043e\u0441\u0442\u0438.","\u041d\u0435\u0432\u0438\u043d\u043d\u043e\u0441\u0442\u044c","\u041c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f, \u043a\u043e\u043c\u0444\u043e\u0440\u0442 \u0438 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u043a. \u0411\u043b\u0430\u0433\u043e\u043f\u043e\u043b\u0443\u0447\u0438\u0435 \u0438 \u0431\u043b\u0430\u0433\u043e\u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435. \u0412\u043e\u0441\u043f\u0440\u0438\u044f\u0442\u0438\u0435 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043c\u0438\u0440\u0430, \u0434\u0435\u043d\u044c\u0433\u0438 (\u0438 \u043b\u044e\u0431\u0430\u044f \u0435\u0434\u0438\u043d\u0438\u0446\u0430 \u0441\u0438\u0441\u0442\u0435\u043c\u044b \u043a\u0443\u043f\u043b\u0438-\u043f\u0440\u043e\u0434\u0430\u0436\u0438), \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u0435, \u0432\u043b\u0430\u0434\u0435\u043d\u0438\u0435. \u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0430\u0442\u044c\u0441\u044f \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043c\u0438 \u043f\u0440\u0438 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0438 \u0441\u043c\u044b\u0441\u043b\u0430. \u0412\u044b\u0441\u043e\u043a\u0438\u0439 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u0434\u0443\u0445\u043e\u0432\u043d\u043e\u0439 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u044b \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0432\u0435\u043d \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u043c \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f\u043c. \u0412\u0430\u0436\u043d\u0430 \u0440\u043e\u043b\u044c \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u0435\u0439, \u0438\u0445 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044f \u0438 \u0441\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u044f. \u0414\u0440\u0443\u0433\u0430\u044f \u043a\u0440\u0430\u0439\u043d\u043e\u0441\u0442\u044c -- \u043d\u0438\u0449\u0435\u0442\u0430, \u043d\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043e, \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u044b, \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0441\u0442\u0440\u0435\u043c\u043b\u0435\u043d\u0438\u0439 \u043a \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f\u043c, \u0440\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u044f (\u0431\u0435\u0433\u0441\u0442\u0432\u043e \u0432 \u0443\u043c\u043e\u0437\u0430\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f).","\u041c\u0435\u0446\u0435\u043d\u0430\u0442","\u041c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u0430\u044f \u0438 \u0434\u0443\u0445\u043e\u0432\u043d\u0430\u044f \u0449\u0435\u0434\u0440\u043e\u0441\u0442\u044c.","\u0423\u043c\u0435\u0435\u0442 \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u0442\u044c \u0438\u0437\u043e\u0431\u0438\u043b\u0438\u0435, \u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043c\u0438, \u0446\u0435\u043d\u0438\u0442\u044c \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e.","\u0416\u0430\u0434\u043d\u043e\u0441\u0442\u044c, \u043c\u0435\u0440\u043a\u0430\u043d\u0442\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043e\u0446\u0435\u043d\u043a\u0430 \u0432\u0441\u0435\u0433\u043e \u0447\u0435\u0440\u0435\u0437 \u043f\u0440\u0438\u0437\u043c\u0443 \u0441\u0442\u043e\u0438\u043c\u043e\u0441\u0442\u0438.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u041c\u0435\u0446\u0435\u043d\u0430\u0442 \u043f\u0440\u043e\u0441\u044b\u043f\u0430\u0435\u0442\u0441\u044f \u0432 \u0432\u043e\u043f\u0440\u043e\u0441\u0430\u0445 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432, \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432 \u0438 \u0441\u0430\u043c\u043e\u043e\u0446\u0435\u043d\u043a\u0438.","\xab\u042f \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e \u0434\u0435\u043d\u044c\u0433\u0438 \u043a\u0430\u043a \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u0438\u043b\u0438 \u043a\u0430\u043a \u0446\u0435\u043b\u044c?\xbb","\u0423\u0434\u043e\u0432\u043b\u0435\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u0435 \u043e\u0442 \u0438\u0437\u043e\u0431\u0438\u043b\u0438\u044f, \u0441\u0442\u0440\u0430\u0445 \u043d\u0438\u0449\u0435\u0442\u044b, \u0449\u0435\u0434\u0440\u043e\u0441\u0442\u044c, \u0436\u0430\u0434\u043d\u043e\u0441\u0442\u044c (\u043d\u0430 \u043d\u0438\u0437\u043a\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u0435), \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c (\u043e\u0442 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0439 \u0431\u0430\u0437\u044b).","\u0418\u0441\u043a\u0440\u0435\u043d\u043d\u044f\u044f, \u0449\u0435\u0434\u0440\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u043e\u0442 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u0438 \u0441\u0434\u0435\u043b\u0430\u0442\u044c \u0434\u043e\u0440\u043e\u0433\u043e\u0439 \u043f\u043e\u0434\u0430\u0440\u043e\u043a \u0438\u043b\u0438 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u043e \u043f\u043e\u043c\u043e\u0447\u044c. \u0418\u0440\u0440\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0442\u0440\u0430\u0445 \u0438 \u043f\u0430\u043d\u0438\u043a\u0430 \u043f\u0440\u0438 \u043d\u0435\u0437\u043d\u0430\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u044b\u0445 \u043f\u043e\u0442\u0435\u0440\u044f\u0445. \u0421\u043f\u043e\u043a\u043e\u0439\u043d\u0430\u044f, \u0434\u043e\u0441\u0442\u043e\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0432 \u0441\u0435\u0431\u0435, \u043f\u043e\u0434\u043a\u0440\u0435\u043f\u043b\u0435\u043d\u043d\u0430\u044f \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u043e\u0439 \u043d\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u044c\u044e. \u041d\u0435\u0440\u0432\u043d\u044b\u0439 \u043f\u043e\u0434\u0441\u0447\u0435\u0442 \u0440\u0430\u0441\u0445\u043e\u0434\u043e\u0432 \u0438 \u0441\u043a\u0443\u043f\u043e\u0441\u0442\u044c, \u0435\u0441\u043b\u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0443\u0433\u0440\u043e\u0437\u0443 \u0441\u0432\u043e\u0435\u043c\u0443 \u0431\u043b\u0430\u0433\u043e\u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044e."],t.l)
B.UY=new A.aL(B.aI,["\u041f\u0440\u0430\u0432\u043e\u0441\u0443\u0434\u0438\u0435","\u0421\u0442\u0430\u0440\u0448\u0430\u044f \u0420\u043e\u043b\u044c. \u0412\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u0421\u0442\u0430\u0440\u0448\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u0421\u0443\u0434","\u0412\u043e\u0437\u0440\u043e\u0436\u0434\u0435\u043d\u0438\u0435, \u043f\u0440\u0438\u0437\u044b\u0432 \u043a \u0442\u0440\u0430\u043d\u0441\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438. \u0424\u0438\u043d\u0430\u043b \u043a\u0430\u0440\u043c\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0446\u0438\u043a\u043b\u0430.","\u0421\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u0432. \u0423\u043b\u044c\u0442\u0438\u043c\u0430\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c. \u041c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u0430\u044f.","\u0417\u0430\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043e\u0431\u0449\u0435\u043d\u0438\u044e","\u0432\u044b\u0441\u043e\u043a\u0438\u0439","\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u0432","\u0411\u043e\u043b\u0435\u0435 \u043e\u0441\u0442\u0440\u043e \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c, \u0431\u043e\u043b\u044c\u0448\u0435 \u0438 \u043b\u0443\u0447\u0448\u0435 \u043f\u043e\u043d\u0438\u043c\u0430\u0435\u0442 \u0438 \u043e\u043f\u0435\u0440\u0438\u0440\u0443\u0435\u0442 \u0437\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u0441\u0444\u0435\u0440\u043e\u0439.","\u0421\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0438 \u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u0432.","\u0412\u043d\u0435\u0434\u0440\u0435\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u0432. \u0412\u044b\u044f\u0432\u0438\u0442\u044c, \u0441\u0440\u0430\u0432\u043d\u0438\u0442\u044c, \u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043d\u0446\u0438\u0440\u043e\u0432\u0430\u0442\u044c, \u043d\u0430\u0432\u0435\u0441\u0442\u0438 \u043f\u043e\u0440\u044f\u0434\u043e\u043a.","\u041f\u043e\u043b\u0438\u0442\u0438\u043a\u0430. \u041f\u0440\u0430\u0432\u043e\u0441\u0443\u0434\u0438\u0435. \u0423\u0447\u0438\u0442\u0435\u043b\u044f, \u0442\u0440\u0435\u043d\u0435\u0440\u044b, \u0434\u0443\u0445\u043e\u0432\u043d\u044b\u0435 \u043d\u0430\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u0438.","\u0421\u0442\u0440\u0430\u0445 \u0431\u044b\u0442\u044c \u043d\u0435\u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u044b\u043c. \u0421\u0442\u0440\u0430\u0445 \u043c\u0435\u0436\u043b\u0438\u0447\u043d\u043e\u0441\u0442\u043d\u043e\u0433\u043e \u043e\u0431\u0449\u0435\u043d\u0438\u044f. \u0421\u0442\u0440\u0430\u0445 \u043e\u043a\u0430\u0437\u0430\u0442\u044c\u0441\u044f \u0432 \u043f\u043e\u0434\u0447\u0438\u043d\u0435\u043d\u0438\u0438. \u0421\u0442\u0440\u0430\u0445 \u0448\u0430\u043d\u0442\u0430\u0436\u0430.","\u0418\u043d\u043e\u0433\u0434\u0430 \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0444\u0430\u0442\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0438 \u0431\u0435\u0441\u043a\u043e\u043c\u043f\u0440\u043e\u043c\u0438\u0441\u0441\u043d\u043e\u0441\u0442\u044c \u0432 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0438 \u0440\u0435\u0448\u0435\u043d\u0438\u044f, \u043f\u043e\u0437\u0438\u0446\u0438\u044f \u0441\u0432\u0435\u0440\u0445\u0443 \u0432\u043d\u0438\u0437, \u043f\u0440\u0430\u0432 \u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u043e\u0437\u0432\u043e\u043b\u0438\u0442\u044c \u0441\u0435\u0431\u0435 \u0441\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u0430\u043c\u0438, \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438, \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0430\u043c\u0438, \u0432\u0437\u0433\u043b\u044f\u0434\u0430\u043c\u0438.","\u0417\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u0430\u043c\u0438 \u0438\u043b\u043b\u044e\u0437\u0438\u0439",'\u0412\u044b\u0441\u0448\u0435\u0435 \u043f\u0440\u0430\u0432\u043e \u043d\u0430 "\u043f\u0440\u0430\u0432\u043e", \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0432\u0438\u0434\u0435\u043d\u0438\u0435 \u0438 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u0432, \u0441\u043e\u0437\u0438\u0434\u0430\u043d\u0438\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u0432, "\u0437\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0442\u0435\u043b\u044c". \u041f\u043e\u0441\u0442\u0440\u043e\u0435\u043d\u0438\u0435 \u0436\u0435\u043b\u0430\u0435\u043c\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0430 \u0438 \u0435\u0433\u043e \u0443\u0437\u0430\u043a\u043e\u043d\u0438\u0432\u0430\u043d\u0438\u0435. \u0412\u044b\u0441\u0448\u0430\u044f \u043c\u0435\u0440\u0430 \u043f\u043e\u0431\u0443\u0436\u0434\u0435\u043d\u0438\u044f -- \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0436\u0435\u043b\u0430\u043d\u0438\u0435. \u0423\u043b\u044c\u0442\u0438\u043c\u0430\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c. \u041c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u0439.',"\u0417\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0442\u0435\u043b\u044c","\u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0432\u044b\u0441\u0448\u0435\u0439 \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u0438.","\u0423\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442 \u0441\u0432\u043e\u0438 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u044b \u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0436\u0438\u0437\u043d\u0438, \u0441\u043b\u0435\u0434\u0443\u0435\u0442 \u0438\u043c.","\u0414\u043e\u0433\u043c\u0430\u0442\u0438\u0437\u043c, \u043d\u0435\u0442\u0435\u0440\u043f\u0438\u043c\u043e\u0441\u0442\u044c \u043a \u0438\u043d\u0430\u043a\u043e\u043c\u044b\u0441\u043b\u0438\u044e, \u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u0441\u0443\u0434\u0438\u0442\u044c \u0434\u0440\u0443\u0433\u0438\u0445.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0417\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0442\u0435\u043b\u044c \u0444\u043e\u0440\u043c\u0438\u0440\u0443\u0435\u0442 \u0432\u0430\u0448 \u043b\u0438\u0447\u043d\u044b\u0439 \u043c\u043e\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u043a\u043e\u0434\u0435\u043a\u0441.","\xab\u041c\u043e\u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0434\u0435\u043b\u0430\u044e\u0442 \u043c\u0435\u043d\u044f \u0441\u0432\u043e\u0431\u043e\u0434\u043d\u0435\u0435 \u0438\u043b\u0438 \u0437\u0430\u043a\u043e\u0432\u044b\u0432\u0430\u044e\u0442 \u0432 \u043a\u0430\u043d\u0434\u0430\u043b\u044b?\xbb","\u0427\u0443\u0432\u0441\u0442\u0432\u043e \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u0438, \u0433\u043d\u0435\u0432 (\u043d\u0430 \u043d\u0430\u0440\u0443\u0448\u0438\u0442\u0435\u043b\u0435\u0439 \u0437\u0430\u043a\u043e\u043d\u0430), \u0434\u043e\u0433\u043c\u0430\u0442\u0438\u0437\u043c, \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u044c (\u0432 \u0441\u0432\u043e\u0435\u0439 \u043f\u0440\u0430\u0432\u043e\u0442\u0435), \u0438\u0437\u043e\u043b\u044f\u0446\u0438\u044f.","\u0413\u043e\u0440\u044f\u0447\u0435\u0435, \u043f\u0440\u0430\u0432\u0435\u0434\u043d\u043e\u0435 \u043d\u0435\u0433\u043e\u0434\u043e\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u0438 \u0432\u0438\u0434\u0435 \u043d\u0430\u0440\u0443\u0448\u0435\u043d\u0438\u044f \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044b\u0445 \u043f\u0440\u0430\u0432\u0438\u043b \u0438\u043b\u0438 \u043c\u043e\u0440\u0430\u043b\u044c\u043d\u044b\u0445 \u043d\u043e\u0440\u043c. \u0423\u0434\u043e\u0432\u043b\u0435\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u0435 \u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0430, \u043a\u043e\u0433\u0434\u0430 \u0432\u0441\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044e\u0442 \u0441\u043e\u0433\u043b\u0430\u0441\u043d\u043e \u0435\u0433\u043e \u0441\u0438\u0441\u0442\u0435\u043c\u0435. \u0420\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0438 \u043d\u0435\u043f\u0440\u0438\u044f\u0442\u0438\u0435 \u0442\u0435\u0445, \u043a\u0442\u043e \u0441\u0442\u0430\u0432\u0438\u0442 \u043f\u043e\u0434 \u0441\u043e\u043c\u043d\u0435\u043d\u0438\u0435 \u0435\u0433\u043e \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u044b. \u041e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u043e\u0434\u0438\u043d\u043e\u0447\u0435\u0441\u0442\u0432\u0430 '\u043d\u0430 \u0432\u0435\u0440\u0448\u0438\u043d\u0435', \u0433\u0434\u0435 \u043e\u043d \u0441\u0430\u043c \u0443\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442 \u0437\u0430\u043a\u043e\u043d\u044b, \u043a\u043e\u0442\u043e\u0440\u044b\u043c \u0441\u043b\u0435\u0434\u0443\u0435\u0442."],t.l)
B.UX=new A.aL(B.aI,["\u041c\u0438\u0440\u043e\u0442\u0432\u043e\u0440\u0435\u0446","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f","\u0421\u0442\u0430\u0440\u0448\u0430\u044f","\u0421\u043e\u044e\u0437\u043d\u0438\u043a","\u041c\u0438\u0440","\u0426\u0435\u043b\u043e\u0441\u0442\u043d\u043e\u0441\u0442\u044c, \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043d\u0438\u0435, \u0433\u0430\u0440\u043c\u043e\u043d\u0438\u044f. \u0412 \u0432\u044b\u0445\u043e\u0434 \u043d\u0430 \u043d\u043e\u0432\u044b\u0439 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u0431\u044b\u0442\u0438\u044f.","\u041c\u0443\u0434\u0440\u043e\u0441\u0442\u044c \u0436\u0438\u0437\u043d\u0438, \u0434\u0443\u0445\u043e\u0432\u043d\u043e\u0441\u0442\u044c. \u041f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u0439 \u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f","\u0441\u0440\u0435\u0434\u043d\u0438\u0439","\u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043c\u0438","\u0417\u0430\u0434\u0430\u0435\u0442\u0441\u044f \u0432\u043e\u043f\u0440\u043e\u0441\u0430\u043c\u0438 \u0434\u0443\u0445\u043e\u0432\u043d\u043e\u0441\u0442\u0438. \u041f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442 \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u0439 \u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u043c\u044b\u0441\u043b\u0430, \u0433\u043b\u0443\u0431\u0438\u043d\u043d\u0430\u044f \u0444\u0438\u043b\u043e\u0441\u043e\u0444\u0438\u044f.","\u041f\u0443\u0431\u043b\u0438\u0447\u043d\u043e\u0435 \u0432\u044b\u0441\u0442\u0443\u043f\u043b\u0435\u043d\u0438\u0435, \u043e\u0433\u043b\u0430\u0448\u0435\u043d\u0438\u0435, \u0434\u0435\u043c\u043e\u043d\u0441\u0442\u0440\u0430\u0446\u0438\u044f. \u041e\u0442\u043a\u0440\u044b\u0442\u043e\u0441\u0442\u044c, \u0449\u0435\u0434\u0440\u043e\u0441\u0442\u044c. \u041f\u0440\u0438\u0437\u043d\u0430\u043d\u0438\u0435.","\u041c\u0435\u0436\u0434\u0443\u043d\u0430\u0440\u043e\u0434\u043d\u044b\u0435 \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u044b. \u0424\u0438\u043b\u043e\u0441\u043e\u0444\u0438\u044f.","\u0421\u0442\u0440\u0430\u0445 \u043e\u0441\u0442\u0430\u0442\u044c\u0441\u044f \u0431\u0435\u0437 \u043a\u0440\u043e\u0432\u0430, \u0431\u0435\u0437 \u043f\u043e\u043a\u0440\u043e\u0432\u0438\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u0432\u044b\u0441\u0448\u0435\u0439 \u0441\u0438\u043b\u044b. \u0421\u0442\u0440\u0430\u0445 \u043e\u0442\u0440\u0435\u0447\u0435\u043d\u0438\u044f.","\u0418\u043d\u043e\u0433\u0434\u0430 \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0433\u043b\u0443\u0431\u0438\u043d\u043d\u043e\u0435 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043f\u0440\u0438\u0447\u0438\u043d\u043d\u043e \u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0441\u0432\u044f\u0437\u0435\u0439.","\u041e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u0442\u044c \u0441\u0432\u043e\u044e \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u0441\u0447\u0435\u0442 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u043f\u0440\u0438\u0447\u0438\u043d\u043d\u043e \u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0441\u0432\u044f\u0437\u0435\u0439 \u0438 \u0437\u0430 \u0441\u0447\u0435\u0442 \u0433\u043b\u0443\u0431\u0438\u043d\u043d\u044b\u0445 \u043f\u043e\u0437\u043d\u0430\u043d\u0438\u0439 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 \u043a\u0430\u043a \u0441\u0438\u0441\u0442\u0435\u043c\u044b.","\u0417\u0430\u0432\u0435\u0440\u0448\u0435\u043d\u043d\u043e\u0441\u0442\u044c",'\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u0438 \u0436\u0438\u0437\u043d\u0438, \u0434\u0443\u0445\u043e\u0432\u043d\u043e\u0441\u0442\u0438, \u0441\u0430\u043a\u0440\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438, \u0441\u043e\u043a\u0440\u043e\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u0438 \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0437\u043d\u0430\u043d\u0438\u0439 \u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435, "\u043f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0444\u0438\u043b\u043e\u0441\u043e\u0444". \u0412\u043b\u0430\u0434\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u043e\u043c \u0438 \u0435\u0433\u043e \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043c\u0438 \u043d\u0430 \u0432\u044b\u0441\u0448\u0435\u043c \u0443\u0440\u043e\u0432\u043d\u0435. \u041f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0432\u0441\u0435\u0433\u043e \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u043e\u0433\u043e \xab9\xbb \u0440\u043e\u043b\u044c\u044e.',"\u041c\u0430\u0441\u0442\u0435\u0440","\u0426\u0435\u043b\u043e\u0441\u0442\u043d\u043e\u0441\u0442\u044c, \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u044c.","\u0412\u0438\u0434\u0438\u0442 \u043e\u0431\u0449\u0443\u044e \u043a\u0430\u0440\u0442\u0438\u043d\u0443, \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0435\u0442 \u0437\u043d\u0430\u043d\u0438\u044f \u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435, \u043e\u0449\u0443\u0449\u0430\u0435\u0442 \u0441\u0432\u044f\u0437\u044c \u0441 \u043c\u0438\u0440\u043e\u043c.","\u041e\u0442\u0440\u044b\u0432 \u043e\u0442 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438, \u0434\u0443\u0445\u043e\u0432\u043d\u0430\u044f \u0433\u043e\u0440\u0434\u044b\u043d\u044f, \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \xab\u043c\u0438\u0441\u0441\u0438\u043e\u043d\u0435\u0440\u0441\u0442\u0432\u0430\xbb.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u041c\u0430\u0441\u0442\u0435\u0440 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u043e\u0431\u0440\u0435\u0441\u0442\u0438 \u0446\u0435\u043b\u043e\u0441\u0442\u043d\u043e\u0441\u0442\u044c \u0438 \u043d\u0430\u0439\u0442\u0438 \u0433\u043b\u0443\u0431\u043e\u043a\u0438\u0439 \u0441\u043c\u044b\u0441\u043b.","\xab\u041a\u0430\u043a \u043c\u043e\u044f \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0432 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0445 \u0434\u0435\u043b\u0430\u0445?\xbb","\u0426\u0435\u043b\u043e\u0441\u0442\u043d\u043e\u0441\u0442\u044c, \u0433\u043b\u0443\u0431\u043e\u043a\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c \u0431\u044b\u0442\u0438\u044f, \u0441\u043f\u043e\u043a\u043e\u0439\u0441\u0442\u0432\u0438\u0435, \u043e\u0442\u0441\u0442\u0440\u0430\u043d\u0435\u043d\u043d\u043e\u0441\u0442\u044c (\u043e\u0442 \u0441\u0443\u0435\u0442\u044b), \u0432\u0441\u0435\u043f\u0440\u0438\u044f\u0442\u0438\u0435.","\u0413\u043b\u0443\u0431\u043e\u043a\u043e\u0435, \u043c\u043e\u043b\u0447\u0430\u043b\u0438\u0432\u043e\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0430 \u0441 \u043c\u0438\u0440\u043e\u043c \u0438 \u0443\u0434\u043e\u0432\u043b\u0435\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u044f \u043e\u0442 \u0442\u0435\u043a\u0443\u0449\u0435\u0433\u043e \u043c\u043e\u043c\u0435\u043d\u0442\u0430. \u041c\u044f\u0433\u043a\u0430\u044f, \u043d\u0435\u043e\u0441\u0443\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0443\u043b\u044b\u0431\u043a\u0430 \u043f\u0440\u0438 \u0432\u0438\u0434\u0435 \u0447\u0443\u0436\u0438\u0445 \u043e\u0448\u0438\u0431\u043e\u043a, \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438\u0445 \u043a\u0430\u043a \u0447\u0430\u0441\u0442\u0438 \u043f\u0443\u0442\u0438. \u0421\u043f\u043e\u043a\u043e\u0439\u043d\u043e\u0435 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435 \u0441\u043b\u043e\u0436\u043d\u044b\u0445 \u0441\u043e\u0431\u044b\u0442\u0438\u0439 \u043a\u0430\u043a \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u043e\u0433\u043e \u043e\u043f\u044b\u0442\u0430. \u041b\u0435\u0433\u043a\u0430\u044f \u0433\u0440\u0443\u0441\u0442\u044c \u043e\u0442 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u0438\u044f, \u0447\u0442\u043e \u044d\u0442\u043e\u0439 \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u044c\u044e \u0442\u0440\u0443\u0434\u043d\u043e \u043f\u043e\u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f \u0441\u043b\u043e\u0432\u0430\u043c\u0438."],t.l)
B.V8=new A.aL(B.aI,["\u041d\u0418-\u0427\u0422\u041e","\u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e-\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f","\u0421\u0430\u043c\u0430\u044f \u0441\u0442\u0430\u0440\u0448\u0430\u044f \u0420\u043e\u043b\u044c","\u0410\u043d\u0442\u0430\u0433\u043e\u043d\u0438\u0441\u0442","\u0428\u0443\u0442/\u0414\u0443\u0440\u0430\u043a","\u041d\u0435\u0432\u0438\u043d\u043d\u043e\u0441\u0442\u044c, \u043d\u0430\u0447\u0430\u043b\u043e \u043f\u0443\u0442\u0438, \u0441\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u043e\u0441\u0442\u044c. \u0421\u0432\u043e\u0431\u043e\u0434\u0430 \u0447\u0435\u0440\u0435\u0437 \u043e\u0442\u043f\u0443\u0441\u043a\u0430\u043d\u0438\u0435 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044f.","\u0422\u043e\u0442\u0430\u043b\u044c\u043d\u044b\u0439 \u043e\u043f\u044b\u0442 \u0432\u0441\u0435\u0445 \u0437\u043e\u043d. \u041e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432.","\u041e\u0442\u043a\u0440\u044b\u0442\u0430\u044f \u043a \u043c\u0438\u0440\u043e\u043e\u0449\u0443\u0449\u0435\u043d\u0438\u044f\u043c","\u0441\u0440\u0435\u0434\u043d\u0438\u0439/\u044f\u0440\u043a\u0438\u0439","\u043f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u0432\u043e\u0431\u043e\u0434\u044b","\u0421\u043a\u043b\u043e\u043d\u0435\u043d \u0445\u043e\u0440\u043e\u0448\u043e \u0441\u043b\u044b\u0448\u0430\u0442\u044c \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0438\u0439 \u043c\u0438\u0440, \u043d\u043e \u0442\u0435\u0440\u044f\u0435\u0442 \u0441\u0432\u043e\u0438 \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u044f \u0432 \u043d\u0435\u043c. \u041f\u0440\u0438 \u043a\u0430\u0436\u0443\u0449\u0435\u0439\u0441\u044f \u043e\u043f\u044b\u0442\u043d\u043e\u0441\u0442\u0438 \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0441\u044f \u043d\u043e\u0432\u044b\u0439 \u043f\u043e\u0438\u0441\u043a.","\u041f\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u0432\u043e\u0431\u043e\u0434\u044b.","\u041b\u044e\u0431\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0448\u0443\u043c\u043b\u0438\u0432\u043e\u0441\u0442\u044c. \u0414\u043e\u0432\u0435\u0440\u0438\u0435. \u0421\u043e\u0442\u0440\u0443\u0434\u043d\u0438\u0447\u0435\u0441\u0442\u0432\u043e. \u041b\u0438\u0431\u043e \u0441\u043a\u0443\u043a\u0430, \u0430\u043d\u0430\u0440\u0445\u0438\u044f \u0438 \u043e\u0442\u0440\u0438\u0446\u0430\u043d\u0438\u0435.","\u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u044b\u0439 \u0438\u0433\u0440\u043e\u043a. \u0427\u0430\u0441\u0442\u043e \u0432 \u043f\u0440\u043e\u0434\u0430\u0436\u0430\u0445.","\u0421\u0442\u0440\u0430\u0445 \u043f\u0440\u0430\u0432\u0438\u043b, \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u043e\u0432, \u0440\u0430\u0441\u043f\u043e\u0440\u044f\u0434\u043a\u043e\u0432 (\u0441\u0442\u0440\u0430\u0445 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u0437\u0430\u043a\u043e\u043d\u043e\u0432), \u0441\u0442\u0440\u0430\u0445 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u044f \u043f\u0440\u0430\u0432\u0438\u043b \u0438\u0433\u0440\u044b \xab\u0416\u0438\u0437\u043d\u044c\xbb. \u0421\u0442\u0440\u0430\u0445 \u043f\u043e\u043f\u0443\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u0438 \u0430\u043d\u0430\u0440\u0445\u0438\u0438. \u0421\u0442\u0440\u0430\u0445 \u0441\u043a\u0443\u043a\u0438 \u0438 \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u0438.","\u0418\u043d\u043e\u0433\u0434\u0430 \u0441\u043a\u043b\u043e\u043d\u0435\u043d \u0434\u043e\u0432\u0435\u0440\u0438\u0442\u044c\u0441\u044f \u0438 \xab\u043e\u0442\u043f\u0443\u0441\u0442\u0438\u0442\u044c\xbb \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044e, \u043b\u0438\u0431\u043e \u043d\u0435\u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u043e\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044f \u0432 \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u0432\u043d\u043e-\u0430\u043d\u0430\u0440\u0445\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435.","\u041d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u0432\u043b\u0430\u0434\u0435\u0442\u044c \u0432\u0441\u0435\u043c\u0438 \u0441\u0442\u0435\u043f\u0435\u043d\u044f\u043c\u0438 \u0441\u0432\u043e\u0431\u043e\u0434\u044b \u0437\u0430 \u0441\u0447\u0435\u0442 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0438\u0432\u0430\u043d\u0438\u044f \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432, \u043b\u0438\u0431\u043e \u043d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0442\u044c \u0441\u0432\u043e\u044e \u0430\u043d\u0430\u0440\u0445\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043f\u0440\u0438\u0440\u043e\u0434\u0443.","\u0414\u0443\u0440\u0430\u043a",'\u041f\u0440\u043e\u0436\u0438\u043b \u043e\u043f\u044b\u0442 \u0432\u0441\u0435\u0445 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445, \u0442\u043e\u0442\u0430\u043b\u0435\u043d, "\u0430\u0431\u0441\u043e\u043b\u044e\u0442". \u0412 \u043d\u0451\u043c \u0437\u0430\u043a\u043b\u044e\u0447\u0435\u043d \u043e\u043f\u044b\u0442 \u0432\u0441\u0435\u0445 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445 \u0437\u043e\u043d, \u043d\u043e \u043d\u0435\u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u044d\u0442\u043e\u0433\u043e, \u0442\u0430\u043a \u043a\u0430\u043a \u044d\u0442\u043e\u0442 \u043e\u043f\u044b\u0442 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043f\u0440\u043e\u0436\u0438\u0442\u044b\u043c \u0438 \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043d\u043d\u044b\u043c. \u0415\u0433\u043e \u0437\u0430\u0434\u0430\u0447\u0430 \u0434\u043b\u044f \u0441\u0435\u0431\u044f -- \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f \u0441\u0435\u0431\u044f \u0436\u0435 \u0441\u0430\u043c\u043e\u0439: \u0432\u0430\u0436\u043d\u043e \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u0442\u044c, \u0447\u0442\u043e \u044f\u0432\u043b\u044f\u0435\u0448\u044c\u0441\u044f \u043e\u0431\u043b\u0430\u0434\u0430\u0442\u0435\u043b\u0435\u043c "\u0432\u0441\u0435\u0433\u043e", \u043d\u043e \u0438 \u043d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u044d\u0442\u043e "\u0432\u0441\u0451" \u043f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0442\u044c. \u0425\u043e\u0440\u043e\u0448\u043e \u0441\u043b\u044b\u0448\u0438\u0442 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0438\u0439 \u043c\u0438\u0440, \u043d\u043e \u0442\u0435\u0440\u044f\u0435\u0442 \u0441\u0432\u043e\u0438 \u043e\u0449\u0443\u0449\u0435\u043d\u0438\u044f \u0432 \u043d\u0435\u043c, \u0434\u043e\u043b\u0433\u043e \u043d\u0435 \u0441\u043b\u044b\u0448\u0438\u0442 \u0441\u0435\u0431\u044f (\u043f\u0440\u0438 \u043a\u0430\u0436\u0443\u0449\u0435\u0439\u0441\u044f \u043e\u043f\u044b\u0442\u043d\u043e\u0441\u0442\u0438 \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0441\u044f \u043d\u043e\u0432\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u0441\u0435\u0431\u044f). \u0412\u0430\u0436\u043d\u0430 \u0443\u043c\u0435\u0441\u0442\u043d\u043e\u0441\u0442\u044c.',"\u0428\u0443\u0442","\u0421\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u043e\u0441\u0442\u044c, \u0441\u0432\u043e\u0431\u043e\u0434\u0430 \u043e\u0442 \u0440\u0430\u043c\u043e\u043a.","\u0412\u0438\u0434\u0438\u0442 \u043c\u0438\u0440 \u0431\u0435\u0437 \u0444\u0438\u043b\u044c\u0442\u0440\u043e\u0432, \u0442\u0432\u043e\u0440\u0438\u0442, \u043d\u0435 \u0431\u043e\u0438\u0442\u0441\u044f \u0432\u044b\u0433\u043b\u044f\u0434\u0435\u0442\u044c \u0433\u043b\u0443\u043f\u043e.","\u0411\u0435\u0437\u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c, \u043e\u0442\u0440\u0438\u0446\u0430\u043d\u0438\u0435 \u043b\u044e\u0431\u044b\u0445 \u043f\u0440\u0430\u0432\u0438\u043b, \u0445\u0430\u043e\u0441.","\u0412\u0430\u0448 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u0428\u0443\u0442 \u043d\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0435\u0442, \u0447\u0442\u043e \u043c\u043e\u0436\u043d\u043e \u043e\u0442\u043f\u0443\u0441\u0442\u0438\u0442\u044c \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438 \u043f\u0440\u043e\u0441\u0442\u043e \u0431\u044b\u0442\u044c.","\xab\u0413\u0434\u0435 \u0432 \u043c\u043e\u0435\u0439 \u0436\u0438\u0437\u043d\u0438 \u043d\u0435 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u043b\u0451\u0433\u043a\u043e\u0441\u0442\u0438 \u0438 \u0431\u0435\u0437\u0443\u043c\u0438\u044f?\xbb","\u0421\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u0430\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u044c, \u0441\u043a\u0443\u043a\u0430 (\u043e\u0442 \u043f\u0440\u0430\u0432\u0438\u043b), \u043b\u0435\u0433\u043a\u043e\u043c\u044b\u0441\u043b\u0438\u0435, \u0441\u0442\u0440\u0430\u0445 \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438, \u0447\u0443\u0432\u0441\u0442\u0432\u043e \u0441\u0432\u043e\u0431\u043e\u0434\u044b.","\u0412\u043d\u0435\u0437\u0430\u043f\u043d\u044b\u0439, \u0437\u0430\u0440\u0430\u0437\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0441\u043c\u0435\u0445 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0441\u0435\u0440\u044c\u0435\u0437\u043d\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438, \u043b\u043e\u043c\u0430\u044e\u0449\u0438\u0439 \u043d\u0430\u043f\u0440\u044f\u0436\u0435\u043d\u0438\u0435. \u041f\u043e\u043b\u043d\u043e\u0435 \u0438\u0433\u043d\u043e\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0445 \u043d\u043e\u0440\u043c, \u0432\u0435\u0434\u0443\u0449\u0435\u0435 \u043a \u043d\u0435\u043b\u043e\u0432\u043a\u043e\u0441\u0442\u0438 \u0438\u043b\u0438 \u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0435\u043d\u0438\u044e. \u041f\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u0431\u0435\u0433\u0441\u0442\u0432\u043e \u043e\u0442 \u043b\u044e\u0431\u044b\u0445 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0442\u0441\u044f \u043a\u0430\u043a \u043a\u043b\u0435\u0442\u043a\u0430. \u041e\u0449\u0443\u0449\u0435\u043d\u0438\u0435 \u043f\u043e\u043b\u043d\u043e\u0439, \u0434\u0435\u0442\u0441\u043a\u043e\u0439 \u0441\u0432\u043e\u0431\u043e\u0434\u044b \u0438 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0430 \u0441 \u043c\u0438\u0440\u043e\u043c \u0432 \u043c\u043e\u043c\u0435\u043d\u0442\u044b \u0441\u043f\u043e\u043d\u0442\u0430\u043d\u043d\u043e\u0433\u043e \u0442\u0432\u043e\u0440\u0447\u0435\u0441\u0442\u0432\u0430 \u0438\u043b\u0438 \u043f\u0443\u0442\u0435\u0448\u0435\u0441\u0442\u0432\u0438\u0439."],t.l)
